-- Complete, individually assignable annual in-service curricula for Pennsylvania
-- nursing-home nurse aides, home-health aides, and hospice aides.
--
-- Primary authorities reviewed for this catalog:
--   * 42 CFR 483.95 and 28 Pa. Code Sections 201.2 and 201.20
--   * 42 CFR 484.80, CMS SOM Appendix B, and 28 Pa. Code Section 601.35
--   * 42 CFR 418.76, CMS SOM Appendix M, and PA DOH hospice guidance
--
-- The three original 12-hour aggregate courses contained only a few short blocks.
-- Keep their versions, direct training-type bridges, and assignments as historical
-- evidence, but prevent new enrollment by archiving the catalog entries. The
-- comprehensive courses below use version-scoped compliance mappings instead.

do $archive$
declare
  v_legacy_codes text[] := array[
    'NH-AIDE-ANNUAL',
    'HHA-AIDE-ANNUAL',
    'HOS-AIDE-ANNUAL'
  ];
  v_training_type_code text;
  v_match_count integer;
  v_archived integer;
begin
  -- Resolve each aggregate through its stable system training-type bridge rather
  -- than its mutable title, and fail before changing rows if any bridge is not
  -- unique. Historical assignments depend on training_type_id remaining intact.
  foreach v_training_type_code in array v_legacy_codes
  loop
    select count(*) into v_match_count
    from public.courses c
    join public.training_types tt on tt.id = c.training_type_id
    where c.organization_id is null
      and c.catalog_code is null
      and tt.organization_id is null
      and tt.code = v_training_type_code;

    if v_match_count <> 1 then
      raise exception 'Expected exactly one legacy system aggregate course bridged to training type %, found %',
        v_training_type_code, v_match_count;
    end if;
  end loop;

  perform set_config('app.privileged_write', 'on', true);

  update public.courses c
  set status = 'archived', updated_at = now()
  from public.training_types tt
  where tt.id = c.training_type_id
    and c.organization_id is null
    and c.catalog_code is null
    and tt.organization_id is null
    and tt.code = any (v_legacy_codes);

  get diagnostics v_archived = row_count;
  if v_archived <> 3 then
    raise exception 'Expected to archive exactly 3 legacy clinical aggregate courses, archived %', v_archived;
  end if;

  foreach v_training_type_code in array v_legacy_codes
  loop
    select count(*) into v_match_count
    from public.courses c
    join public.training_types tt on tt.id = c.training_type_id
    where c.organization_id is null
      and c.catalog_code is null
      and c.status = 'archived'
      and tt.organization_id is null
      and tt.code = v_training_type_code;

    if v_match_count <> 1 then
      raise exception 'Archiving did not preserve the unique legacy course bridge for training type %',
        v_training_type_code;
    end if;
  end loop;

  perform set_config('app.privileged_write', 'off', true);
end
$archive$;

do $seed$
declare
  v_nh_catalog jsonb := $nh$
[
  {
    "catalog_code": "PA-NH-AIDE-DEMENTIA-COGNITIVE-CARE",
    "track": "NH",
    "title": "Dementia and Cognitive-Impairment Care for Nursing Home Aides",
    "summary": "Builds practical skills for recognizing cognitive change, communicating respectfully, preventing avoidable distress, and supporting person-centered routines for residents with dementia or other cognitive impairment.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 90,
    "topic_code": "NH-483.95-G2-G4",
    "objectives": ["Distinguish common dementia-related changes from sudden changes that require prompt reporting.", "Use person-centered communication and cueing that protects dignity and choice.", "Identify triggers and unmet needs before responding to distress behavior.", "Apply safety, escalation, and documentation steps within the nurse-aide role."],
    "lessons": [
      {"title": "Cognitive change and observation", "content": "Dementia commonly affects memory, language, judgment, orientation, and the ability to sequence tasks, but each resident has an individual baseline. Observe specific changes in function, alertness, intake, mobility, mood, and communication. A sudden or marked departure from baseline can reflect illness, pain, medication effects, dehydration, or another urgent problem and must be reported promptly rather than labeled as normal dementia.", "takeaway": "Compare observations with the resident's baseline and promptly report sudden or significant change instead of assuming it is dementia."},
      {"title": "Respectful communication and cueing", "content": "Approach from the front, identify yourself, reduce competing noise, and use a calm tone with one clear idea at a time. Allow extra processing time and offer limited, meaningful choices. Validate the resident's emotion without arguing about facts, and use familiar words, gestures, demonstrations, or objects as cues. Never use childish language, public correction, threats, or deception for staff convenience.", "takeaway": "Use calm one-step communication, processing time, and meaningful choices while validating emotion and preserving adult dignity."},
      {"title": "Triggers, unmet needs, and person-centered response", "content": "Distress behavior communicates something even when the cause is not immediately clear. Consider pain, hunger, toileting, temperature, fatigue, overstimulation, loneliness, fear, unfamiliar caregivers, and changes in routine. Follow the care plan, remove avoidable triggers, offer a familiar calming activity, and report patterns to the nurse so the interdisciplinary team can adjust supports. Restraint, intimidation, or punishment is never a routine response.", "takeaway": "Look for unmet needs and environmental triggers, follow the plan, and report patterns so supports can be individualized."},
      {"title": "Safety, wandering, and escalation", "content": "Use the resident-specific care plan and facility safeguards for exit-seeking, unsafe ambulation, falls, and other foreseeable risks. Redirect without blocking or grabbing unless immediate protection requires action allowed by policy. Maintain observation, remove hazards when safe, and summon help for imminent danger, missing residents, acute symptoms, or behavior that cannot be safely redirected. Record objective facts, actions, notifications, and response.", "takeaway": "Use planned safeguards and least-restrictive redirection, summon help for imminent danger, and document objective facts."}
    ],
    "scenarios": [
      {"title": "A sudden afternoon change", "content": "A resident who usually recognizes staff becomes very sleepy, refuses fluids, and cannot follow the familiar transfer sequence. A coworker says this is just dementia and suggests finishing rounds first.", "response": "Keep the resident safe, stop the transfer if it is unsafe, promptly notify the nurse with baseline comparisons and objective findings, follow immediate directions, and document the observations and notifications."},
      {"title": "Repeated requests to go home", "content": "During evening care, a resident paces near the exit and repeatedly asks to find her children. Correcting her makes her louder and more frightened.", "response": "Approach calmly, acknowledge the worry, use the resident's preferred name, offer a familiar planned activity or quiet walk, maintain required safety observation, and report the trigger and response pattern to the nurse."}
    ],
    "citation_label": "42 CFR 483.95 and 28 Pa. Code 201.20",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-483/section-483.95 | https://www.pacodeandbulletin.gov/secure/pacode/data/028/chapter201/s201.20.html",
    "citation_note": "Federal nursing-facility training rules require nurse-aide annual in-service content on care of cognitively impaired residents and dementia management when applicable; Pennsylvania also requires facility-needs-based annual education. Facility assessment, performance review, and resident population must shape acceptance and tailoring."
  },
  {
    "catalog_code": "PA-NH-AIDE-ABUSE-PREVENTION-REPORTING",
    "track": "NH",
    "title": "Abuse, Neglect, Exploitation, and Reporting for Nursing Home Aides",
    "summary": "Develops recognition, immediate protection, reporting, evidence-preservation, and nonretaliation practices for suspected abuse, neglect, exploitation, mistreatment, and misappropriation.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 90,
    "topic_code": "NH-483.95-C-G2",
    "objectives": ["Recognize indicators and examples of abuse, neglect, exploitation, mistreatment, and misappropriation.", "Take immediate protective action within role and policy.", "Use required internal and external reporting pathways without screening or delay.", "Preserve facts, privacy, and potential evidence while avoiding retaliation."],
    "lessons": [
      {"title": "Recognizing prohibited conduct", "content": "Abuse can be physical, verbal, sexual, mental, or facilitated through technology; neglect can involve failure to provide needed care or protection; exploitation and misappropriation involve improper use of a resident's property or resources. Warning signs include unexplained injury, fear around a person, abrupt behavior change, poor hygiene, missing belongings, sexually transmitted infection, or inconsistent explanations. A single sign is not a diagnosis, but it can require immediate reporting.", "takeaway": "Treat signs and disclosures as reportable concerns; do not require proof or make your own investigative finding first."},
      {"title": "Immediate safety and trauma-informed response", "content": "If danger is present, remain with the resident when safe, call for clinical or emergency help, and separate the resident from the alleged source only as policy directs. Listen without blame, pressure, disbelief, or promises you cannot keep. Use the resident's words, protect privacy, and avoid repeated questioning. Necessary care and emotional reassurance continue while leaders activate protection and reporting procedures.", "takeaway": "Protect immediate safety, listen without leading questions, and activate the reporting chain at once."},
      {"title": "Reporting duties and deadlines", "content": "Federal and state rules and facility policy establish who must receive allegations and how quickly reports must be made. Nurse aides must notify the designated supervisor immediately and use external reporting or emergency pathways when policy or law requires; they must not wait for a shift change, conduct an investigation, or let a suspected staff member screen the report. If the usual contact is implicated or unavailable, use the alternate escalation route.", "takeaway": "Report immediately through the designated and alternate pathways; never delay while trying to prove the allegation."},
      {"title": "Objective documentation, evidence, and nonretaliation", "content": "Document exact observations, the resident's own words, location, time, people present, safety actions, and notifications. Do not speculate about motive, alter records, photograph without authorization, clean a possible evidence area unless necessary for safety, or discuss details with people who do not need to know. Retaliation, intimidation, or interference with reporting is prohibited; report any such conduct through the same protected channels.", "takeaway": "Record exact facts and notifications, preserve potential evidence as directed, protect privacy, and report retaliation or interference."}
    ],
    "scenarios": [
      {"title": "A frightened disclosure", "content": "While helping with dressing, a resident whispers that a night employee hurt her and asks you not to tell because she fears losing her room.", "response": "Ensure immediate safety, listen without pressing for details, explain that you must get help, immediately notify the designated supervisor and use required reporting pathways, preserve the resident's words, and document facts without conclusions."},
      {"title": "Missing cash and an implicated supervisor", "content": "A resident reports cash missing after a supervisor searched a drawer. The supervisor tells you to forget it because the resident is confused.", "response": "Do not confront or investigate; use the alternate reporting chain immediately, protect the resident and remaining property as policy directs, document the exact statement and circumstances, and avoid discussing the allegation beyond authorized people."}
    ],
    "citation_label": "42 CFR 483.12 and 483.95; 28 Pa. Code 201.20",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-483/section-483.12 | https://www.ecfr.gov/current/title-42/part-483/section-483.95 | https://www.pacodeandbulletin.gov/secure/pacode/data/028/chapter201/s201.20.html",
    "citation_note": "Federal nursing-facility rules require abuse-prohibition training and facility reporting systems; nurse-aide in-service education must address abuse prevention. Employers must supply their current reporting contacts, deadlines, protection procedures, and state-specific escalation instructions."
  },
  {
    "catalog_code": "PA-NH-AIDE-COMMUNICATION-RIGHTS-CULTURE",
    "track": "NH",
    "title": "Resident Rights, Communication, and Cultural Responsiveness for Nursing Home Aides",
    "summary": "Strengthens daily practices that preserve resident rights, privacy, autonomy, communication access, nondiscrimination, cultural identity, and informed choice.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 75,
    "topic_code": "NH-483.95-A-B-PA201.20",
    "objectives": ["Apply resident-rights principles during routine care and shared living.", "Use accessible communication and qualified supports through facility processes.", "Respond respectfully to cultural, religious, linguistic, gender, and disability-related preferences.", "Escalate conflicts between preference, plan, and safety without coercion."],
    "lessons": [
      {"title": "Rights in everyday care", "content": "Rights are expressed through ordinary interactions: knocking, explaining care, seeking permission, covering the body, honoring reasonable schedules, protecting possessions, and supporting access to visitors, activities, grievances, and records as allowed. A resident may refuse care. The aide should pause, explore the reason without pressure, address an immediate concern if possible, and report the refusal so the nurse can assess and revise the approach.", "takeaway": "Explain, seek permission, protect privacy and choice, and report refusals without coercion or punishment."},
      {"title": "Communication access and understanding", "content": "Use the communication method identified in the care plan, including hearing devices, glasses, communication boards, plain language, or interpreter services obtained through facility procedures. Face the resident, check understanding without shaming, and give time to respond. Do not rely on an unapproved child, visitor, or roommate to interpret sensitive clinical information, and do not pretend understanding when communication is unclear.", "takeaway": "Use care-plan communication supports and authorized language access, then check understanding respectfully."},
      {"title": "Culture, identity, and nondiscrimination", "content": "Ask rather than assume how a resident wants to be addressed, touched, dressed, groomed, fed, or supported in religious and cultural practices. Respect names, pronouns, relationships, dietary practices, disability accommodations, and modesty preferences within the plan. Personal beliefs do not justify ridicule, unequal care, slurs, outing private information, or denying assistance. Report discriminatory conduct and unresolved accommodation needs.", "takeaway": "Honor stated identity and cultural preferences without stereotyping, and report discriminatory conduct or unmet accommodation needs."},
      {"title": "Choice, risk, and team resolution", "content": "Resident choice can coexist with clinical risk. The aide should identify the preference, explain only information authorized for the role, offer plan-consistent alternatives, and notify the nurse when a choice conflicts with current directions or creates a new hazard. Do not invent restrictions or promise a change. Document the resident's words, options offered, observations, notifications, and immediate response.", "takeaway": "Support informed choice within the plan and escalate unresolved risk instead of imposing an unauthorized restriction."}
    ],
    "scenarios": [
      {"title": "A declined early shower", "content": "A resident says the scheduled 6 a.m. shower conflicts with prayer and asks for afternoon care. The assignment sheet lists only the morning time.", "response": "Respect the refusal, maintain privacy and comfort, ask about the preferred option, notify the nurse or scheduler for a plan-consistent adjustment, and document the request and response without labeling the resident uncooperative."},
      {"title": "A communication shortcut", "content": "A resident with limited English needs intimate care. A coworker asks the resident's young grandchild to interpret because the approved language service may take several minutes.", "response": "Use the facility's authorized language-access process, preserve privacy, provide urgent safety care within role if needed, and notify the nurse if communication barriers prevent informed participation."}
    ],
    "citation_label": "42 CFR 483.10, 483.95, and 28 Pa. Code 201.20",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-483/section-483.10 | https://www.ecfr.gov/current/title-42/part-483/section-483.95 | https://www.pacodeandbulletin.gov/secure/pacode/data/028/chapter201/s201.20.html",
    "citation_note": "Federal resident-rights and training rules and Pennsylvania annual-education rules support rights, effective communication, nondiscrimination, cultural awareness, and resident-population-specific education. Facility policies must supply current language-access and accommodation procedures."
  },
  {
    "catalog_code": "PA-NH-AIDE-INFECTION-PREVENTION",
    "track": "NH",
    "title": "Infection Prevention and Control for Nursing Home Aides",
    "summary": "Applies standard precautions, transmission-based directions, hand hygiene, personal protective equipment, cleaning boundaries, and early reporting to routine nursing-home care.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 60,
    "topic_code": "NH-483.95-E",
    "objectives": ["Select hand hygiene and PPE practices based on task and facility direction.", "Prevent cross-contamination during personal care and shared-equipment use.", "Recognize and report infection-related changes and exposure events.", "Follow transmission-based and outbreak instructions without stigmatizing residents."],
    "lessons": [
      {"title": "Standard precautions and hand hygiene", "content": "Treat blood, body fluids, nonintact skin, and mucous membranes as potential exposure sources. Perform hand hygiene at the moments required by facility policy, including before clean contact and after body-fluid risk, glove removal, resident contact, and contaminated surroundings. Gloves do not replace hand hygiene. Use soap and water when policy or the situation requires it, and keep nails, jewelry, and skin condition consistent with infection-control rules.", "takeaway": "Perform hand hygiene at required moments and remember that wearing gloves never replaces cleaning hands."},
      {"title": "PPE and isolation directions", "content": "Choose gown, gloves, mask, respirator, or eye protection according to the anticipated exposure and posted or communicated precautions. Complete required fit testing and training before respirator use. Put on and remove PPE in the facility sequence to avoid contaminating skin, clothing, or the environment. If supplies, signage, or directions are unclear, pause nonurgent care and ask the nurse or infection preventionist.", "takeaway": "Use the PPE and sequence required for the task and precautions, and seek clarification before nonurgent care when directions are unclear."},
      {"title": "Clean workflow and shared equipment", "content": "Move from cleaner to more contaminated tasks, change gloves and clean hands between body sites when indicated, and keep clean supplies away from used linen and waste. Handle linen without shaking, contain waste as directed, and disinfect shared equipment using the approved product, contact time, and assigned responsibility. Never return a used item to clean storage or mix chemicals outside policy.", "takeaway": "Separate clean and contaminated items and disinfect shared equipment with the approved product, contact time, and workflow."},
      {"title": "Symptoms, exposures, and outbreak response", "content": "Observe for fever, cough, breathing change, vomiting, diarrhea, drainage, new confusion, reduced intake, skin changes, and other deviations from baseline. Promptly report findings and occupational exposures, complete required first aid, and follow testing, work-restriction, vaccination, or outbreak instructions from authorized leaders. Maintain resident dignity and confidentiality; precautions are safety measures, not a reason for isolation beyond the care plan.", "takeaway": "Report symptoms and exposures promptly and follow authorized outbreak directions while preserving dignity and confidentiality."}
    ],
    "scenarios": [
      {"title": "Contaminated gloves at the supply cart", "content": "After perineal care, an aide keeps the same gloves on and reaches toward a shared cart for clean wipes.", "response": "Stop before touching the cart, remove gloves safely, perform hand hygiene, obtain clean supplies without contaminating storage, and clean any surface already touched according to facility procedure."},
      {"title": "New cough during an outbreak", "content": "A resident develops a new cough and unusual fatigue during a unit outbreak, but has no posted precautions yet.", "response": "Apply the source-control and immediate precautions authorized by policy, keep the resident comfortable, promptly notify the nurse with objective findings, limit avoidable exposure, and follow new directions and documentation requirements."}
    ],
    "citation_label": "42 CFR 483.80 and 483.95",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-483/section-483.80 | https://www.ecfr.gov/current/title-42/part-483/section-483.95",
    "citation_note": "Federal nursing-facility rules require an infection prevention and control program and staff training. The facility's infection preventionist, risk assessment, current public-health direction, products, PPE, and outbreak plan must tailor this module."
  },
  {
    "catalog_code": "PA-NH-AIDE-ACCIDENT-FALL-TRANSFER-SAFETY",
    "track": "NH",
    "title": "Accident Prevention, Falls, and Transfer Safety for Nursing Home Aides",
    "summary": "Builds resident-specific hazard recognition, safe transfer and mobility habits, fall response, equipment checks, and timely reporting without creating avoidable restraint.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 75,
    "topic_code": "NH-PA201.20-A1",
    "objectives": ["Identify environmental and resident-specific accident risks.", "Follow assigned transfer, lift, mobility, and assistance levels.", "Respond safely to a fall or near miss without moving the resident prematurely.", "Report and document hazards, equipment problems, and changes in mobility."],
    "lessons": [
      {"title": "Resident-specific risk and environment", "content": "Review the care plan for assistance level, footwear, sensory needs, toileting schedule, orthostatic risk, cognition, mobility aids, and alarms or safeguards. Before care, scan for spills, clutter, poor lighting, bed or chair position, inaccessible call devices, and incorrect equipment. Correct hazards within role and report recurring or structural risks. A generic fall score never replaces observing the resident's current condition.", "takeaway": "Combine the care plan with a fresh environmental and resident check before every mobility task."},
      {"title": "Transfers, lifts, and mobility aids", "content": "Use only equipment for which you are trained and currently authorized, with the sling, number of staff, weight limit, and assistance level specified in the plan. Explain the task, lock or position equipment as directed, use body mechanics, and communicate with the resident and partner. Stop if equipment is damaged, the plan does not match current ability, or the resident develops pain, weakness, dizziness, or fear.", "takeaway": "Follow the exact transfer plan and stop for unsafe equipment or a change in the resident's ability or symptoms."},
      {"title": "Fall and near-miss response", "content": "If a resident falls, call for help, protect from further injury, and do not lift or reposition unless immediate danger or clinical direction requires it. Observe breathing, responsiveness, pain, position, bleeding, and surrounding facts without performing an assessment outside role. Stay with the resident, follow emergency and post-fall procedures, and preserve the scene when safe. Near misses also reveal hazards and should be reported.", "takeaway": "After a fall, protect and observe the resident, summon help, and do not move the person until authorized unless immediate danger requires it."},
      {"title": "Reporting, learning, and restraint avoidance", "content": "Report equipment defects, changes in gait or transfer ability, dizziness, unsafe footwear, repeated call attempts, and workarounds. Document objective circumstances and actions, not blame. Devices or practices that limit movement can be restraints depending on purpose and effect; never add side rails, belts, trays, alarms, or furniture barriers for convenience. Use only assessed, authorized, least-restrictive safeguards in the plan.", "takeaway": "Report changes and hazards and never add an unauthorized movement-limiting device for convenience."}
    ],
    "scenarios": [
      {"title": "The transfer plan no longer fits", "content": "A resident assigned a one-person pivot transfer cannot bear weight today and says the knee is newly painful. The mechanical lift is on another unit.", "response": "Do not attempt the planned pivot, keep the resident safe and comfortable, promptly notify the nurse of the change, obtain trained help and authorized equipment, and document the observations and actions."},
      {"title": "A resident found on the floor", "content": "You enter a room and find a resident sitting on the floor beside the bed, alert but reporting hip pain. A coworker reaches down to lift the resident quickly.", "response": "Stop an unassessed lift, summon the nurse and required help, keep the resident still and protected unless immediate danger exists, observe and report objective findings, and follow the facility's fall-response and documentation process."}
    ],
    "citation_label": "28 Pa. Code 201.20 and 42 CFR 483.25, 483.95",
    "citation_url": "https://www.pacodeandbulletin.gov/secure/pacode/data/028/chapter201/s201.20.html | https://www.ecfr.gov/current/title-42/part-483/section-483.25 | https://www.ecfr.gov/current/title-42/part-483/section-483.95",
    "citation_note": "Pennsylvania expressly includes accident prevention in annual nursing-facility education. Federal quality-of-care and training rules require adequate supervision, assistive devices, competency, and facility-specific training. Transfer techniques and equipment must be tailored to policy and resident plans."
  },
  {
    "catalog_code": "PA-NH-AIDE-RESTORATIVE-NURSING",
    "track": "NH",
    "title": "Restorative Nursing and Maintenance of Function for Nursing Home Aides",
    "summary": "Teaches plan-directed support for mobility, range of motion, self-care, continence, communication, and resident participation while preventing over-assistance and avoidable decline.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 60,
    "topic_code": "NH-PA201.20-A2",
    "objectives": ["Explain how restorative approaches preserve function and autonomy.", "Use cueing, pacing, and graded assistance according to the plan.", "Recognize intolerance, pain, fatigue, and functional change requiring reporting.", "Document resident participation and response objectively."],
    "lessons": [
      {"title": "Restorative purpose and the aide role", "content": "Restorative nursing helps a resident attain or maintain the highest practicable physical, mental, and psychosocial function. The aide carries out assigned activities under nursing direction; the aide does not design exercises, change repetitions, or replace therapy. Review the goal, technique, assistance level, precautions, and frequency before beginning, and ask for clarification when the restorative plan and current assignment differ.", "takeaway": "Carry out the assigned restorative plan under nursing direction and never independently design or change the program."},
      {"title": "Promoting participation instead of dependence", "content": "Allow the resident time to do each safe part of dressing, grooming, eating, mobility, communication, or toileting. Set up supplies, offer stepwise cues, use adaptive devices as trained, and provide only the assistance needed. Rushing or completing every task for the resident can reduce skill and choice. Praise effort without treating an adult like a child, and honor rest and preference within the plan.", "takeaway": "Use time, setup, cues, and the least assistance needed so the resident performs every safe part possible."},
      {"title": "Safe movement and tolerance", "content": "Use prescribed alignment, supports, repetitions, devices, and assistance for walking, range of motion, positioning, or splint routines. Watch for pain, shortness of breath, dizziness, weakness, color change, guarding, swelling, or reduced performance. Stop or pause as the plan directs and report unexpected symptoms or decline. Never force a joint, continue through new pain, or use equipment without training.", "takeaway": "Follow prescribed technique and stop and report unexpected pain, symptoms, or decline rather than forcing completion."},
      {"title": "Measuring and communicating progress", "content": "Document the assigned activity, assistance and cues provided, distance or repetitions when required, participation, tolerance, refusals, and reason known. Use observable language rather than vague labels such as lazy or did well. Report trends such as greater assistance, new loss of balance, repeated refusal, or improved independence so the nurse can evaluate the plan and coordinate with therapy.", "takeaway": "Record measurable participation and report trends in ability, tolerance, or refusal so the team can evaluate the plan."}
    ],
    "scenarios": [
      {"title": "Finishing faster", "content": "A resident can button a shirt with setup and extra time, but the unit is busy and a coworker suggests dressing the resident completely.", "response": "Set up the clothing, cue and allow the planned time for participation, assist only where needed, communicate workload concerns through supervision, and document the resident's actual assistance level."},
      {"title": "New pain during range of motion", "content": "During an assigned passive range-of-motion routine, the resident grimaces and says the shoulder pain is new.", "response": "Stop the movement without forcing the joint, position the resident comfortably, promptly report the pain and exact point in the activity to the nurse, follow directions, and document the response."}
    ],
    "citation_label": "28 Pa. Code 201.20 and 42 CFR 483.24, 483.95",
    "citation_url": "https://www.pacodeandbulletin.gov/secure/pacode/data/028/chapter201/s201.20.html | https://www.ecfr.gov/current/title-42/part-483/section-483.24 | https://www.ecfr.gov/current/title-42/part-483/section-483.95",
    "citation_note": "Pennsylvania expressly includes restorative nursing techniques in annual education. Federal quality-of-life and training rules support maintaining function and competency. The facility must tailor techniques, precautions, competency validation, and documentation to each resident and its program."
  },
  {
    "catalog_code": "PA-NH-AIDE-PERSONAL-CARE-SKIN-NUTRITION",
    "track": "NH",
    "title": "Personal Care, Skin Observation, Nutrition, and Hydration for Nursing Home Aides",
    "summary": "Integrates dignified personal care with skin observation, oral health, nutrition, hydration, elimination, and prompt reporting of meaningful change.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 60,
    "topic_code": "NH-JOB-SKILLS-PERSONAL-CARE",
    "objectives": ["Provide personal care that protects privacy, choice, and infection control.", "Observe and report skin, oral, elimination, intake, and swallowing changes.", "Follow diet, fluid, assistance, and positioning directions exactly.", "Document care, intake, output, refusals, and changes accurately."],
    "lessons": [
      {"title": "Dignified bathing, grooming, and elimination care", "content": "Review preferences and precautions, explain the sequence, gather supplies, provide privacy, and encourage participation. Work from clean to less clean areas, use water temperature and products approved by the plan, and avoid sharing personal items. During toileting and continence care, respond promptly, protect skin, and never shame a resident for odor, incontinence, body size, anatomy, or assistance needs.", "takeaway": "Explain and individualize personal care, protect privacy and skin, and encourage the resident's safe participation."},
      {"title": "Skin and oral observation", "content": "During authorized care, observe exposed skin for redness, discoloration, warmth, moisture, rash, tears, bruising, swelling, drainage, and pain, especially at pressure points and under devices. Observe the mouth for dryness, sores, bleeding, broken teeth, coating, or denture problems. Report new findings promptly and use only approved products; do not massage reddened pressure areas or independently treat wounds.", "takeaway": "Report new skin or oral findings promptly and use only plan-approved prevention and care measures."},
      {"title": "Meals, hydration, and swallowing safety", "content": "Verify the correct resident, diet texture, liquid consistency, allergies, positioning, adaptive equipment, and assistance level before offering food or fluid. Keep the resident upright as directed, pace bites and sips, and monitor for coughing, wet voice, pocketing, fatigue, breathing change, or distress. Stop and obtain clinical help for swallowing warning signs. Never alter a diet, thicken liquids, or force intake independently.", "takeaway": "Verify diet and feeding directions, monitor swallowing, and stop and report warning signs without independently changing food or fluids."},
      {"title": "Intake, output, refusals, and change", "content": "Measure and record meal percentage, fluids, output, bowel patterns, weight-related observations, and assistance using the facility method. Report reduced intake, repeated refusal, vomiting, diarrhea, constipation signs, dark or low urine, edema, sudden weight concern, or a change from baseline. Explore preferences within role and offer authorized alternatives, but never conceal poor intake or chart care before it occurs.", "takeaway": "Record actual intake and output and promptly report refusals or changes rather than estimating or pre-charting."}
    ],
    "scenarios": [
      {"title": "Coughing at lunch", "content": "A resident on a modified diet begins coughing, has a wet-sounding voice, and appears short of breath after a sip.", "response": "Stop feeding, keep the resident in the directed safe position, summon the nurse and emergency help according to symptoms and policy, do not offer more food or fluid, and document the objective signs and response."},
      {"title": "Nonblanching heel redness", "content": "While removing socks, you notice persistent dark-red discoloration on a resident's heel that was not reported at the start of the shift.", "response": "Relieve pressure using the existing plan, avoid rubbing or applying an unapproved product, promptly notify the nurse, protect the area during care, and document the location and objective appearance."}
    ],
    "citation_label": "42 CFR 483.24, 483.25, and 483.95",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-483/section-483.24 | https://www.ecfr.gov/current/title-42/part-483/section-483.25 | https://www.ecfr.gov/current/title-42/part-483/section-483.95",
    "citation_note": "Federal quality-of-life, quality-of-care, nutrition, and training requirements support competent personal care and observation. The facility must tailor diets, skin protocols, swallowing precautions, products, measurement rules, and escalation instructions to current orders and resident plans."
  },
  {
    "catalog_code": "PA-NH-AIDE-EMERGENCY-FIRE-PREPAREDNESS",
    "track": "NH",
    "title": "Emergency and Fire Preparedness for Nursing Home Aides",
    "summary": "Prepares aides to carry out assigned emergency roles for fire, evacuation, sheltering, severe weather, utility failure, missing residents, and acute medical events.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 60,
    "topic_code": "NH-PA201.20-A3-A4",
    "objectives": ["Locate and follow facility-specific emergency roles and communication methods.", "Use the facility fire response and movement priorities without improvising unsafe actions.", "Support residents during evacuation or sheltering according to acuity and mobility needs.", "Report hazards and participate in drills, debriefing, and corrective action."],
    "lessons": [
      {"title": "Know the plan before the event", "content": "Learn the alarm signals, emergency numbers, command structure, alternate communication methods, evacuation zones, shelter locations, exits, fire doors, extinguishers, oxygen controls, resident tracking tools, and your assigned role. Review which residents need lifts, two-person help, oxygen, communication supports, or close supervision. Do not wait for an alarm to discover equipment or assume a role that conflicts with the facility plan.", "takeaway": "Know your assigned role, alarms, routes, communication methods, and resident assistance needs before an emergency."},
      {"title": "Fire and smoke response", "content": "Follow the facility's fire sequence and alarm procedures, remove people from immediate danger only when safe, close doors or contain smoke as directed, and never block exits or fire doors. Use an extinguisher only if trained, assigned, and there is a safe escape path. Do not reenter, use elevators, shut off oxygen, or move residents contrary to command instructions and the approved fire plan.", "takeaway": "Activate the facility fire plan, protect people from immediate danger, and perform only trained and assigned fire actions."},
      {"title": "Evacuation, sheltering, and continuity", "content": "Use the ordered horizontal, vertical, partial, or full movement plan and the specified equipment and staffing. Maintain resident identification, essential information, medications or supplies only as assigned, and continuous accountability at receiving areas. Preserve warmth, privacy, communication, hydration, and supervision. Never leave a resident untracked or choose a destination independently because it appears faster.", "takeaway": "Move and account for residents exactly as the incident plan directs while maintaining safety, dignity, and essential supports."},
      {"title": "Medical events, missing residents, and drills", "content": "For acute symptoms or injury, summon licensed and emergency help, begin only trained response measures, and communicate objective observations. For a missing resident, immediately activate the search and notification procedure rather than searching alone or delaying. Treat drills as real practice: carry out the role, identify barriers, report equipment or communication failures, and participate in debriefing without falsifying completion.", "takeaway": "Activate the correct emergency pathway immediately, perform trained actions, and report drill or response gaps for correction."}
    ],
    "scenarios": [
      {"title": "Smoke in a laundry area", "content": "You smell smoke and see haze coming from a laundry-room doorway near two resident rooms. No alarm is sounding yet.", "response": "Immediately initiate the facility fire notification and alarm procedure, protect residents in immediate danger as trained, close or contain the area if directed and safe, follow command instructions, and do not enter smoke or fight the fire unless trained and assigned."},
      {"title": "Power loss during severe weather", "content": "The unit loses power during a storm, electronic call systems fail, and one resident uses oxygen equipment.", "response": "Activate the downtime communication process, immediately report oxygen and other priority needs, use assigned backup equipment and rounding procedures, keep exits clear, account for residents, and document actions under the emergency plan."}
    ],
    "citation_label": "28 Pa. Code 201.20 and 42 CFR 483.73, 483.90, 483.95",
    "citation_url": "https://www.pacodeandbulletin.gov/secure/pacode/data/028/chapter201/s201.20.html | https://www.ecfr.gov/current/title-42/part-483/section-483.73 | https://www.ecfr.gov/current/title-42/part-483/section-483.90 | https://www.ecfr.gov/current/title-42/part-483/section-483.95",
    "citation_note": "Pennsylvania annual education expressly includes emergency and fire prevention procedures. Federal emergency-preparedness, physical-environment and life-safety-from-fire, and training rules require facility-specific plans, policies, communication, and exercises. Credit requires employer drills, local procedures, and role validation; this module cannot substitute for them."
  },
  {
    "catalog_code": "PA-NH-AIDE-BEHAVIORAL-HEALTH-PERSON-CENTERED",
    "track": "NH",
    "title": "Behavioral Health and Person-Centered Support for Nursing Home Aides",
    "summary": "Builds respectful observation and response skills for behavioral health needs, trauma histories, substance-use concerns, distress, and crisis warning signs.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 45,
    "topic_code": "NH-483.95-I",
    "objectives": ["Use nonstigmatizing language and person-centered support.", "Recognize changes and crisis warning signs requiring escalation.", "Apply trauma-informed de-escalation within the care plan.", "Maintain boundaries, safety, privacy, and objective documentation."],
    "lessons": [
      {"title": "Behavior is information", "content": "Describe what the resident says and does instead of applying labels such as manipulative, crazy, or difficult. Compare with baseline and consider pain, medication effects, sleep loss, grief, trauma reminders, substance withdrawal, sensory needs, loneliness, or environmental stress. The aide observes and reports; diagnosis and treatment decisions belong to qualified clinicians. Respect recovery goals and avoid moral judgment.", "takeaway": "Describe observable behavior and possible context without diagnosing or using stigmatizing labels."},
      {"title": "Trauma-informed interaction", "content": "Promote safety, predictability, voice, and choice. Explain before approaching or touching, ask permission, offer options, and recognize that loss of control, noise, exposure, or certain caregivers may trigger distress. Avoid threats, crowding, power struggles, forced disclosure, or promises of secrecy. Follow documented preferences and report new triggers so the team can strengthen the plan.", "takeaway": "Use predictability, permission, choice, and plan-based supports while avoiding coercion and unnecessary triggering."},
      {"title": "De-escalation and crisis warning signs", "content": "Stay calm, maintain personal space and an exit route, reduce stimulation, use short respectful statements, and offer a simple safe choice. Summon help early for escalating agitation, threats, weapons, self-harm statements, severe withdrawal signs, hallucination-related danger, or abrupt mental-status change. Do not argue, restrain, search belongings, or attempt counseling beyond training and policy.", "takeaway": "Use calm low-stimulation de-escalation and summon help early for danger, self-harm, or acute change."},
      {"title": "Boundaries, privacy, and documentation", "content": "Be supportive without exchanging money, gifts outside policy, private contact information, substances, favors, secrets, or personal social-media access. Share information only through authorized care channels. Document exact words, observed behavior, precipitating events, interventions, response, injuries, and notifications. Report boundary violations by anyone and seek supervision when a resident request creates uncertainty.", "takeaway": "Maintain professional boundaries and document exact observations, interventions, response, and notifications."}
    ],
    "scenarios": [
      {"title": "A statement of hopelessness", "content": "A resident quietly says there is no reason to live and asks you not to tell anyone. The resident then turns away.", "response": "Stay present and take the statement seriously, immediately notify the nurse and activate the facility's self-harm safety pathway, do not promise secrecy or leave the resident alone if policy directs observation, and document the exact words."},
      {"title": "Escalation during care", "content": "A resident with a trauma history begins shouting and pushing your hands away during bathing after the door opens unexpectedly.", "response": "Stop nonurgent care, restore privacy, step back, speak calmly, offer a plan-consistent choice, obtain help if safety risk continues, and report the trigger and response so the care approach can be reviewed."}
    ],
    "citation_label": "42 CFR 483.40 and 483.95",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-483/section-483.40 | https://www.ecfr.gov/current/title-42/part-483/section-483.95",
    "citation_note": "Federal nursing-facility rules address behavioral health services and training for staff caring for residents with mental and psychosocial disorders, substance-use disorders, and related needs. Facility assessment, population, crisis resources, and policies must tailor this content."
  },
  {
    "catalog_code": "PA-NH-AIDE-QAPI-ETHICS-DOCUMENTATION",
    "track": "NH",
    "title": "QAPI, Ethics, and Documentation for Nursing Home Aides",
    "summary": "Connects accurate records, ethical conduct, incident reporting, privacy, teamwork, and frontline observations to nursing-home quality assurance and performance improvement.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 45,
    "topic_code": "NH-483.95-D-F",
    "objectives": ["Create timely, objective, complete records within the aide role.", "Identify ethical and privacy risks in daily work.", "Report incidents, near misses, and quality concerns through protected channels.", "Participate in QAPI learning without altering or concealing facts."],
    "lessons": [
      {"title": "Records that tell the truth", "content": "Chart only care you provided or observations you made, at the correct time and in the correct resident record. Use measurements and specific behavior rather than unsupported conclusions. Never pre-chart, copy a prior entry without verification, share credentials, backdate, erase, or alter another person's record. Correct errors through the approved audit-preserving process and promptly report any mistaken entry that affects care.", "takeaway": "Document actual care and objective observations promptly, and correct errors only through the approved audit-preserving process."},
      {"title": "Ethics, privacy, and conflicts", "content": "Protect resident information in conversation, screens, paper, photographs, messaging, and social media. Access only what work requires and use approved communication systems. Avoid favoritism, borrowing, financial involvement, hidden gifts, falsified time, and personal relationships that impair judgment. When policy, an assignment, and resident welfare appear to conflict, protect immediate safety and seek supervisory guidance rather than hiding the concern.", "takeaway": "Use resident information only for authorized work and disclose conflicts or boundary concerns through supervision."},
      {"title": "Incidents and just learning", "content": "Report injury, error, near miss, equipment failure, missing item, unsafe staffing condition, and deviation from a plan as policy requires. Immediate safety and clinical notification come before completing forms. Describe events without blame, retaliation, or speculation. An incident report does not replace the clinical record, and the clinical record should not mention confidential quality-review conclusions unless policy directs.", "takeaway": "Protect the resident and report incidents and near misses promptly with objective facts; one record never substitutes for another."},
      {"title": "Frontline participation in QAPI", "content": "Aides see recurring workflow and resident-response patterns that dashboards may miss. Participate honestly in huddles, audits, root-cause discussions, tests of change, and competency refreshers. Distinguish a temporary workaround from an approved process, identify unintended effects, and report when an improvement creates a new risk. Never manipulate documentation or resident selection to make a measure look better.", "takeaway": "Contribute honest frontline observations to improvement work and report unintended risks without manipulating data."}
    ],
    "scenarios": [
      {"title": "Charting for a coworker", "content": "A coworker forgot to chart a completed round and asks to use your login because the coworker's account is locked.", "response": "Refuse to share credentials or enter another person's work, help the coworker contact the approved support or supervisor, and report any care concern or record delay through policy."},
      {"title": "A repeated near miss", "content": "A lift battery repeatedly fails during setup, but staff swap batteries and do not report it because no resident has fallen.", "response": "Remove or tag unsafe equipment as policy allows, protect the resident, notify the supervisor and equipment process, submit the required near-miss report, and provide objective details for corrective action."}
    ],
    "citation_label": "42 CFR 483.75 and 483.95",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-483/section-483.75 | https://www.ecfr.gov/current/title-42/part-483/section-483.95",
    "citation_note": "Federal nursing-facility rules require QAPI, effective communication, compliance and ethics, and staff training. Facility documentation systems, incident policies, privacy controls, and current QAPI priorities must tailor exercises and acceptance."
  },
  {
    "catalog_code": "PA-NH-AIDE-PERFORMANCE-FACILITY-REMEDIATION",
    "track": "NH",
    "title": "Performance Review and Facility-Needs Remediation for Nursing Home Aides",
    "summary": "Provides a structured annual module for correcting nurse-aide performance gaps and addressing resident-population and facility-assessment priorities through employer-selected practice.",
    "category": "Nursing Home Aide Annual",
    "duration_minutes": 60,
    "topic_code": "NH-483.95-G3-PA201.20-A6",
    "objectives": ["Translate performance feedback into observable safe-practice actions.", "Connect annual learning to the facility assessment and resident population.", "Practice feedback, teach-back, and escalation when a task is unclear or beyond competence.", "Document remediation and competency evidence without overstating mastery."],
    "lessons": [
      {"title": "From feedback to a learning target", "content": "Performance feedback should identify an observable gap, the expected standard, resident risk, and the conditions under which the skill occurs. Restate the target in your own words, ask for examples, and distinguish a knowledge gap from a hands-on competency need, workload barrier, equipment problem, or unclear plan. Training alone cannot solve every system issue, and accepting feedback does not require concealing contributing conditions.", "takeaway": "Turn feedback into a specific observable target and identify whether education, competency practice, or system correction is needed."},
      {"title": "Facility assessment and population needs", "content": "The facility assessment describes the resident population, acuity, diagnoses, behavioral and communication needs, services, staffing competencies, equipment, and emergency demands. Annual education should reflect these realities, including new populations, recurring incidents, survey findings, infection risks, and technology changes. The employer must insert its current priorities; generic vendor material cannot decide which local risks are most important.", "takeaway": "Use the current facility assessment and resident population to choose and tailor the annual learning priority."},
      {"title": "Deliberate practice and competency evidence", "content": "Review the standard, observe a qualified demonstration when needed, practice in a safe setting, receive specific feedback, and repeat until the employer's evaluator confirms the required performance. Explain what you would do when the usual conditions change. Course completion measures learning activity, while competency may require direct observation, return demonstration, simulation, or other employer-defined evidence.", "takeaway": "Complete employer-required practice and competency validation; an online completion record alone does not prove hands-on competence."},
      {"title": "Speaking up and sustaining improvement", "content": "Before performing an unfamiliar, changed, or unsafe task, pause and tell the responsible nurse what is unclear. Seek supervision, equipment, staffing, or retraining rather than improvising. After remediation, use checklists, peer reminders, huddles, or follow-up observation approved by the facility. Report when the solution does not work in actual conditions, and document completion accurately without altering dates or evaluator findings.", "takeaway": "Pause and seek help for unclear or unsafe work, then use honest follow-up evidence to show whether improvement is sustained."}
    ],
    "scenarios": [
      {"title": "A recurring documentation gap", "content": "A performance review finds repeated missing intake entries. The aide says the electronic device often loses connection during meals.", "response": "Review the required measurement and downtime process, practice accurate entry and correction, report the connectivity barrier for system action, and complete employer follow-up validation without inventing missing values."},
      {"title": "A new high-acuity admission pattern", "content": "The facility begins admitting more residents with complex transfer equipment, but several aides have only watched a brief video.", "response": "Do not use unfamiliar equipment independently, notify the nurse or educator of the competency gap, obtain device-specific training and supervised return demonstration, and ensure the facility assessment and assignments reflect available competency."}
    ],
    "citation_label": "42 CFR 483.71, 483.95, and 28 Pa. Code 201.20",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-483/section-483.71 | https://www.ecfr.gov/current/title-42/part-483/section-483.95 | https://www.pacodeandbulletin.gov/secure/pacode/data/028/chapter201/s201.20.html",
    "citation_note": "Federal rules require annual nurse-aide in-service education sufficient to ensure continuing competence, including areas of weakness from performance review and facility-assessment needs. Pennsylvania requires at least annual facility-needs-based education. The employer must select the actual remediation target and validate competence."
  }
]
$nh$::jsonb;
  v_hha_catalog jsonb := $hha$
[
  {
    "catalog_code": "PA-HHA-AIDE-RIGHTS-COMMUNICATION-CULTURE",
    "track": "HHA",
    "title": "Patient Rights, Communication, and Cultural Responsiveness for Home Health Aides",
    "summary": "Applies patient rights, privacy, communication access, cultural humility, choice, and professional boundaries to care delivered in a person's home.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HHA-484.80-D-01",
    "objectives": ["Protect rights, dignity, privacy, and choice during home care.", "Use patient-specific communication supports and authorized language access.", "Explain how the aging process and emotional problems of illness can affect communication without stereotyping.", "Respond respectfully to cultural, disability, identity, and household preferences and escalate unresolved concerns."],
    "lessons": [
      {"title": "Rights travel into the home", "content": "Entering a person's home does not reduce the patient's rights. Introduce yourself, seek permission before entering rooms or moving belongings, explain care, provide privacy, and honor the care-plan schedule and preferences as far as authorized. A patient may refuse. Pause, address an immediate comfort or communication barrier, notify the supervising nurse as required, and never threaten discharge, shame, or withhold care to gain cooperation.", "takeaway": "Seek permission, protect privacy and choice, and report refusals without coercion or punishment."},
      {"title": "Accessible and accurate communication", "content": "Use the communication method in the plan, such as glasses, hearing devices, writing, picture boards, plain language, or agency-arranged interpreter service. Face the patient, reduce noise, allow time, and confirm understanding with respectful teach-back. Do not rely on unapproved relatives or children for sensitive interpretation, and do not guess when instructions, symptoms, or preferences are unclear.", "takeaway": "Use plan-directed communication supports and agency-approved language access, then confirm understanding respectfully."},
      {"title": "Aging, emotional effects of illness, culture, and identity", "content": "Aging is a varied life process, not a diagnosis: sensory, mobility, sleep, memory, social-role, and energy changes differ by person and can interact with illness. Illness can bring fear, grief, anger, shame, loneliness, loss of control, or changing family roles. Observe and report a change from the patient's baseline without labeling emotion as difficult behavior or assuming every change is age-related. Ask how culture, faith, disability, gender identity, and household routines affect support, and follow the plan without stereotypes.", "takeaway": "Recognize individual aging and illness-related emotional needs without stereotyping, then report meaningful changes from baseline."},
      {"title": "Choice, privacy, and boundaries", "content": "Support plan-consistent choices while protecting confidential information from neighbors, visitors, unsecured messages, and social media. Maintain boundaries around gifts, money, errands, keys, transportation, photographs, personal contact, and family disputes according to agency policy. If a request falls outside the plan or creates risk, explain the role limit, offer an authorized option, and contact the supervisor rather than making a private arrangement.", "takeaway": "Maintain privacy and agency boundaries, and escalate requests outside the plan instead of creating private arrangements."}
    ],
    "scenarios": [
      {"title": "A family member answers for the patient", "content": "A competent patient tries to describe a care preference, but a relative repeatedly interrupts and tells the aide to ignore the patient.", "response": "Address the patient directly, provide privacy when appropriate, use communication supports, follow the authorized plan, and report any unresolved conflict, coercion, or safety concern to the supervising nurse."},
      {"title": "A request to post a photograph", "content": "A patient asks the aide to take a selfie together and post it online to thank the agency.", "response": "Do not use a personal device or post patient information; explain the privacy and boundary rule, refer the request to the agency's authorized process, and document or report the interaction if policy requires."}
    ],
    "citation_label": "42 CFR 484.50, 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.50 | https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal HHA conditions protect patient rights and require at least 12 hours of annual in-service training. Pennsylvania Section 601.35 expressly requires training in the aging process, emotional problems of illness, ethics, confidentiality, the health team, and related home-care skills. For credit, the agency RN must approve the content and attend the in-service to supervise it, and the agency must retain the record."
  },
  {
    "catalog_code": "PA-HHA-AIDE-OBSERVATION-VITALS-ESCALATION",
    "track": "HHA",
    "title": "Observation, Vital Signs, and Escalation for Home Health Aides",
    "summary": "Develops accurate observation, assigned measurement, comparison with baseline, and timely escalation of acute or meaningful changes in the home.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 90,
    "topic_code": "HHA-484.80-D-02",
    "objectives": ["Observe and communicate objective changes without diagnosing.", "Obtain assigned vital signs and measurements using validated agency technique.", "Distinguish emergency, urgent, and routine reporting pathways using agency instructions.", "Document readings, symptoms, actions, and notifications accurately."],
    "lessons": [
      {"title": "Baseline and focused observation", "content": "Know the patient's usual alertness, breathing, skin color, mobility, speech, intake, output, pain expression, mood, and ability to complete activities. Observe during normal care without conducting an independent assessment. Describe what changed, when it began, what the patient reports, relevant measurements, and how function differs. Avoid labels such as stable or fine when specific facts show a change.", "takeaway": "Compare specific observations with baseline and communicate facts rather than a diagnosis or vague conclusion."},
      {"title": "Accurate assigned measurements", "content": "Measure temperature, pulse, respirations, blood pressure, weight, intake, output, or other assigned data only when trained, delegated or included in role, and directed by the plan. Verify equipment, patient identity, position, timing, cuff or device fit, and repeat rules. Never change a reading, invent missing data, or repeatedly test in a way that delays escalation of symptoms.", "takeaway": "Use the agency-validated technique for assigned measurements and report questionable readings without altering or hiding them."},
      {"title": "Emergency and urgent escalation", "content": "Follow the individualized emergency instructions and agency call tree. Call emergency services for the signs and circumstances identified by the plan or policy, then notify the agency; examples may include unresponsiveness, severe breathing difficulty, uncontrolled bleeding, or other immediate threats. For meaningful but non-immediate changes, promptly contact the supervising nurse. If no one answers, use the next escalation contact rather than waiting until the next visit.", "takeaway": "Use the agency's emergency and alternate call pathways immediately; never wait with a serious or worsening change."},
      {"title": "Closed-loop reporting and documentation", "content": "Give the patient's identity, exact change, onset, symptoms, readings, actions already taken, and current safety. Read back directions when required and clarify who will follow up. Document the actual measurement, patient statement, time, person notified, direction received, action, and response. Do not enter a nurse assessment, promise an outcome, or omit a call that did not connect.", "takeaway": "Report with specific facts, confirm directions, and document every attempted and completed notification and response."}
    ],
    "scenarios": [
      {"title": "Breathing is suddenly difficult", "content": "During morning care, a patient becomes unable to speak a full sentence, looks blue around the lips, and appears frightened. The family asks the aide to wait for a relative who is a nurse.", "response": "Activate emergency services immediately according to the plan and agency policy, keep the patient safe, perform only trained emergency measures, notify the agency, and document objective signs and actions without delaying for the relative."},
      {"title": "A concerning weight change", "content": "An assigned daily weight is several pounds above the recent recorded range, and the patient has more ankle swelling but says there is no need to bother anyone.", "response": "Verify the measurement using agency technique without repeated delay, promptly notify the supervising nurse with the weight trend and swelling observation, follow directions, and document the patient's statement and communications."}
    ],
    "citation_label": "42 CFR 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal competency rules and Pennsylvania Section 601.35 require aides to recognize and report changes in condition and to work from RN-prepared patient instructions; assigned basic measurements must follow agency competency. For credit, the agency RN must approve the content and attend the in-service to supervise it, with agency thresholds, emergency protocols, and records applied."
  },
  {
    "catalog_code": "PA-HHA-AIDE-DOCUMENTATION-CARE-COORDINATION",
    "track": "HHA",
    "title": "Documentation and Care Coordination for Home Health Aides",
    "summary": "Builds timely, objective home-visit records and reliable communication with the supervising nurse and interdisciplinary team.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HHA-484.80-D-03",
    "objectives": ["Document delivered care and patient response accurately and promptly.", "Communicate deviations, refusals, and changes through the agency chain.", "Protect records and electronic credentials in the home and during travel.", "Use correction, late-entry, and downtime procedures without obscuring the audit trail."],
    "lessons": [
      {"title": "The visit record", "content": "Record arrival and departure as required, tasks actually completed, assistance level, observations, measurements, patient response, refusals, and communications. Match entries to the plan and do not pre-chart, copy forward without verification, or record a task completed by someone else. If scheduled work was not done, state what occurred and notify the supervisor according to agency policy rather than making the record appear complete.", "takeaway": "Chart only actual care and observations, including omitted or refused tasks and the required notification."},
      {"title": "Objective language and meaningful detail", "content": "Use direct quotes and measurable descriptions: location and appearance of a skin change, amount eaten, distance walked, number of prompts, or exact behavior. Avoid blame, guesses, diagnostic labels, and vague phrases. Separate what the patient or family reported from what you observed. Relevant context helps the nurse act; unrelated personal judgments do not belong in the record.", "takeaway": "Use measurements, direct quotes, and observable facts while separating reports from your own observations."},
      {"title": "Coordination and deviation from plan", "content": "Contact the supervising nurse when the patient's condition, environment, available caregiver, equipment, or willingness makes the plan unsafe or impossible. Do not independently substitute a different clinical task or silently omit care. Use closed-loop communication, repeat back directions when needed, and identify unresolved needs at handoff. Emergency communication takes priority over routine electronic completion.", "takeaway": "Report deviations and unresolved needs promptly and obtain direction instead of silently changing the plan."},
      {"title": "Security, corrections, and downtime", "content": "Protect paper and electronic records from household members, vehicles, public screens, unsecured texts, and personal apps. Use only your credentials and log out. Correct errors through the agency process that preserves the original entry, author, date, and reason; never erase or backdate. During outage, use the approved downtime form and reconcile it promptly without duplicating or losing information.", "takeaway": "Secure records and use audit-preserving correction and downtime processes with your own credentials."}
    ],
    "scenarios": [
      {"title": "A missed task", "content": "The care plan requires a supervised walk, but the patient's dizziness makes standing unsafe. The visit application will not close unless every task is marked complete.", "response": "Do not perform an unsafe walk or falsely mark it complete; keep the patient safe, notify the supervising nurse, record the dizziness and omitted task using the agency exception process, and follow new directions."},
      {"title": "A late correction", "content": "After leaving the home, an aide notices that an intake amount was entered in the wrong patient's record.", "response": "Immediately notify the agency as required, use the authorized correction process that preserves the audit trail, enter the correct information only when verified, and never overwrite, delete, or conceal the error."}
    ],
    "citation_label": "42 CFR 484.60, 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.60 | https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal rules require care-plan coordination and annual in-service; Pennsylvania Section 601.35 requires training in agency and health-team work, ethics, confidentiality, reporting changes, and recordkeeping. For credit, the agency RN must approve the content and attend the in-service to supervise it, and the agency must insert its record system, call tree, and correction procedures."
  },
  {
    "catalog_code": "PA-HHA-AIDE-INFECTION-PREVENTION",
    "track": "HHA",
    "title": "Infection Prevention in the Home for Home Health Aides",
    "summary": "Adapts standard precautions, hand hygiene, PPE, clean-bag technique, equipment handling, exposure response, and symptom reporting to varied home environments.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HHA-484.80-D-04",
    "objectives": ["Perform hand hygiene and PPE use according to task and agency policy.", "Create a clean work zone and prevent contamination of supplies and equipment.", "Handle linen, waste, sharps encounters, and household hazards safely within role.", "Report symptoms and occupational exposures promptly."],
    "lessons": [
      {"title": "Standard precautions in every home", "content": "Plan for blood, body-fluid, nonintact-skin, and mucous-membrane exposure regardless of diagnosis. Carry approved hand-hygiene and PPE supplies, clean hands at agency-required moments, and remember that gloves do not replace hand hygiene. Ask where soap and water are available and use the required method for visibly soiled hands or specified organisms. Do not compromise precautions because a household considers them unnecessary.", "takeaway": "Apply standard precautions and required hand hygiene in every home, even when the household sees no infection risk."},
      {"title": "Clean-bag and supply technique", "content": "Place the agency bag or supplies on a clean, dry barrier away from pets, children, food, sinks, and contaminated items. Remove only what is needed, keep clean and used items separate, disinfect reusable equipment with the approved product and contact time, and discard the barrier as directed. Never place contaminated equipment back in the clean bag or refill personal containers with agency products.", "takeaway": "Establish a clean work zone and keep contaminated equipment and supplies out of the clean agency bag."},
      {"title": "PPE, linen, waste, and sharps", "content": "Select and remove PPE according to anticipated exposure and agency sequence. Bag linen and waste at the point of care as directed, avoid shaking linen, and do not compress bags with your hands. Home health aides do not recap or handle loose sharps unless specifically trained and assigned; protect the area, keep others away, and contact the agency for safe direction when an unexpected sharp is found.", "takeaway": "Use task-appropriate PPE and contain linen, waste, and unexpected sharps without contaminating yourself or the home."},
      {"title": "Symptoms, exposure, and work restrictions", "content": "Report patient changes such as fever, cough, drainage, vomiting, diarrhea, new confusion, or reduced intake, and follow plan-specific precautions. For a splash, needlestick, bite, or other exposure, perform immediate first aid and contact the agency without delay. Follow authorized testing, vaccination, outbreak, and work-restriction instructions while protecting patient confidentiality and avoiding unsupported claims about infection source.", "takeaway": "Report patient symptoms and occupational exposures promptly and follow the agency's current clinical and work instructions."}
    ],
    "scenarios": [
      {"title": "No clean surface", "content": "A crowded home has pets on the furniture and no visibly clean table for supplies. The visit includes perineal care.", "response": "Create an agency-approved clean work zone with a barrier, keep the bag closed and away from pets and contamination, remove only needed supplies, perform hand hygiene and PPE steps, and contact supervision if safe technique cannot be maintained."},
      {"title": "An unexpected needlestick", "content": "While gathering used linens, an aide is punctured by an uncapped needle hidden in the bedding.", "response": "Stop work, perform immediate first aid according to exposure policy, promptly contact the agency's exposure pathway for urgent evaluation, secure the hazard without recapping or unsafe handling, and document the event as directed."}
    ],
    "citation_label": "42 CFR 484.70, 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.70 | https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal HHA rules require infection-control practices and annual in-service, while Pennsylvania Section 601.35 requires procedures that maintain a clean, healthful, and pleasant home environment. For credit, the agency RN must approve the content and attend the in-service to supervise it. The agency must tailor PPE, bag technique, products, exposure contacts, and outbreak instructions."
  },
  {
    "catalog_code": "PA-HHA-AIDE-HOME-SAFETY-EMERGENCIES",
    "track": "HHA",
    "title": "Home Safety and Emergency Response for Home Health Aides",
    "summary": "Prepares aides to recognize environmental risk, follow individualized emergency plans, respond to acute events, and manage unsafe home or visit conditions.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HHA-484.80-D-05",
    "objectives": ["Identify and report home hazards affecting care and evacuation.", "Support a clean, healthful, and pleasant home environment through assigned household services.", "Use patient-specific emergency contacts and agency escalation pathways.", "Respond within training to falls, fire, weather, utility failure, and acute symptoms while protecting personal safety."],
    "lessons": [
      {"title": "A clean, healthful, pleasant, and safe home environment", "content": "Pennsylvania requires aides to be trained in procedures for maintaining a clean, healthful, and pleasant environment. Follow the care plan for household services essential to health care, such as clearing safe pathways, controlling contamination, handling food and waste, changing linens, and keeping needed equipment accessible. Pleasant means respecting the patient's home, routines, privacy, possessions, and sensory preferences rather than imposing the aide's housekeeping standard. Observe lighting, rugs, stairs, alarms, utilities, pets, smoking, oxygen, pests, spoiled food, and equipment, correct only assigned hazards with permission, and report unresolved risks.", "takeaway": "Perform assigned health-related household services with permission and report hazards without imposing personal housekeeping preferences."},
      {"title": "The individualized emergency plan", "content": "Know the patient's emergency contacts, evacuation assistance, communication limitations, backup power or oxygen process, medication and supply responsibilities, and agency call tree. Keep your phone and location information available under policy. If the plan is missing, outdated, or impossible to use, notify the supervisor before a predictable event. Do not create a private emergency arrangement with family or transport a patient in a personal vehicle unless explicitly authorized.", "takeaway": "Use the patient's current agency emergency plan and report gaps before an event instead of creating informal arrangements."},
      {"title": "Falls and acute events", "content": "For a fall, acute illness, injury, or change, protect the patient from further harm, summon the required clinical or emergency help, and do not lift, move, feed, medicate, or treat beyond training and direction. Observe and communicate responsiveness, breathing, bleeding, pain, position, symptoms, and circumstances. Stay until the authorized handoff when safe and document actions and notifications.", "takeaway": "Protect, observe, and summon the designated help; do not move or treat beyond training and authorized direction."},
      {"title": "Violence, fire, weather, and unsafe visits", "content": "Know the agency's worker-safety code, exit strategy, missed-visit process, and when to leave and call emergency services. Do not enter active violence, fire, hazardous fumes, unsecured weapons, or another imminent threat. From a safe location, activate help and notify the agency. During weather or utility failure, use the continuity plan and promptly escalate needs for heat, oxygen, refrigeration, power, water, or evacuation.", "takeaway": "Do not enter or remain in imminent danger; move to safety, activate emergency help, and use the agency continuity pathway."}
    ],
    "scenarios": [
      {"title": "A patient on the floor", "content": "The aide arrives and finds a patient on the bathroom floor reporting severe neck pain. A family member wants help lifting the patient into bed.", "response": "Do not lift the patient, activate emergency and agency procedures, keep the patient still and safe unless immediate danger requires movement, observe and report objective findings, and remain for authorized handoff if safe."},
      {"title": "Oxygen during a power outage", "content": "A storm causes prolonged power loss and the patient's oxygen concentrator stops. The backup arrangement in the home is unclear.", "response": "Immediately use the individualized emergency and oxygen plan, contact emergency services when indicated, notify the agency, keep the patient safe, do not improvise electrical or oxygen equipment, and document the response."}
    ],
    "citation_label": "42 CFR 484.60, 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.60 | https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal plan-of-care and aide rules require safe coordinated services and annual in-service. Pennsylvania Section 601.35 requires household services essential to home health care and training to maintain a clean, healthful, and pleasant environment. For credit, the agency RN must approve the content and attend the in-service to supervise it; the agency adds local emergency and continuity procedures."
  },
  {
    "catalog_code": "PA-HHA-AIDE-HYGIENE-ORAL-CONTINENCE-SKIN",
    "track": "HHA",
    "title": "Personal Hygiene, Oral Care, Continence, and Skin Observation for Home Health Aides",
    "summary": "Builds complete, dignified plan-directed personal care with focused skin and oral observation, continence support, infection prevention, and change reporting.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 90,
    "topic_code": "HHA-484.80-D-06",
    "objectives": ["Prepare and provide safe, private, preference-sensitive personal care.", "Support oral health and continence without stigma or shortcuts.", "Identify and report skin, mouth, urine, stool, pain, and functional changes.", "Use only plan-authorized products, devices, and techniques."],
    "lessons": [
      {"title": "Planning a safe personal-care visit", "content": "Review the plan for bathing method, assistance level, mobility limits, skin precautions, devices, products, preferences, and tasks the patient can do. Gather supplies, check water and room temperature, prevent slips, protect tubes and equipment, and position for safety and privacy. Explain each step and obtain consent. Stop when symptoms, equipment, environment, or patient response make the planned method unsafe.", "takeaway": "Review the plan, prepare the environment and supplies, obtain consent, and stop when conditions make care unsafe."},
      {"title": "Bathing, grooming, and oral care", "content": "Work from cleaner to more contaminated areas, change water or supplies as agency procedure directs, and dry skin folds gently. Encourage the patient to complete safe portions. For oral care, use the prescribed positioning, products, denture handling, and aspiration precautions. Observe dryness, sores, bleeding, broken teeth, coating, pain, and denture fit, and report changes rather than applying unapproved remedies.", "takeaway": "Provide clean-to-contaminated care with safe positioning and report oral changes instead of using unapproved treatments."},
      {"title": "Continence and elimination support", "content": "Follow scheduled toileting, transfer assistance, catheter or ostomy boundaries, incontinence-product use, perineal technique, and measurement directions in the plan. Respond promptly and respectfully, clean front to back when applicable, protect skin, and keep drainage systems positioned as trained. Do not insert, irrigate, disconnect, or manipulate a device unless specifically authorized, trained, and within agency policy.", "takeaway": "Use respectful plan-directed toileting and device care and never manipulate a catheter or ostomy beyond authorization and training."},
      {"title": "Skin observation and escalation", "content": "During care, observe pressure points and areas exposed by authorized tasks for redness or discoloration, warmth, moisture, rash, bruising, tears, drainage, swelling, or pain. Report new findings promptly with exact location and appearance. Follow turning, offloading, barrier, and device directions already in the plan. Do not stage wounds, massage persistent redness, or apply powders, creams, dressings, or treatments independently.", "takeaway": "Report objective skin changes promptly and use only plan-authorized prevention measures and products."}
    ],
    "scenarios": [
      {"title": "Dizziness in the shower", "content": "A patient becomes pale and dizzy while standing in a shower. The shower chair is across the room and the patient says to finish quickly.", "response": "Stop the shower, protect against a fall using trained assistance, help to the safest available position without exceeding transfer directions, summon help and notify the nurse according to severity, and document the symptoms and response."},
      {"title": "A new sacral skin change", "content": "During incontinence care, the aide sees a new dark area over the sacrum with intact skin. The family offers an herbal cream.", "response": "Do not apply the unapproved cream, reduce pressure using existing directions, keep the area clean and dry as planned, promptly notify the supervising nurse with the exact appearance, and document the finding."}
    ],
    "citation_label": "42 CFR 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal competency rules and Pennsylvania Section 601.35 support plan-directed personal care, simple procedures, reporting changes, and close supervision for competence. For credit, the agency RN must approve the content and attend the in-service to supervise it; the agency must validate hands-on competency and current products and device procedures."
  },
  {
    "catalog_code": "PA-HHA-AIDE-TRANSFERS-AMBULATION-FALLS",
    "track": "HHA",
    "title": "Transfers, Ambulation, and Fall Response for Home Health Aides",
    "summary": "Develops safe plan-directed mobility support, use of transfer devices, body mechanics, home-hazard control, and post-fall response.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 90,
    "topic_code": "HHA-484.80-D-07",
    "objectives": ["Verify assistance level, equipment, and precautions before mobility.", "Use trained transfer and ambulation techniques without improvisation.", "Recognize when current function no longer matches the plan.", "Respond to falls and near misses using the agency emergency process."],
    "lessons": [
      {"title": "Pre-mobility safety check", "content": "Review weight-bearing status, assistance level, devices, footwear, oxygen or line management, precautions, and symptoms that require stopping. Clear the route, position surfaces and equipment, lock components as trained, and ensure the required second person is present. Ask how the patient feels and observe alertness, strength, balance, pain, and breathing. A prior successful transfer does not make today's transfer automatically safe.", "takeaway": "Verify today's condition, the exact plan, route, equipment, and required helpers before every mobility task."},
      {"title": "Transfer and lift technique", "content": "Explain the movement, use a coordinated count, maintain stable body mechanics, and let the patient perform the safe portion. Use only a gait belt, board, mechanical lift, sling, or other device for which you have agency training and patient-specific authorization. Never drag, pull on arms, use household furniture as transfer equipment, or substitute a one-person method when the plan requires two.", "takeaway": "Use only the trained, patient-authorized device and number of helpers specified in the plan."},
      {"title": "Ambulation and change in function", "content": "Use the prescribed aid and side of assistance, pace the activity, keep lines and pathways clear, and watch for dizziness, weakness, pain, shortness of breath, fatigue, or gait change. Stop safely and report a change rather than pushing to complete the planned distance. Do not independently upgrade or downgrade a device, weight-bearing status, or assistance level based on personal judgment.", "takeaway": "Stop and report new symptoms or functional decline and never independently change the mobility plan or device."},
      {"title": "Falls, near misses, and prevention learning", "content": "If a fall occurs, call for the required help, protect the patient, and do not lift or reposition unless immediate danger or authorized clinical direction requires it. Observe responsiveness, breathing, pain, bleeding, position, and environmental facts. Near misses, repeated loss of balance, equipment defects, and hazards also require communication. Document objective circumstances, actions, notifications, and patient response without blame.", "takeaway": "After a fall, protect and observe without lifting until directed, and report both falls and near misses objectively."}
    ],
    "scenarios": [
      {"title": "The second helper is absent", "content": "The plan requires two people and a mechanical lift, but the family helper left. The patient asks the aide to complete the transfer alone to avoid missing an appointment.", "response": "Do not attempt the transfer, keep the patient safe and comfortable, contact the agency for an authorized alternative, explain the plan limit respectfully, and document the situation and notifications."},
      {"title": "A near fall with new weakness", "content": "During a planned walk, the patient's knee buckles and the aide safely guides the patient back to a chair. The patient says not to report it.", "response": "Stop further walking, assess only through observation within role, promptly notify the supervising nurse of the near fall and new weakness, follow directions, and document objective facts despite the request to omit it."}
    ],
    "citation_label": "42 CFR 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal competency rules and Pennsylvania Section 601.35 include ambulation, exercise, simple procedures, maximum self-reliance, RN assignment, and close supervision for competence. For credit, the agency RN must approve the content and attend the in-service to supervise it; device-specific and hands-on validation remain the agency's responsibility."
  },
  {
    "catalog_code": "PA-HHA-AIDE-ROM-POSITIONING-SKIN-INTEGRITY",
    "track": "HHA",
    "title": "Range of Motion, Positioning, and Skin Integrity for Home Health Aides",
    "summary": "Builds plan-directed positioning, range-of-motion, pressure prevention, device awareness, and functional-change reporting skills in the home.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HHA-484.80-D-08",
    "objectives": ["Carry out assigned positioning and range-of-motion activities safely.", "Use alignment, offloading, and support devices exactly as directed.", "Recognize intolerance, device pressure, and skin or functional changes.", "Document participation, tolerance, and reported changes."],
    "lessons": [
      {"title": "Plan-directed movement", "content": "Confirm whether movement is active, active-assisted, or passive; which joints, repetitions, supports, precautions, and frequency apply; and what symptoms require stopping. The aide implements an assigned plan and does not design an exercise program or replace therapy. Explain the activity, position safely, move smoothly within the directed range, and never force resistance or continue through new pain.", "takeaway": "Follow the exact assigned movement plan and never force a joint or independently add exercises or repetitions."},
      {"title": "Positioning and alignment", "content": "Use pillows, wedges, foot supports, bed features, and turning schedules as trained and specified, while protecting tubes and devices. Align the head, trunk, and limbs, avoid direct pressure on vulnerable sites, and check comfort, breathing, and circulation cues. Do not use improvised restraints, knots, or household objects that create entrapment or pressure risk.", "takeaway": "Use only plan-approved positioning supports and check alignment, comfort, breathing, and device pressure after movement."},
      {"title": "Skin and device observation", "content": "Observe skin exposed during authorized care, especially over bony areas and under braces, tubing, footwear, or supports. Report persistent redness or discoloration, blistering, moisture damage, swelling, warmth, drainage, pain, or an equipment mark. Follow established offloading and skin-protection directions. Do not stage, treat, massage, or adjust a clinical device outside training and authorization.", "takeaway": "Promptly report skin or device-pressure changes and use only existing prevention directions within role."},
      {"title": "Tolerance, function, and records", "content": "Watch for guarding, reduced motion, spasm, dizziness, weakness, fatigue, breathing change, fear, or inability to assist as usual. Stop or pause according to the plan and contact the nurse for unexpected change. Record activity, assistance, repetitions when required, patient participation, tolerance, refusal, and notification. Never chart a full routine when only part was completed.", "takeaway": "Record actual participation and promptly report new pain, intolerance, or loss of function."}
    ],
    "scenarios": [
      {"title": "Pain with a prescribed movement", "content": "On the second repetition of an assigned shoulder exercise, the patient reports sharp new pain and pulls away.", "response": "Stop the exercise, support the limb comfortably, do not test or force the movement, promptly notify the supervising nurse with exact observations, follow directions, and document partial completion and response."},
      {"title": "A brace leaves a mark", "content": "After removing a plan-authorized leg brace, the aide sees a deep red line that remains after routine hygiene.", "response": "Keep pressure off according to the plan, do not reapply or alter the brace until directed when policy requires clarification, promptly report the skin finding and device location, and document its objective appearance."}
    ],
    "citation_label": "42 CFR 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal competency rules and Pennsylvania Section 601.35 address exercise, simple procedures as an extension of therapy, maximum self-reliance, RN-prepared instructions, and close supervision. For credit, the agency RN must approve the content and attend the in-service to supervise it; patient-specific precautions and hands-on validation come from the agency."
  },
  {
    "catalog_code": "PA-HHA-AIDE-NUTRITION-HYDRATION-SAFE-FEEDING",
    "track": "HHA",
    "title": "Nutrition, Hydration, and Safe Feeding for Home Health Aides",
    "summary": "Applies diet verification, meal support, swallowing precautions, intake observation, food safety, and timely escalation to home-based care.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HHA-484.80-D-09",
    "objectives": ["Verify the ordered diet, texture, liquids, allergies, and feeding assistance.", "Prepare and offer food safely within the plan and household setting.", "Recognize swallowing, hydration, nutrition, and food-safety concerns.", "Record intake and report changes, refusals, and warning signs."],
    "lessons": [
      {"title": "Verify before preparing or feeding", "content": "Check patient identity, diet, texture, liquid consistency, allergies, restrictions, adaptive equipment, positioning, and assistance level in the current plan. Compare available food with those directions and contact the agency if the plan, label, or household request conflicts. Do not guess, substitute a restricted item, thicken liquid, add supplements, or change a diet based on preference alone.", "takeaway": "Verify every diet and feeding direction and obtain agency guidance before substituting or changing food or fluids."},
      {"title": "Safe meal preparation in the home", "content": "Clean hands and surfaces, separate raw and ready-to-eat foods, use safe storage and cooking methods, check dates and signs of spoilage, and prevent cross-contact as directed. Respect cultural preferences and budget while staying within the plan. The aide should not use food from an unsafe source or conceal a lack of adequate food; report supply, sanitation, or access concerns through the agency.", "takeaway": "Use safe food handling and report inadequate or unsafe food access rather than hiding or improvising around the problem."},
      {"title": "Feeding and swallowing observation", "content": "Position the patient as directed, minimize distraction, pace bites and sips, allow time, and use adaptive tools as trained. Watch for coughing, choking, wet voice, pocketing, drooling, fatigue, breathing change, color change, or inability to manage the prescribed texture. Stop feeding and activate clinical or emergency help according to severity. Never sweep the mouth blindly or force intake.", "takeaway": "Follow positioning and pacing directions and stop and escalate immediately for swallowing or breathing warning signs."},
      {"title": "Intake, hydration, and reporting", "content": "Record actual food and fluid intake using the agency method. Observe reduced appetite, repeated refusal, vomiting, diarrhea, constipation signs, dry mouth, low or dark urine, swelling, rapid weight change, or decline in ability to eat. Offer only authorized alternatives and report trends promptly. Avoid diagnosing dehydration, promising a supplement, or pressuring a patient to finish.", "takeaway": "Measure actual intake and promptly report trends or warning signs while offering only plan-authorized choices."}
    ],
    "scenarios": [
      {"title": "The wrong liquid consistency", "content": "The care plan specifies thickened liquids, but only regular juice is available and a family member says the patient drinks it all the time.", "response": "Do not provide a conflicting liquid, explain the current safety direction, contact the supervising nurse for an authorized solution, keep the patient comfortable, and document the supply issue and communications."},
      {"title": "Coughing during breakfast", "content": "A patient coughs repeatedly, develops a wet voice, and appears short of breath while eating the prescribed breakfast.", "response": "Stop feeding, maintain the directed safe position, summon clinical and emergency help according to symptoms and agency policy, do not offer more food or fluid, and report and document objective signs."}
    ],
    "citation_label": "42 CFR 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal competency rules and Pennsylvania Section 601.35 expressly include nutrition, meal preparation, personal care, reporting changes, and RN-prepared patient instructions. For credit, the agency RN must approve the content and attend the in-service to supervise it; the agency supplies current diets, swallowing plans, emergency response, and documentation rules."
  },
  {
    "catalog_code": "PA-HHA-AIDE-MEDICATION-ASSISTANCE-SCOPE",
    "track": "HHA",
    "title": "Medication Assistance and Scope Boundaries for Home Health Aides",
    "summary": "Clarifies safe assistance with ordinarily self-administered medications, observation and reporting, refusal response, storage concerns, and firm boundaries against unauthorized administration or changes.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 30,
    "topic_code": "HHA-484.80-D-10",
    "objectives": ["Distinguish authorized assistance from medication administration or clinical decision-making.", "Follow the current plan and agency policy for reminders and practical assistance.", "Recognize and report discrepancies, refusals, symptoms, and unsafe storage.", "Avoid independent dose, schedule, route, or medication changes."],
    "lessons": [
      {"title": "Know the authorized boundary", "content": "Home health aides may assist only as permitted by law, agency policy, competency, and the patient's plan, often with medications ordinarily self-administered. Assistance can differ from administration and may include a reminder or opening a container when specifically authorized. Never assume a family request expands scope, and ask the supervising nurse before performing any unclear medication-related task.", "takeaway": "Provide only medication assistance explicitly authorized by law, agency policy, competency, and the current plan."},
      {"title": "Verify the plan, not memory", "content": "Use the current medication assistance directions and agency record; do not rely on bottle arrangement, an old list, or what occurred last visit. If a label, organizer, dose, time, appearance, or instruction conflicts, pause and contact the supervising nurse. Do not sort, refill, calculate, crush, split, inject, select as-needed medication, or change a schedule unless the exact action is lawfully authorized and assigned.", "takeaway": "Pause and call the nurse for any medication discrepancy and never independently select, prepare, or change a medication."},
      {"title": "Observation, refusal, and symptoms", "content": "Respect a patient's refusal and promptly report it as the plan requires; do not coerce, hide medicine in food, or claim a clinical consequence beyond your role. Observe and report swallowing difficulty, vomiting, unusual sleepiness, rash, dizziness, breathing change, confusion, pain, or other change temporally associated with medication. Use emergency services when signs meet the agency emergency criteria.", "takeaway": "Respect refusal and promptly report it and any concerning symptoms without coercing or independently treating the patient."},
      {"title": "Storage, disposal, and records", "content": "Report unsecured medications, missing doses, damaged labels, expired products, unsafe temperature, child or pet access, suspected diversion, or a sharps hazard. Do not take medication home, dispose of it, borrow between patients, or accept custody outside policy. Record only the assistance and observation required by the agency, at the actual time, and immediately report an error or near miss.", "takeaway": "Protect medication security and promptly report discrepancies, hazards, errors, or near misses without disposing or replacing items yourself."}
    ],
    "scenarios": [
      {"title": "A changed pill appearance", "content": "A patient's morning pill looks different from the image on the current plan, and the patient asks the aide to hand it over anyway.", "response": "Pause the medication assistance, keep the item secure, contact the supervising nurse or authorized pharmacy process for clarification, do not identify or substitute the pill independently, and document the discrepancy and directions."},
      {"title": "A request to double a dose", "content": "A family member says the patient missed yesterday's medication and asks the aide to give two doses today.", "response": "Do not change or double the dose, explain the role boundary, promptly contact the supervising nurse for authorized direction, watch for concerning symptoms, and use emergency procedures if indicated."}
    ],
    "citation_label": "42 CFR 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal rules and Pennsylvania Section 601.35 include assistance with medications ordinarily self-administered, subject to state law, RN-prepared instructions, agency policy, and competence. For credit, the agency RN must approve the content and attend the in-service to supervise it; the agency defines lawful assistance and validates competency."
  },
  {
    "catalog_code": "PA-HHA-AIDE-AGENCY-POLICIES-NEW-PROCEDURES",
    "track": "HHA",
    "title": "Agency Policies, New Procedures, and Competency Remediation for Home Health Aides",
    "summary": "Provides an employer-tailored annual module for policy updates, new technology, recurring quality risks, competency gaps, and safe implementation in varied home environments.",
    "category": "Home Health Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HHA-484.80-D-11",
    "objectives": ["Locate and apply current agency policies relevant to assigned care.", "Distinguish course knowledge from required hands-on competency validation.", "Use supervision when a procedure, device, or home condition exceeds training.", "Participate honestly in remediation, incident learning, and follow-up."],
    "lessons": [
      {"title": "Finding the current standard", "content": "Use the agency's controlled policy source, current care plan, assignment, and supervisory direction rather than screenshots, old handouts, or coworker custom. Review the effective date, changed steps, documentation, escalation contact, and patient-specific limits. Ask questions before the visit when possible. If two sources conflict, protect safety and obtain clarification instead of choosing the easier version.", "takeaway": "Use the controlled current policy and plan and escalate conflicts before improvising a procedure."},
      {"title": "New procedure and technology readiness", "content": "A video or written course can introduce a device, application, or procedure, but safe use may also require demonstration, supervised practice, and return demonstration with the correct equipment. Confirm login, connectivity, supplies, cleaning, alarm, downtime, and troubleshooting boundaries. Never practice a new clinical skill on a patient before the agency confirms required training and assignment.", "takeaway": "Complete all agency-required hands-on validation before using a new clinical procedure or device with a patient."},
      {"title": "Remediation and system barriers", "content": "When a gap is identified, clarify the expected behavior, resident risk, and evidence needed to demonstrate improvement. Practice with specific feedback, but also report missing supplies, unrealistic scheduling, unclear plans, or technology failures that contribute to the gap. Education cannot correct a system barrier by itself, and system problems do not justify falsifying care or continuing an unsafe task.", "takeaway": "Address both the individual skill gap and contributing system barriers without concealing or normalizing unsafe work."},
      {"title": "Sustaining and documenting change", "content": "Use approved checklists, coaching, observation, and follow-up audits to confirm the new process works across different homes. Report unintended effects and near misses promptly. Document the training date and content, evidence that the RN approved the content and attended the in-service to supervise it, the competency method when applicable, evaluator, outcome, and retraining. A completion certificate alone does not prove employer acceptance or hands-on competence.", "takeaway": "Use honest follow-up evidence and complete agency documentation; course completion alone is not competency or credit acceptance."}
    ],
    "scenarios": [
      {"title": "An unfamiliar transfer device", "content": "A new patient has a lift model the aide has never used. A family member says it works just like the agency's old model.", "response": "Do not use the unfamiliar lift, keep the patient safe, contact the agency for device-specific direction and trained help, complete required competency validation, and document the delayed task and communications."},
      {"title": "A new app fails in the home", "content": "The agency requires a new visit application, but there is no signal and the aide cannot access the plan or emergency contact screen.", "response": "Use the approved downtime and call process, do not guess the plan or record false completion, obtain essential directions from authorized staff, protect any paper record, and report the system barrier for follow-up."}
    ],
    "citation_label": "42 CFR 484.80; CMS SOM Appendix B; 28 Pa. Code 601.35",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-484/section-484.80 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_b_hha.pdf | https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/028/chapter601/s601.35.html",
    "citation_note": "Federal rules require annual HHA in-service; Pennsylvania Section 601.35 requires careful training across self-reliance, nutrition, aging, emotional problems of illness, environment, reporting, teamwork, ethics, confidentiality, and records, with close supervision for competence. For credit, the agency RN must approve the content and attend the in-service to supervise it, and the agency must tailor and document the module."
  }
]
$hha$::jsonb;
  v_hos_catalog jsonb := $hos$
[
  {
    "catalog_code": "PA-HOS-AIDE-HOSPICE-PHILOSOPHY-IDG-PLAN",
    "track": "HOS",
    "title": "Hospice Philosophy, Interdisciplinary Care, and the Aide Plan",
    "summary": "Introduces goal-concordant hospice care, the interdisciplinary group, the aide's plan-directed role, and reliable reporting that supports comfort and continuity.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HOS-418.76-D-01",
    "objectives": ["Explain the hospice focus on comfort, quality of life, and patient and family goals.", "Describe how the aide contributes to the interdisciplinary plan of care.", "Identify tasks and decisions inside and outside the hospice-aide role.", "Report changes and plan barriers promptly to the supervising nurse."],
    "lessons": [
      {"title": "Hospice goals and individual meaning", "content": "Hospice supports comfort and quality of life for a person with a terminal illness while addressing physical, emotional, social, and spiritual needs of the patient and family. Comfort is defined by the person's goals, culture, values, and plan, not by a single routine. The aide listens and provides assigned care without promising a prognosis, declaring that treatment has stopped, or imposing personal beliefs about dying.", "takeaway": "Let the patient's goals and interdisciplinary plan define comfort, and avoid promises or explanations beyond the aide role."},
      {"title": "The interdisciplinary group", "content": "Nurses, physicians, social workers, counselors, aides, therapists, volunteers, and other disciplines coordinate through the interdisciplinary group. The aide contributes close observations about function, comfort, intake, elimination, skin, breathing, mood, family concerns, and response to care. Report through the supervising nurse and established channels; do not independently revise goals, give clinical interpretations, or bypass urgent escalation because a meeting is scheduled later.", "takeaway": "Bring objective bedside observations promptly to the supervising nurse so the interdisciplinary group can evaluate the plan."},
      {"title": "The hospice aide plan and supervision", "content": "Before care, review assigned tasks, frequency, assistance level, infection precautions, equipment, comfort measures, communication needs, and signs that require contact. Perform only duties in the current aide plan, under required RN supervision and agency policy. When family requests conflict with the plan or a patient's needs have changed, pause the affected task and obtain direction rather than improvising.", "takeaway": "Follow the current aide plan under RN supervision and obtain direction before changing or adding a clinical task."},
      {"title": "Continuity, handoff, and unmet need", "content": "Document care delivered, patient response, refusals, symptoms, family reports, supplies, and notifications. Use closed-loop communication and the alternate contact if the primary person does not respond. Identify unmet needs such as uncontrolled symptoms, caregiver distress, unsafe equipment, inadequate supplies, or inability to complete assigned care. Course concepts do not replace patient-specific orders, on-call processes, or competency validation.", "takeaway": "Communicate and document unmet needs and use alternate escalation rather than leaving a plan barrier unresolved."}
    ],
    "scenarios": [
      {"title": "A request outside the plan", "content": "A family asks the aide to change the oxygen flow because the patient appears more short of breath. The aide plan does not authorize oxygen adjustment.", "response": "Do not change the flow, position and support the patient only as currently directed, promptly contact the hospice nurse or emergency pathway according to symptoms and policy, and document the observations and request."},
      {"title": "A change before the next team meeting", "content": "A patient who usually talks through care is much sleepier, takes little fluid, and needs far more assistance. The next interdisciplinary meeting is in two days.", "response": "Keep the patient safe and comfortable, promptly report the specific changes to the supervising nurse now, follow updated directions, and document baseline comparisons and notifications rather than waiting for the meeting."}
    ],
    "citation_label": "42 CFR 418.56, 418.76, and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.56 | https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice rules require interdisciplinary planning, RN-supervised hospice-aide services, and at least 12 hours of aide in-service every 12 months. The hospice must accept this module, provide RN supervision, tailor it to policies and patient population, and retain training records."
  },
  {
    "catalog_code": "PA-HOS-AIDE-COMMUNICATION-PRIVACY-GRIEF",
    "track": "HOS",
    "title": "Communication, Privacy, and Grief Support for Hospice Aides",
    "summary": "Builds presence, listening, accessible communication, privacy, cultural humility, anticipatory-grief awareness, and appropriate referral without counseling beyond role.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HOS-418.76-D-02",
    "objectives": ["Use calm, patient-led communication during serious illness and dying.", "Protect privacy while coordinating with authorized family and the hospice team.", "Recognize grief and distress cues and connect people with appropriate team support.", "Maintain cultural humility and professional boundaries."],
    "lessons": [
      {"title": "Presence and listening", "content": "Begin with the patient's preferred name and communication method, allow silence, and listen for what matters now. Use simple questions and reflect emotion without forcing conversation or positive thinking. Do not make predictions, explain why suffering occurs, or assure a family that everything will be fine. Honest presence can include saying that you will notify the nurse or connect the person with a team member who can help.", "takeaway": "Listen without forcing reassurance or prediction, and connect questions beyond role to the appropriate hospice team member."},
      {"title": "Communication access and changing ability", "content": "Use glasses, hearing devices, writing, picture or yes-no systems, touch cues, or interpreter services identified by the plan. Reduce noise, face the patient, ask one question at a time, and allow time. As speech or alertness changes, continue addressing the patient respectfully and observe nonverbal comfort cues. Report new communication loss or distress rather than assuming the person cannot understand.", "takeaway": "Use plan-directed communication supports and continue respectful direct communication even when response is limited."},
      {"title": "Privacy, family roles, and conflict", "content": "Share patient information only with authorized people and through hospice-approved methods. A visitor's concern does not automatically grant access to clinical details. When family members disagree, remain neutral, protect immediate safety, follow the plan and known patient preference, and notify the nurse or social worker. Do not mediate legal disputes, disclose confidential information, or use personal messaging and social media.", "takeaway": "Protect confidentiality, remain neutral in family conflict, and refer unresolved questions through the hospice team."},
      {"title": "Grief, culture, spirituality, and boundaries", "content": "Grief responses vary and can include sadness, anger, guilt, numbness, relief, fear, or changing needs over time. Ask about cultural, spiritual, ritual, modesty, and family preferences without stereotyping. Offer assigned support and notify the nurse, social worker, counselor, or chaplain when distress, complicated concerns, or resource needs arise. Maintain boundaries around gifts, secrets, personal contact, and your own beliefs.", "takeaway": "Honor individual grief and cultural preferences and refer needs beyond supportive presence to the appropriate team member."}
    ],
    "scenarios": [
      {"title": "A prognosis question", "content": "A spouse asks the aide exactly how many days the patient has left and says the nurse has not returned a call yet.", "response": "Acknowledge the uncertainty and distress, do not estimate prognosis, promptly contact the nurse using the alternate on-call path if needed, remain supportively present within the visit, and document the question and communication."},
      {"title": "Conflicting family instructions", "content": "Two relatives argue at the bedside about who may receive updates and ask the aide to choose a side.", "response": "Protect the patient's privacy and known preferences, share no unauthorized details, remain neutral, reduce disruption when possible, and promptly refer the conflict to the nurse or designated hospice team member."}
    ],
    "citation_label": "42 CFR 418.52, 418.56, 418.76, and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.52 | https://www.ecfr.gov/current/title-42/part-418/section-418.56 | https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice rules protect patient rights and require interdisciplinary, RN-supervised aide services and annual in-service. The hospice must tailor privacy contacts, interpreter access, grief referrals, cultural supports, and boundaries."
  },
  {
    "catalog_code": "PA-HOS-AIDE-OBSERVATION-REPORTING-DOCUMENTATION",
    "track": "HOS",
    "title": "Observation, Reporting, and Documentation for Hospice Aides",
    "summary": "Develops baseline-aware observation, symptom communication, closed-loop escalation, and accurate hospice-aide records without diagnosis or independent plan changes.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HOS-418.76-D-03",
    "objectives": ["Describe changes in comfort and function using objective details.", "Use routine, urgent, emergency, and alternate hospice reporting pathways.", "Document delivered care, response, refusals, and communications accurately.", "Avoid diagnostic language, pre-charting, and independent clinical changes."],
    "lessons": [
      {"title": "Observe the whole comfort picture", "content": "Compare alertness, breathing, facial expression, movement, vocalization, skin, intake, output, sleep, mobility, anxiety, and ability to accept care with the patient's recent pattern. Ask the patient about comfort using the plan's communication method. Report the exact change, onset, triggers, relieving factors observed, and effect on function. The aide does not diagnose pain type, delirium, infection, or imminent death.", "takeaway": "Compare specific comfort and function observations with baseline and report facts without diagnosing."},
      {"title": "Escalation that matches urgency", "content": "Use the hospice plan and call tree for routine changes, urgent uncontrolled symptoms, medication or equipment concerns, unexpected injury, and emergencies. If severe or rapidly worsening signs meet agency emergency criteria, activate the designated emergency response while contacting hospice. If a call is unanswered, use the alternate on-call route. Never assume a serious change is expected simply because the patient is receiving hospice.", "takeaway": "Use the current urgent and alternate pathways and never dismiss a serious change as automatically expected in hospice."},
      {"title": "Closed-loop team communication", "content": "State patient identity and location, exact symptoms and observations, time course, care already provided, safety, and family concerns. Repeat back directions when required and clarify whether the aide should remain, pause a task, or expect another team member. Do not carry out a verbal instruction outside role or competency; explain the limit and ask for an authorized response.", "takeaway": "Give a complete factual report, confirm directions, and decline any instruction outside the authorized aide role."},
      {"title": "Records and corrections", "content": "Document actual tasks, assistance, comfort response, skin and elimination observations, intake when required, refusals, calls attempted and completed, directions, and actions. Use direct quotes and objective language. Never pre-chart, copy without verification, share credentials, erase, backdate, or hide an error. Use the hospice's correction and downtime procedures that preserve the audit trail.", "takeaway": "Create timely objective records and correct errors only through the hospice's audit-preserving process."}
    ],
    "scenarios": [
      {"title": "Pain is no longer controlled", "content": "A patient who was resting comfortably now grimaces, guards the abdomen, and repeatedly rates pain as severe after the aide's assigned comfort measures.", "response": "Promptly contact the hospice nurse or on-call pathway with exact observations and measures tried, keep the patient safely supported, do not alter medication or treatment, follow directions, and document response and notifications."},
      {"title": "A charting shortcut", "content": "The electronic record has copied yesterday's intact-skin statement into today's visit, but the aide sees a new reddened area.", "response": "Do not accept the copied statement, document today's objective finding, promptly notify the nurse, correct any mistaken entry through the approved process, and record actions without staging or diagnosing the area."}
    ],
    "citation_label": "42 CFR 418.56, 418.76, and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.56 | https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice conditions require plan-coordinated, RN-supervised aide services, reporting of changes, and annual training. The hospice must supply its current symptom thresholds, call tree, record system, correction process, and patient-specific directions."
  },
  {
    "catalog_code": "PA-HOS-AIDE-INFECTION-PREVENTION",
    "track": "HOS",
    "title": "Infection Prevention for Hospice Aides",
    "summary": "Applies standard precautions, hand hygiene, PPE, clean-bag technique, equipment handling, exposure response, and compassionate precaution practices across hospice settings.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HOS-418.76-D-04",
    "objectives": ["Use hand hygiene and PPE correctly for assigned hospice care.", "Prevent cross-contamination of supplies, equipment, linen, and the care environment.", "Report symptoms and occupational exposure through hospice pathways.", "Balance infection precautions with dignity, communication, and comfort goals."],
    "lessons": [
      {"title": "Standard precautions and hand hygiene", "content": "Plan for exposure to blood, body fluids, nonintact skin, and mucous membranes in every setting. Clean hands at hospice-required moments and use soap and water when policy or the organism requires it. Gloves do not replace hand hygiene. Keep nails, jewelry, skin condition, and uniforms consistent with policy, and do not reduce precautions because a patient is near end of life or a family requests fewer barriers.", "takeaway": "Apply required hand hygiene and standard precautions for every patient; comfort goals do not remove exposure protections."},
      {"title": "PPE with compassionate communication", "content": "Choose and remove PPE according to task, expected exposure, and current transmission-based directions. Explain equipment calmly so the patient and family understand it supports safe care rather than rejection. Preserve eye contact, hearing access, and comforting communication where possible. If PPE, fit-testing, or precaution directions are unavailable or unclear, contact hospice before nonurgent exposure-prone care.", "takeaway": "Use task-appropriate PPE while explaining it respectfully and seek clarification when safe supplies or directions are missing."},
      {"title": "Clean workflow, linen, and equipment", "content": "Create a clean supply zone, separate used items, handle linen without shaking, contain waste as directed, and disinfect shared equipment with the approved product and contact time. Protect the hospice bag from pets, food, sinks, floors, and contaminated surfaces. Do not mix chemicals, reuse single-use items, return used supplies to clean storage, or handle unexpected sharps unsafely.", "takeaway": "Keep clean and contaminated items separate and disinfect reusable equipment with the hospice-approved process."},
      {"title": "Symptoms, exposure, and family teaching boundaries", "content": "Observe and report fever, cough, drainage, vomiting, diarrhea, new confusion, skin change, or other deviation from baseline. For a splash, needlestick, bite, or exposure, perform immediate first aid and activate the employee-exposure process. Reinforce only hospice-approved teaching; refer questions about contagiousness, testing, treatment, visitation, or prognosis to the nurse rather than making unsupported claims.", "takeaway": "Report symptoms and exposures promptly and refer clinical infection questions to the hospice nurse."}
    ],
    "scenarios": [
      {"title": "Family asks to skip PPE", "content": "A family says gowns frighten the patient and asks the aide to ignore posted contact precautions during incontinence care.", "response": "Explain the precaution calmly, use the required PPE and communication supports, preserve comfort and dignity, and contact the nurse if the family continues to object or the plan needs adaptation."},
      {"title": "A splash exposure", "content": "Body fluid splashes into an aide's eye during oral care, and the family urges the aide to finish the visit before calling anyone.", "response": "Stop and perform immediate exposure first aid, promptly contact the hospice employee-exposure pathway, arrange patient care handoff as directed, and document the event without delaying evaluation."}
    ],
    "citation_label": "42 CFR 418.60, 418.76, and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.60 | https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice rules require infection control, RN-supervised aide services, and annual training. The hospice must tailor current precautions, PPE, products, clean-bag procedure, exposure contacts, and setting-specific requirements."
  },
  {
    "catalog_code": "PA-HOS-AIDE-COMFORT-HYGIENE-ORAL-CONTINENCE",
    "track": "HOS",
    "title": "Comfort-Focused Hygiene, Oral Care, and Continence Support for Hospice Aides",
    "summary": "Builds gentle, goal-concordant personal care that balances cleanliness, comfort, energy, privacy, skin protection, oral moisture, continence, and patient choice.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 90,
    "topic_code": "HOS-418.76-D-05",
    "objectives": ["Adapt assigned personal care to comfort, tolerance, and patient preference.", "Provide oral and continence care using plan-directed precautions.", "Recognize pain, fatigue, breathing, skin, mouth, and elimination changes.", "Pause, report, and document when the planned routine no longer fits."],
    "lessons": [
      {"title": "Comfort goals before routine completion", "content": "Review the aide plan, ask what matters to the patient now, and prioritize comfort, privacy, safety, and energy. A full shower may become a partial bed bath, rest period, or rescheduled task only with plan-consistent choice and nursing direction when needed. Explain each step, seek permission, provide warmth, and let the patient perform safe portions. Never force care to complete a checklist.", "takeaway": "Let comfort, tolerance, choice, and the current plan guide the amount and timing of personal care."},
      {"title": "Gentle bathing and grooming", "content": "Gather supplies, protect lines and devices, position safely, use approved water temperature and products, and work from clean to more contaminated areas. Use slow movements and pause for pain, breathlessness, anxiety, fatigue, or cold. Support familiar grooming, clothing, and cultural preferences that help identity and dignity. Avoid vigorous rubbing, strong scents, unapproved products, and unnecessary exposure.", "takeaway": "Provide slow, warm, preference-sensitive care and pause for pain, breathlessness, anxiety, fatigue, or cold."},
      {"title": "Oral comfort and changing swallowing", "content": "Follow the plan for positioning, mouth care frequency, dentures, moisture products, suction boundaries, and aspiration precautions. Observe dryness, crusting, sores, bleeding, coating, odor, pain, loose teeth, and changes in swallowing or ability to manage secretions. Use only approved products and techniques. Do not pour fluids into an unresponsive mouth, force dentures, or independently suction or medicate.", "takeaway": "Use plan-approved oral comfort methods and report mouth, secretion, or swallowing changes without forcing fluids or devices."},
      {"title": "Continence, elimination, and dignity", "content": "Respond promptly, use the assigned toileting or incontinence approach, protect skin, and handle catheters, ostomies, drainage, and briefs only within training and plan. Observe urine and stool amount, color or consistency changes, discomfort, leakage, reduced output, diarrhea, constipation signs, and device problems. Never shame, make jokes, or withhold care because elimination needs increase.", "takeaway": "Provide prompt respectful continence care and report elimination or device changes using objective details."}
    ],
    "scenarios": [
      {"title": "The shower is too much today", "content": "A patient scheduled for a shower becomes breathless and exhausted while sitting at the bedside and says not today.", "response": "Stop the shower plan, support breathing and comfort as currently directed, offer a limited plan-consistent hygiene option only if desired, promptly report the change to the nurse, and document the refusal, symptoms, and care provided."},
      {"title": "Dry mouth with reduced alertness", "content": "A less-responsive patient has a very dry mouth. A visitor asks the aide to pour water into the patient's mouth.", "response": "Do not pour fluid or force swallowing, position and provide only the plan-authorized oral moisture care, promptly notify the nurse of reduced alertness and oral findings, and teach the visitor only from approved directions."}
    ],
    "citation_label": "42 CFR 418.76 and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice-aide rules cover personal-care duties under RN supervision and require annual in-service. The hospice must tailor bathing, oral care, continence, device, comfort, and escalation procedures to patient plans and validate hands-on competency."
  },
  {
    "catalog_code": "PA-HOS-AIDE-SKIN-POSITIONING-PRESSURE-COMFORT",
    "track": "HOS",
    "title": "Skin Integrity, Positioning, and Pressure Comfort for Hospice Aides",
    "summary": "Integrates comfort-focused positioning, pressure reduction, skin and device observation, gentle movement, and timely communication when goals or tolerance change.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HOS-418.76-D-06",
    "objectives": ["Use plan-directed positioning and pressure-relief measures safely.", "Observe skin and device contact areas during assigned care.", "Balance scheduled movement with comfort, tolerance, and current nursing direction.", "Report and document new skin findings, pain, and device concerns."],
    "lessons": [
      {"title": "Comfort-focused positioning plan", "content": "Review desired positions, frequency, assistance, devices, pressure sites, breathing needs, contractures, pain, and signs for stopping. Explain the movement and coordinate helpers and equipment. Hospice goals may require individualized tradeoffs between pressure reduction, sleep, breathing, pain, and patient preference; the nurse and interdisciplinary team set those directions. The aide does not independently abandon or intensify a turning schedule.", "takeaway": "Follow the individualized positioning plan and report when comfort or tolerance suggests it needs clinical review."},
      {"title": "Alignment, movement, and supports", "content": "Use trained body mechanics, draw sheets, lifts, pillows, wedges, heel supports, and bed features exactly as directed. Protect fragile skin, tubes, drains, and bony areas from friction, shear, and pressure. After movement, check alignment, comfort, breathing, circulation cues, and device placement. Do not use improvised rings, knots, restraints, or household objects that create pressure or entrapment.", "takeaway": "Use approved supports and equipment, minimize friction and shear, and recheck comfort and device placement after movement."},
      {"title": "Skin and wound boundaries", "content": "Observe skin exposed during authorized care for discoloration, warmth, moisture, rash, tears, bruising, blistering, swelling, drainage, odor, bleeding, or pain. Report new or worsening findings promptly with location and appearance. Follow assigned skin cleansing, moisture protection, offloading, and dressing-adjacent tasks only. Do not stage wounds, remove dressings, pack, debride, or apply a treatment outside authorization.", "takeaway": "Report objective skin changes promptly and do not stage or treat wounds beyond the assigned aide plan."},
      {"title": "Pain, refusal, and documentation", "content": "If movement causes grimacing, guarding, breathlessness, fear, or refusal, stop or pause, support comfort, and contact the nurse according to the plan. Never force turning or characterize refusal as noncompliance without context. Document position, assistance, skin observations, patient words, comfort response, task completed or omitted, and notifications so the team can adjust the plan.", "takeaway": "Pause for pain or refusal, report the response, and document actual positioning and comfort outcomes objectively."}
    ],
    "scenarios": [
      {"title": "Turning worsens breathing", "content": "A planned side-lying position makes the patient visibly more short of breath and anxious within a minute.", "response": "Return the patient to the safest previously tolerated position using trained assistance, provide assigned comfort support, promptly notify the hospice nurse, and document the position, symptoms, response, and direction."},
      {"title": "Drainage through a dressing", "content": "During bathing, an aide notices new drainage leaking through a covered wound dressing and a strong odor.", "response": "Do not remove or change the dressing unless specifically assigned, protect clothing and skin using authorized measures, promptly report the location and objective findings to the nurse, and document the observation."}
    ],
    "citation_label": "42 CFR 418.76 and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice-aide rules require plan-directed personal care under RN supervision and annual in-service. Hospice policy and patient goals must tailor positioning, pressure reduction, skin tasks, device care, escalation, and competency validation."
  },
  {
    "catalog_code": "PA-HOS-AIDE-TRANSFERS-AMBULATION-FALLS",
    "track": "HOS",
    "title": "Transfers, Ambulation, and Fall Response for Hospice Aides",
    "summary": "Develops safe mobility assistance that respects changing strength, comfort goals, equipment needs, caregiver capacity, and patient choice near end of life.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HOS-418.76-D-07",
    "objectives": ["Verify the current mobility plan, symptoms, equipment, and helpers.", "Use only trained transfer and ambulation techniques and devices.", "Recognize decline that makes the planned method unsafe.", "Respond to falls and near misses through hospice and emergency pathways."],
    "lessons": [
      {"title": "Changing mobility and comfort goals", "content": "Review assistance level, weight-bearing, devices, precautions, oxygen and line management, and what to do when strength changes. Ask about pain, dizziness, breathlessness, fatigue, and the patient's goal for the activity. A transfer that was safe yesterday may not be safe today. The aide should not pressure ambulation for a generic benefit when the current plan or patient's tolerance calls for rest.", "takeaway": "Recheck today's symptoms and goal against the current mobility plan before every transfer or walk."},
      {"title": "Safe transfers and equipment", "content": "Prepare the route and surfaces, use the specified footwear, gait belt, lift, sling, and number of helpers, and communicate a coordinated sequence. Use only equipment for which the hospice has trained and authorized you. Stop for damaged equipment, missing help, patient fear, new weakness, or plan conflict. Never drag, pull arms, or use a family member as an untrained required helper.", "takeaway": "Use the exact trained equipment and helper level and stop when supplies, assistance, or current ability do not match the plan."},
      {"title": "Ambulation, energy conservation, and refusal", "content": "Pace activity, use rest breaks, protect lines, keep pathways clear, and observe breathing, color, pain, balance, and fatigue. Honor refusal and offer a safe plan-consistent alternative such as repositioning only if authorized. Report reduced distance, greater assistance, near falls, or repeated refusal so the nurse can reassess. Do not independently change the device or mobility goal.", "takeaway": "Conserve energy, honor refusal, and report functional change rather than independently changing the mobility goal or device."},
      {"title": "Fall response and communication", "content": "After a fall, call for help, protect the patient from further harm, and do not lift or reposition unless immediate danger or authorized clinical direction requires it. Observe responsiveness, breathing, pain, bleeding, position, and environmental facts. Activate hospice and emergency pathways based on the plan and circumstances. Document objective details, actions, notifications, and patient and family response.", "takeaway": "Protect and observe after a fall, summon designated help, and do not lift until authorized unless immediate danger requires movement."}
    ],
    "scenarios": [
      {"title": "Strength has declined overnight", "content": "A patient who previously pivoted with one aide cannot bear weight and becomes breathless while sitting at the bed edge.", "response": "Stop the transfer, support the patient in the safest tolerated position, promptly contact the hospice nurse for reassessment and authorized equipment or help, and document the change and response."},
      {"title": "A fall beside the commode", "content": "The aide finds the patient on the floor beside a commode, awake but with new hip pain. A caregiver wants to lift immediately.", "response": "Prevent an unassessed lift, activate hospice and emergency procedures as directed, protect and observe the patient without unnecessary movement, report objective findings, and remain for authorized handoff if safe."}
    ],
    "citation_label": "42 CFR 418.76 and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice-aide rules require RN-supervised, plan-directed care and annual training. The hospice must tailor mobility goals, equipment, helpers, fall response, emergency choices, and hands-on competency validation to each patient and setting."
  },
  {
    "catalog_code": "PA-HOS-AIDE-NUTRITION-HYDRATION-SWALLOWING",
    "track": "HOS",
    "title": "Nutrition, Hydration, and Swallowing Support for Hospice Aides",
    "summary": "Applies comfort goals, patient choice, diet and swallowing directions, safe assistance, oral comfort, intake observation, and noncoercive family support.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HOS-418.76-D-08",
    "objectives": ["Follow the current comfort, diet, texture, liquid, positioning, and assistance plan.", "Recognize swallowing and breathing warning signs during intake.", "Support patient choice without forcing food or fluid.", "Report and document intake changes, refusals, symptoms, and family concerns."],
    "lessons": [
      {"title": "Goals, appetite, and choice", "content": "Appetite and fluid interest can change with illness and dying. Follow the interdisciplinary plan and ask what the patient wants now, offering small preferred choices when authorized. Do not pressure, bargain, shame, or claim that refusal is causing the illness. Explain only approved guidance and refer family questions about prognosis, artificial nutrition, or hydration decisions to the nurse and interdisciplinary team.", "takeaway": "Follow the comfort plan and patient choice without forcing intake or interpreting what reduced appetite means clinically."},
      {"title": "Verify diet and assistance", "content": "Check diet, texture, liquid consistency, allergies, position, adaptive equipment, and feeding assistance before offering anything. Ensure the patient is sufficiently alert according to the plan and keep prescribed precautions. Do not thicken, thin, crush, supplement, or substitute independently. If the desired food conflicts with the current plan, pause and contact the nurse for goal-concordant direction.", "takeaway": "Verify current diet and swallowing directions and obtain nursing guidance before any change or conflicting choice."},
      {"title": "Safe feeding and swallowing signs", "content": "Position and pace as directed, offer small amounts, allow complete swallowing, and watch for coughing, choking, wet voice, pocketing, drooling, fatigue, breathing or color change, distress, and reduced alertness. Stop feeding and activate the clinical or emergency response required by severity. Never perform a blind finger sweep, pour fluid into a poorly responsive mouth, or continue because a family insists.", "takeaway": "Stop intake and escalate for swallowing or breathing warning signs; never force food or fluid into a poorly responsive person."},
      {"title": "Oral comfort, intake records, and family support", "content": "Provide plan-authorized mouth moisture and hygiene even when intake is low. Record actual food and fluid offered and accepted when required, along with symptoms, refusal, and response. Acknowledge caregiver worry and notify the nurse about declining intake, vomiting, diarrhea, constipation signs, dry mouth, low output, or inability to swallow. Do not promise that a specific amount will improve or prolong life.", "takeaway": "Provide authorized oral comfort, record actual intake, and connect family concerns and changes to the nurse."}
    ],
    "scenarios": [
      {"title": "Family pressure to keep feeding", "content": "A sleepy patient turns away and coughs after a small spoonful, but a relative says the patient must finish the bowl to stay strong.", "response": "Stop feeding, position safely as directed, promptly notify the hospice nurse of reduced alertness and coughing, provide only authorized oral comfort, and support the family without forcing intake or predicting outcomes."},
      {"title": "A requested favorite food conflicts", "content": "An alert patient asks for a favorite food that does not match the documented texture, and the family asks the aide to serve it secretly.", "response": "Do not secretly provide a conflicting texture, acknowledge the preference, contact the hospice nurse for a goal-concordant plan decision, offer an authorized alternative if desired, and document the request and direction."}
    ],
    "citation_label": "42 CFR 418.56, 418.76, and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.56 | https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice plan and aide rules require goal-concordant, RN-supervised personal care and annual training. The hospice must tailor diet, swallowing, emergency, mouth-care, documentation, and family-teaching directions to the current plan."
  },
  {
    "catalog_code": "PA-HOS-AIDE-ACTIVE-DYING-SYMPTOM-ESCALATION",
    "track": "HOS",
    "title": "Active Dying, Comfort Observation, and Symptom Escalation for Hospice Aides",
    "summary": "Prepares aides to recognize and report common end-of-life changes, provide assigned comfort measures, support families, and distinguish expected-plan guidance from urgent or unexpected concerns.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 90,
    "topic_code": "HOS-418.76-D-09",
    "objectives": ["Recognize possible changes near end of life without independently declaring active dying or death.", "Provide assigned nonpharmacologic comfort care and observe response.", "Escalate uncontrolled, unexpected, or severe symptoms promptly.", "Support family understanding using only hospice-approved teaching and referrals."],
    "lessons": [
      {"title": "Possible changes near end of life", "content": "Changes can include more sleep, less intake, weakness, altered breathing patterns, cool or mottled skin, reduced urine, difficulty swallowing, restlessness, or less verbal response. Patterns vary, and similar changes can have treatable or urgent causes. Observe specific facts and promptly report changes to the nurse. The aide does not determine prognosis, certify that dying has begun, or pronounce death.", "takeaway": "Report specific end-of-life changes and let qualified hospice clinicians interpret prognosis, active dying, or death."},
      {"title": "Assigned comfort measures", "content": "Use the current plan for position, fan or room environment, mouth care, skin care, continence care, quiet presence, music, touch, linens, and reduced stimulation. Explain care, preserve dignity, and pace activity according to tolerance. Observe whether the measure improves or worsens comfort. Do not independently administer or adjust medication, oxygen, suction, heat, cold, food, or fluids.", "takeaway": "Provide only plan-assigned comfort measures, observe response, and never independently adjust medication, oxygen, or treatment."},
      {"title": "Uncontrolled and unexpected symptoms", "content": "Promptly contact the hospice nurse for new or worsening pain behaviors, severe breathlessness, repeated vomiting, seizure, heavy bleeding, injury, marked agitation, medication or pump concern, inability to manage secretions, or another plan-defined symptom. Use emergency services when the hospice plan or immediate circumstances require it. Do not dismiss distress as inevitable or wait for the next scheduled visit.", "takeaway": "Escalate severe, worsening, or unexpected symptoms immediately through the hospice and emergency plan."},
      {"title": "Family guidance, vigil, and after a change", "content": "Explain only the signs and comfort steps the hospice has authorized for the aide to reinforce. Invite the family to call hospice with questions and offer team contacts for clinical, spiritual, social, or grief support. If the patient becomes unresponsive or appears to have stopped breathing, follow the hospice's exact death-event procedure; do not pronounce, remove equipment, call a funeral home, or change the body unless directed.", "takeaway": "Use hospice-approved family guidance and follow the exact death-event procedure without pronouncing or making after-death arrangements."}
    ],
    "scenarios": [
      {"title": "Sudden severe bleeding", "content": "A patient develops sudden heavy bleeding. A family member says hospice means no emergency calls and asks the aide to wait quietly.", "response": "Activate the hospice's urgent and emergency plan immediately, use only trained protective and comfort measures, stay with the patient when safe, contact the hospice nurse and emergency services as directed, and document the event and actions."},
      {"title": "The patient appears not to be breathing", "content": "During a visit, the aide finds the patient unresponsive and cannot see breathing. The family asks whether the patient has died.", "response": "Follow the hospice's patient-specific death-event and emergency procedure immediately, contact the designated hospice clinician, provide no independent pronouncement, do not move the body or equipment unless directed, and support the family within role."}
    ],
    "citation_label": "42 CFR 418.56, 418.76, and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.56 | https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice rules require coordinated plans, RN-supervised aide care, and annual in-service. The hospice must supply patient-specific comfort, symptom, emergency, death-event, medication, and family-teaching procedures; this course does not establish them."
  },
  {
    "catalog_code": "PA-HOS-AIDE-FAMILY-SUPPORT-BOUNDARIES",
    "track": "HOS",
    "title": "Family Support, Caregiver Teaching Boundaries, and Professional Conduct for Hospice Aides",
    "summary": "Builds supportive caregiver interaction, observation of caregiver strain, approved reinforcement of teaching, conflict referral, privacy, safety, and professional boundaries.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 60,
    "topic_code": "HOS-418.76-D-10",
    "objectives": ["Offer respectful practical support without replacing professional counseling or nursing teaching.", "Recognize and report caregiver strain, unsafe care, conflict, or unmet need.", "Reinforce only hospice-approved instructions and demonstrate assigned nonclinical tasks.", "Maintain privacy, boundaries, and personal safety in patient homes."],
    "lessons": [
      {"title": "Supportive presence and practical help", "content": "Ask what would help within the visit plan, listen without judgment, and acknowledge effort and emotion. Offer assigned personal care, simple organization, or respite-like presence only as authorized. Do not promise availability outside work, provide psychotherapy, settle family decisions, or tell caregivers how they should grieve. Connect needs for counseling, spiritual care, social resources, or clinical explanation to the team.", "takeaway": "Offer plan-authorized practical support and connect counseling, spiritual, social, and clinical needs to the appropriate team member."},
      {"title": "Reinforcing teaching within role", "content": "Reinforce only instructions already approved and documented by the nurse or interdisciplinary team, using teach-back or demonstration when assigned. Do not create new teaching about medications, oxygen, wounds, prognosis, emergency choices, or equipment settings. If a caregiver cannot demonstrate a safe assigned task, stop, protect the patient, and notify the nurse rather than signing off competency yourself.", "takeaway": "Reinforce documented team teaching only and refer unsuccessful or new clinical teaching needs to the nurse."},
      {"title": "Caregiver strain, conflict, and safety", "content": "Observe exhaustion, confusion, anger, fear, missed care, substance use, unsafe lifting, lack of supplies, or statements of being unable to continue. Report concerns promptly and follow abuse, neglect, self-harm, violence, and emergency procedures when indicated. Stay neutral in disputes and do not conceal risk to preserve family harmony. Worker safety and patient safety both matter.", "takeaway": "Report caregiver strain and unsafe care promptly and activate protection or emergency pathways when indicated."},
      {"title": "Boundaries, privacy, gifts, and dual roles", "content": "Follow hospice rules for gifts, money, purchases, errands, keys, transportation, food, personal phone numbers, social media, photographs, and contact after death. Do not borrow, lend, witness documents, accept beneficiary status, or keep secrets that affect care. Protect patient information from neighbors and unauthorized relatives. Seek supervision whenever a relationship or request could impair judgment.", "takeaway": "Maintain hospice boundaries and confidentiality and seek supervision before any request that creates a dual role or conflict."}
    ],
    "scenarios": [
      {"title": "An exhausted caregiver", "content": "A spouse says there has been no sleep for two nights, begins crying, and admits nearly dropping the patient during a transfer.", "response": "Keep the patient safe, do not attempt an unsafe transfer, promptly notify the hospice nurse and team about the caregiver strain and near miss, offer only authorized support, and use emergency or respite pathways as directed."},
      {"title": "A request for private paid help", "content": "A family offers cash for the hospice aide to return off duty and provide care privately because agency hours feel insufficient.", "response": "Decline the private arrangement and payment, explain the professional boundary, promptly refer the unmet-care request to the hospice supervisor or social worker, and document or report the offer according to policy."}
    ],
    "citation_label": "42 CFR 418.52, 418.56, 418.76, and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.52 | https://www.ecfr.gov/current/title-42/part-418/section-418.56 | https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice conditions include patient and family-centered interdisciplinary care and RN-supervised aide services. The hospice must tailor caregiver teaching, boundaries, privacy, worker safety, abuse reporting, and resource referral procedures."
  },
  {
    "catalog_code": "PA-HOS-AIDE-EMERGENCY-VS-EXPECTED-DECLINE",
    "track": "HOS",
    "title": "Emergency Events Versus Expected Decline for Hospice Aides",
    "summary": "Provides a concise decision framework for following patient-specific hospice instructions when a change may reflect expected decline, urgent symptom need, injury, or emergency.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 30,
    "topic_code": "HOS-418.76-D-11",
    "objectives": ["Use the patient-specific plan rather than assumptions about hospice status.", "Recognize changes that require immediate hospice or emergency activation.", "Provide only trained immediate safety and comfort actions.", "Communicate and document decisions, attempts, and handoff."],
    "lessons": [
      {"title": "Hospice does not mean ignore emergencies", "content": "Goals and emergency choices differ by patient and can change. Review the current plan, code-status or emergency instructions as made available for the aide role, and hospice call tree. Never assume that injury, severe distress, choking, fire, violence, or another immediate threat is expected or that no one should be called. The aide follows the authorized plan and immediate safety requirements.", "takeaway": "Use the current patient-specific emergency plan and never assume hospice status means a serious event should be ignored."},
      {"title": "Observe, protect, and activate", "content": "Identify what happened, immediate danger, responsiveness, breathing, bleeding, pain behavior, and environmental risk without delaying the call. Protect the patient, perform only trained first-aid or comfort measures, and contact hospice and emergency services in the sequence required by the plan and circumstances. Do not independently diagnose, pronounce, change treatment, or transport in a personal vehicle.", "takeaway": "Protect the patient and activate the designated hospice and emergency response without diagnosing or changing treatment."},
      {"title": "Expected changes still require communication", "content": "Even when a change is described in prior teaching, report it at the time and frequency directed by the hospice plan. New breathlessness, agitation, bleeding, seizure, fall, uncontrolled symptoms, caregiver inability, or equipment failure may require urgent action. Use the alternate on-call number if the first contact fails, and never wait for the next scheduled visit when the plan calls for immediate notification.", "takeaway": "Follow plan-directed reporting for expected changes and escalate severe or uncontrolled concerns without waiting."},
      {"title": "Handoff and record", "content": "Communicate exact observations, onset, actions, patient wishes known, family requests, and current safety. Confirm directions and who assumes responsibility. Document calls attempted and completed, emergency activation, care provided, and response. Do not alter the record to make the choice look simpler, and participate in debriefing after an event so plan or supply gaps can be corrected.", "takeaway": "Complete a factual closed-loop handoff and record every action and contact attempt for later review."}
    ],
    "scenarios": [
      {"title": "A fall during an expected decline", "content": "A weak patient falls and hits the head. A relative says falls are expected now and asks the aide not to call.", "response": "Protect the patient without an unassessed lift, immediately activate the hospice and emergency procedure for injury, report objective findings, follow authorized directions, and document the relative's request and all actions."},
      {"title": "Breathing pattern changes", "content": "A patient's breathing pattern changes as previously discussed, but the family is frightened and the patient also shows new severe distress.", "response": "Provide assigned comfort measures, promptly contact the hospice nurse or on-call path with both the pattern and new distress, use emergency services if the plan or severity directs, and avoid declaring the change expected on your own."}
    ],
    "citation_label": "42 CFR 418.56, 418.76, and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.56 | https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal hospice rules require individualized plans, coordination, RN supervision, and annual aide training. The hospice must insert each patient's current emergency choices, urgent symptom thresholds, on-call contacts, death-event procedures, and local emergency instructions."
  },
  {
    "catalog_code": "PA-HOS-AIDE-AGENCY-SPECIFIC-NEW-SKILL",
    "track": "HOS",
    "title": "Hospice Policy Updates and New-Skill Competency",
    "summary": "Provides an employer-tailored annual module for policy changes, new devices and procedures, performance remediation, quality priorities, and competency evidence.",
    "category": "Hospice Aide Annual",
    "duration_minutes": 30,
    "topic_code": "HOS-418.76-D-12",
    "objectives": ["Locate current hospice policy and patient-specific direction.", "Identify when a new skill requires demonstration and return demonstration.", "Pause and escalate when equipment, training, or directions are inadequate.", "Document RN supervision, competency, and follow-up evidence honestly."],
    "lessons": [
      {"title": "Current policy and plan control", "content": "Use the hospice's controlled policy source, current aide plan, assignment, and RN direction instead of old handouts, memory, or family custom. Review effective date, changed steps, supplies, documentation, and escalation. When sources conflict, protect the patient and obtain RN clarification. Do not select the convenient version or continue a task whose authorization is uncertain.", "takeaway": "Use the controlled current policy and aide plan and obtain RN clarification before acting on conflicting directions."},
      {"title": "Knowledge versus hands-on competency", "content": "Online learning can explain a procedure, but equipment and direct-care skills may require demonstration, supervised practice, and return demonstration before assignment. Confirm device model, setup, cleaning, alarms, troubleshooting limits, and patient-specific precautions. Never try a new clinical skill on a patient merely because a course was completed or a family member offers to demonstrate.", "takeaway": "Complete hospice-required hands-on validation before using a new device or direct-care skill with a patient."},
      {"title": "Stop-work and escalation", "content": "Pause when supplies are missing, equipment is damaged, the patient condition changed, the required helper is absent, or the task exceeds training. Keep the patient safe, notify the RN or alternate supervisor, and obtain an authorized plan. Reporting a limitation is a safety action, not refusal to work. Never improvise with household equipment or conceal an omitted task.", "takeaway": "Pause and escalate unsafe or unsupported work and never improvise equipment or hide an omitted task."},
      {"title": "Remediation and durable evidence", "content": "For an identified gap, clarify the expected behavior, practice with feedback, complete the required competency method, and participate in follow-up observation. Report system barriers and unintended effects. Training records should identify content, date, duration, RN supervision, evaluator and outcome when applicable, and remediation accurately. A vendor certificate alone does not establish hospice acceptance, annual credit, or competence.", "takeaway": "Use RN-supervised practice and honest follow-up records; a vendor completion certificate alone is not competency or accepted credit."}
    ],
    "scenarios": [
      {"title": "A new bed feature", "content": "A patient receives a specialty bed with controls the aide has not used. The delivery driver gives a quick explanation and leaves.", "response": "Do not operate unfamiliar clinical features beyond authorized basic safety actions, keep the patient safely positioned, contact the hospice for model-specific training and direction, and complete required competency before independent use."},
      {"title": "A policy screenshot conflicts", "content": "A coworker sends a screenshot of an older procedure that conflicts with the current electronic aide plan.", "response": "Pause the affected task, use the controlled hospice policy source, contact the supervising RN to resolve the conflict, follow the confirmed direction, and report the outdated material so it can be removed."}
    ],
    "citation_label": "42 CFR 418.76 and CMS SOM Appendix M",
    "citation_url": "https://www.ecfr.gov/current/title-42/part-418/section-418.76 | https://www.cms.gov/Regulations-and-Guidance/Guidance/Manuals/downloads/som107ap_m_hospice.pdf",
    "citation_note": "Federal rules require RN-supervised hospice-aide services, competency, and at least 12 annual in-service hours. The hospice must insert current policy changes, identified performance gaps, devices, RN supervision, competency methods, and accepted training records."
  }
]
$hos$::jsonb;
  v_nh_enrichment jsonb := $nhe$
{
  "PA-NH-AIDE-DEMENTIA-COGNITIVE-CARE": {
    "correct_positions": [2,4,1,3,3,1,4,2],
    "practices": [
      {"title":"Baseline-to-change reporting worksheet","content":"Use the employer's change-in-condition policy and a de-identified resident profile to distinguish the usual cognitive baseline from a sudden functional change. Decide which care step must stop, which observations matter, and which contact path applies now.","deliverable":"Write a four-line report containing baseline, current facts, immediate safety action, and nurse notification time."},
      {"title":"Trigger and support map","content":"Review a dementia-care plan or employer example and map one distress behavior to possible pain, toileting, sensory, routine, communication, and environmental triggers. Select only plan-authorized supports and identify what pattern requires team review.","deliverable":"Create a trigger-support table with three observations, two least-restrictive supports, and one escalation threshold."}
    ],
    "questions": [
      {"prompt":"A resident with dementia is suddenly sleepy and cannot follow a familiar transfer. What should the aide do first?","correct":"Stop the unsafe transfer and promptly report objective baseline changes to the nurse.","distractors":["Finish the transfer slowly because cognitive changes are expected with dementia.","Use repeated orientation questions until the resident completes the transfer sequence.","Record dementia progression at shift end without interrupting the current routine."],"explanation":"A sudden departure from the resident's cognitive and functional baseline can signal an acute problem. Safety and prompt factual reporting come before completing the planned transfer."},
      {"prompt":"Which communication approach best supports a frightened resident who needs more processing time?","correct":"Use one calm idea at a time, allow silence, and offer two meaningful choices.","distractors":["Repeat several detailed instructions quickly so the resident hears every required step.","Correct each inaccurate statement before moving forward with the personal-care task.","Ask the roommate to persuade the resident because familiar pressure improves cooperation."],"explanation":"One-step language, time, and limited meaningful choice reduce cognitive load while preserving adult dignity. Rapid instruction, correction, and peer pressure can increase distress."},
      {"prompt":"A resident repeatedly pushes away evening care. Which inquiry is most consistent with person-centered dementia support?","correct":"Check for pain, toileting needs, fatigue, fear, and a change in the usual routine.","distractors":["Assume the behavior seeks attention and complete care before it becomes more difficult.","Ask security to stand nearby so the resident understands that refusal is unacceptable.","Remove all choices from the routine because options usually worsen cognitive impairment."],"explanation":"Distress behavior may communicate an unmet need or trigger. Checking common causes and the resident-specific plan supports comfort without punishment or unsupported assumptions."},
      {"prompt":"What is the safest response to exit-seeking when there is no immediate physical danger?","correct":"Maintain required observation and use the care plan's least-restrictive redirection supports.","distractors":["Block the doorway with furniture until a licensed clinician can assess the resident.","Hold the resident's arm firmly and explain that leaving is against facility rules.","Turn off the resident's call access so staff can focus on monitoring the exit."],"explanation":"Plan-directed observation and least-restrictive redirection protect safety without creating an unauthorized restraint. Blocking, grabbing, or removing call access can violate rights and increase risk."},
      {"prompt":"In the sudden-afternoon-change scenario, which report gives the nurse the most useful information?","correct":"Usual recognition and transfer ability, current sleepiness, fluid refusal, and unsafe sequencing.","distractors":["The resident seems much worse today and probably has another dementia-related decline.","The coworker believes the behavior is normal, so no immediate action was considered necessary.","The resident would not cooperate with rounds and may need a stricter behavioral approach."],"explanation":"Baseline comparisons and observable current findings support clinical triage. Diagnostic guesses, coworker opinions, and blame do not describe the change or immediate safety issue."},
      {"prompt":"A resident becomes more frightened when corrected about going home. What should the aide try next?","correct":"Acknowledge the worry, use a familiar support, maintain safety, and report the pattern.","distractors":["Continue correcting the facts until the resident agrees that the facility is home.","Promise a trip home after dinner even though no such plan has been authorized.","Ignore all further requests because responding reinforces repetitive dementia behavior."],"explanation":"Validation, familiar plan-based support, safety observation, and pattern reporting address emotion without arguing, deceiving, or withholding responsive care."},
      {"prompt":"Which documentation entry is most appropriate after a dementia-related distress episode?","correct":"Record exact behavior, possible trigger observed, support used, response, and notification.","distractors":["Record that the resident was combative and impossible throughout the entire evening shift.","Record only that dementia care was completed because detailed behavior is confidential.","Copy yesterday's note when the same resident appeared to have a similar episode."],"explanation":"Objective event details let the team recognize patterns and evaluate supports. Labels, omissions, and copied assumptions are not reliable clinical communication."},
      {"prompt":"When can this vendor dementia module count toward nursing-facility annual aide education?","correct":"After the facility accepts and tailors it to assessment, performance, resident, and policy needs.","distractors":["Immediately after the online quiz because federal dementia content is automatically transferable.","After the aide selects any duration that fills the remaining annual-hour requirement.","Only after the vendor independently certifies that every resident-specific competency is complete."],"explanation":"The facility owns acceptance, attendance records, local tailoring, and connection to the facility assessment and aide performance review. Vendor completion alone does not establish compliance."}
    ]
  },
  "PA-NH-AIDE-ABUSE-PREVENTION-REPORTING": {
    "correct_positions": [3,1,4,2,1,4,2,3],
    "practices": [
      {"title":"Reporting-route verification","content":"Retrieve the current abuse-prohibition policy and identify the immediate supervisor, alternate contact when that person is implicated, external reporting route, emergency route, and applicable timing language. Compare the policy with a disclosure received near shift change.","deliverable":"Produce a no-delay reporting card listing five contacts or routes in the order each would be used."},
      {"title":"Disclosure note and evidence decision","content":"Using a de-identified disclosure example, separate exact words and observations from inference. Decide which safety actions are authorized, which questions are minimal, and which actions could contaminate evidence or expose the resident to retaliation.","deliverable":"Draft an objective note plus a three-item do-not-do list for evidence, privacy, and nonretaliation."}
    ],
    "questions": [
      {"prompt":"What level of certainty does an aide need before reporting a possible abuse or neglect concern?","correct":"A reasonable concern, disclosure, or indicator is enough; proof is not required first.","distractors":["The aide must obtain a second witness before making any internal or external report.","The aide must determine which regulatory definition fits before contacting a supervisor.","The aide must wait for a visible injury because verbal concerns are too unreliable."],"explanation":"Reporting duties begin with allegations, observations, disclosures, or reasonable concern. Investigating for proof can delay protection and interfere with the authorized investigation."},
      {"prompt":"How should an aide respond when a resident first discloses that an employee caused harm?","correct":"Protect safety, listen calmly, ask only minimal open questions, and report immediately.","distractors":["Ask repeated detailed questions so the resident will not need to speak with investigators.","Confront the named employee privately and decide whether the explanation is credible.","Promise complete secrecy so the resident remains comfortable sharing additional details."],"explanation":"A calm, nonleading response preserves the resident's words and immediate safety. Repeated questioning, confrontation, or secrecy promises can cause harm and compromise reporting."},
      {"prompt":"The usual supervisor is named in a missing-property allegation. What reporting action is appropriate?","correct":"Use the alternate reporting chain and any required external route without delay.","distractors":["Give the usual supervisor one shift to locate the property before escalating the concern.","Ask coworkers whether the resident often misplaces items before recording the allegation.","Wait for the administrator's next scheduled visit because alternate contacts create conflict."],"explanation":"An implicated or unavailable supervisor cannot be allowed to screen the concern. The alternate and external routes preserve timely reporting and resident protection."},
      {"prompt":"Which note best preserves useful facts after a resident reports possible mistreatment?","correct":"Document the resident's exact words, observed condition, time, safety actions, and contacts.","distractors":["Document that the accused employee definitely committed abuse and should be terminated.","Document only that management was notified because resident statements belong elsewhere.","Document a summary from memory after coworkers agree on a single description of events."],"explanation":"Exact words, observations, times, actions, and notifications create a contemporaneous factual record. Conclusions and group summaries can distort evidence."},
      {"prompt":"A resident asks the aide not to report an assault because of fear of losing the room. What is the best response?","correct":"Explain the duty to seek help, protect the resident, and make required reports promptly.","distractors":["Honor the request unless the resident later provides physical evidence of the assault.","Ask the resident to sign a refusal form before deciding whether reporting is necessary.","Tell the alleged employee about the disclosure so both sides can resolve it informally."],"explanation":"Fear does not cancel protection and reporting duties. The aide should be transparent about needing help while avoiding delay, confrontation, or an invented refusal process."},
      {"prompt":"What should the aide do when a supervisor dismisses a resident's missing-cash report as confusion?","correct":"Preserve the report and use the alternate chain rather than accepting the dismissal.","distractors":["Search the resident's drawers and roommates' property before deciding whether to report.","Wait for another loss so a financial pattern can be established with greater certainty.","Ask the resident to withdraw the report because confusion makes external review unlikely."],"explanation":"Confusion does not make a property allegation unreportable. The alternate chain avoids screening by a potentially involved supervisor and preserves timely review."},
      {"prompt":"Which response to suspected retaliation is consistent with abuse-prevention responsibilities?","correct":"Report the threat or schedule change through protected routes and document objective facts.","distractors":["Keep the retaliation concern private because only direct resident harm must be reported.","Post the details publicly so outside observers can pressure the facility to respond.","Alter the original report to remove staff names and reduce the chance of workplace conflict."],"explanation":"Retaliation and interference undermine reporting protections and must be escalated through authorized channels. Public disclosure or record alteration creates additional harm."},
      {"prompt":"What must the facility add before accepting this abuse-prevention module for annual credit?","correct":"Current contacts, deadlines, protection steps, reporting routes, and attendance documentation.","distractors":["A vendor promise that the certificate replaces every state and federal reporting procedure.","A learner-selected reporting deadline based on the seriousness the learner personally assigns.","A rule requiring all allegations to remain internal until facility leadership proves misconduct."],"explanation":"The employer must operationalize current reporting law with local contacts, timelines, protection procedures, and records. A vendor course cannot supply or override those details."}
    ]
  },
  "PA-NH-AIDE-COMMUNICATION-RIGHTS-CULTURE": {
    "correct_positions": [4,2,3,1,2,3,1,4],
    "practices": [
      {"title":"Rights-at-the-bedside policy crosswalk","content":"Review the resident-rights notice, refusal procedure, privacy policy, and language-access process. Apply them to one routine care task and identify where permission, choice, privacy, and clinical escalation occur.","deliverable":"Create a six-step care script that includes consent, an accessible choice, refusal response, and nurse notification."},
      {"title":"Preference and risk decision record","content":"Use a de-identified cultural or scheduling preference that conflicts with the assignment sheet. Identify the resident's stated choice, immediate risk, authorized alternatives, role boundaries, and the team decision still needed.","deliverable":"Draft an objective preference note and a closed-loop handoff that avoids labeling the resident uncooperative."}
    ],
    "questions": [
      {"prompt":"A resident refuses scheduled care after the aide explains it. Which response best protects resident rights?","correct":"Pause, explore the reason without pressure, address immediate needs, and notify the nurse.","distractors":["Complete the care because accepting the assignment gives the aide implied permission.","Warn that repeated refusal may reduce future choices in the resident's daily schedule.","Ask a roommate to persuade the resident so the task can be completed on time."],"explanation":"A capable refusal requires a respectful pause and appropriate follow-up, not force or social pressure. The nurse can assess risk and revise the approach."},
      {"prompt":"What is the appropriate response when an aide cannot understand a patient's important care preference?","correct":"Use the plan's communication supports and authorized language-access process before proceeding.","distractors":["Ask any available visitor to interpret because familiarity is more important than privacy.","Proceed with the usual routine because uncertainty does not change the assignment sheet.","Speak much louder and repeat the same wording until the resident gives a response."],"explanation":"Authorized communication and language supports protect understanding, privacy, and meaningful participation. Guessing, volume, or unapproved interpretation can misrepresent the resident."},
      {"prompt":"Which action demonstrates cultural humility during intimate personal care?","correct":"Ask about address, touch, modesty, and routines instead of assuming group preferences.","distractors":["Use the same modesty routine for everyone so no cultural group receives different treatment.","Let staff beliefs determine which identity or relationship preferences are considered reasonable.","Avoid discussing preferences because asking respectful questions may emphasize differences."],"explanation":"Cultural humility relies on individual inquiry, listening, and correction of assumptions. Uniformity can ignore meaningful needs, while staff beliefs cannot justify unequal care."},
      {"prompt":"A resident choice creates a new risk not addressed by the current plan. What should the aide do?","correct":"Support safe options within the plan and promptly ask the nurse to resolve the new risk.","distractors":["Create a temporary restriction and add it to the assignment until the next care conference.","Tell the resident that all personal choices end whenever staff identify any possible hazard.","Ignore the risk because respecting autonomy prevents staff from communicating concerns."],"explanation":"The aide supports choice while communicating new risk to the authorized team. The aide cannot invent restrictions, and respecting autonomy does not require silence."},
      {"prompt":"A resident declines a dawn shower because it conflicts with prayer. What is the best aide response?","correct":"Respect the refusal and seek a plan-consistent alternative time through the care team.","distractors":["Explain that staffing schedules override religious preference and continue preparing the shower.","Cancel all bathing for the week because one refusal applies to every scheduled opportunity.","Trade assignments privately without notifying anyone or documenting the resident's request."],"explanation":"The aide should preserve dignity and communicate the requested accommodation for an authorized schedule adjustment. Coercion, overbroad cancellation, and hidden workarounds are unsafe."},
      {"prompt":"Why is using a young grandchild to interpret sensitive personal care generally inappropriate?","correct":"It can compromise accuracy, privacy, and voluntary participation in the care discussion.","distractors":["Children are never allowed inside a nursing facility under any circumstance or policy.","Family interpretation always changes the resident's legal decision-making capacity permanently.","Only written communication may be used when a resident speaks a different language."],"explanation":"Sensitive communication should use the facility's authorized language-access process because informal child interpretation can burden the child and compromise privacy and accuracy."},
      {"prompt":"Which documentation best captures a resident's request for a cultural accommodation?","correct":"Record the resident's words, requested change, options offered, contacts, and current response.","distractors":["Record that the resident was demanding and refused to follow normal facility culture.","Record only the final schedule because the reason for the change is private and irrelevant.","Copy another resident's accommodation note when both residents identify with the same culture."],"explanation":"The resident's own words and the response process show meaningful choice and follow-through. Labels, missing context, or group-based copying undermine individualized care."},
      {"prompt":"When may this rights and culture module count toward annual nurse-aide education?","correct":"When the facility accepts, tailors, and documents it with local rights and access procedures.","distractors":["When the learner certifies that personal values are consistent with every resident preference.","When the vendor confirms that language services and accommodations are identical nationwide.","When the online certificate replaces facility review of refusal, privacy, and grievance policies."],"explanation":"Facility acceptance and local policy integration are essential because rights, language access, accommodations, and documentation must operate in the actual care environment."}
    ]
  },
  "PA-NH-AIDE-INFECTION-PREVENTION": {
    "correct_positions": [1,3,2,4,4,2,3,1],
    "practices": [
      {"title":"Task-to-precaution selection","content":"Use the current infection-control policy to analyze bathing, oral care, incontinence care, and shared-equipment cleaning. For each task, identify hand-hygiene moments, anticipated exposure, required PPE, and the point at which clean supplies could become contaminated.","deliverable":"Complete a four-row precaution table with PPE, hand hygiene, clean-zone, and escalation decisions."},
      {"title":"Exposure and outbreak call-path drill","content":"Review the employee-exposure and outbreak policies. Apply them to a splash exposure and a resident with new respiratory symptoms, including immediate first aid, source control, alternate contacts, work restrictions, and confidential documentation.","deliverable":"Write two timed action sequences showing what occurs in the first minute, first call, and final record."}
    ],
    "questions": [
      {"prompt":"After removing gloves used for incontinence care, what infection-prevention step is still required?","correct":"Perform hand hygiene using the method required by the facility and situation.","distractors":["Wipe the gloves before removal so hand hygiene can wait until the next room.","Put on a second pair of gloves because layered gloves replace hand cleaning.","Use hand lotion only because intact skin cannot carry organisms after glove use."],"explanation":"Gloves can develop defects and hands can be contaminated during removal. Facility-required hand hygiene remains necessary after glove use."},
      {"prompt":"PPE directions are unclear before nonurgent exposure-prone care. What should the aide do?","correct":"Pause the task and obtain current direction from the nurse or infection-prevention lead.","distractors":["Choose the least restrictive PPE so the resident does not feel unnecessarily isolated.","Copy the PPE used for another resident because transmission precautions are unit-wide.","Begin the task without PPE and add equipment only if visible contamination occurs."],"explanation":"Current precautions and anticipated exposure determine PPE. Pausing nonurgent care prevents unsafe guessing while authorized staff clarify the direction."},
      {"prompt":"Which action prevents contamination when using a shared blood-pressure cuff?","correct":"Disinfect it with the approved product and full contact time before reuse.","distractors":["Cover visible soil with a clean towel so the cuff can be reused immediately.","Return it to clean storage and let the next aide decide whether cleaning is needed.","Spray it with any available household chemical even when compatibility is unknown."],"explanation":"Approved products, compatibility, assigned responsibility, and contact time make disinfection effective. Concealing soil or improvising chemicals can spread infection or damage equipment."},
      {"prompt":"During an outbreak, which observation should be reported as a possible change from baseline?","correct":"A new cough with unusual fatigue, even before a precaution sign is posted.","distractors":["A longstanding preference for a later breakfast with no other functional change.","A clean supply cart positioned in its normal marked location on the unit.","A visitor asking where to find the facility's public infection-control notice."],"explanation":"New respiratory and systemic changes can require prompt clinical and infection-control action. Staff should not wait for signage before reporting new symptoms."},
      {"prompt":"An aide wearing contaminated gloves reaches toward the clean supply cart. What is the best correction?","correct":"Stop, remove gloves safely, clean hands, and prevent or disinfect any cart contamination.","distractors":["Use one clean finger to take supplies because the remaining glove surface stays contaminated.","Ask another aide to open the package while continuing to touch the cart with gloves.","Finish care first and clean only the resident's bedside because carts are low-risk surfaces."],"explanation":"Stopping before contact protects the shared clean zone. Safe glove removal, hand hygiene, and surface response interrupt cross-contamination."},
      {"prompt":"A resident develops cough and fatigue during a unit outbreak. What should the aide do?","correct":"Apply policy-authorized immediate precautions and promptly report objective findings to the nurse.","distractors":["Diagnose the outbreak illness and tell the resident which treatment will be ordered.","Move the resident to another room without authorization to reduce staff exposure.","Wait for fever because respiratory symptoms alone never trigger outbreak communication."],"explanation":"The aide applies currently authorized measures and reports facts so licensed staff can assess. Diagnosis, independent relocation, and delayed reporting exceed the role or increase exposure."},
      {"prompt":"Which source controls the exact disinfectant, PPE, and outbreak steps used in this facility?","correct":"The current facility infection-control program and resident-specific clinical directions.","distractors":["The product preferred by the aide, regardless of label or equipment compatibility.","A social-media checklist written for a different setting and a previous outbreak.","A coworker's memory of precautions used before the current organism was identified."],"explanation":"Federal rules require a facility infection-control program, but local risk assessment, products, precautions, and clinical directions operationalize safe practice."},
      {"prompt":"What is required before this infection module is accepted for annual aide credit?","correct":"Facility acceptance, local policy tailoring, attendance records, and any required competency validation.","distractors":["Learner confirmation that the same PPE sequence applies to every resident and organism.","Vendor approval of the facility's outbreak plan without infection-prevention review.","Completion of the quiz as a substitute for product training and observed PPE technique."],"explanation":"The facility must connect vendor learning to its current program and verify practice where needed. Quiz completion alone cannot validate hands-on PPE or product use."}
    ]
  },
  "PA-NH-AIDE-ACCIDENT-FALL-TRANSFER-SAFETY": {
    "correct_positions": [2,1,4,3,1,3,2,4],
    "practices": [
      {"title":"Transfer-plan readiness check","content":"Use a de-identified transfer plan and equipment policy to verify assistance level, device and sling, helper count, weight limit, footwear, lines, symptoms, and stop conditions. Identify one mismatch that makes the scheduled transfer unsafe.","deliverable":"Produce a pre-transfer checklist and a closed-loop request for the exact missing help or equipment."},
      {"title":"Fall-scene documentation exercise","content":"Analyze a resident-found-on-floor example without diagnosing injury. Separate scene facts, resident statements, immediate protection, prohibited movement, notification, and post-fall follow-up while preserving the area when safe.","deliverable":"Draft a time-ordered fall note and a near-miss report using objective, blame-free language."}
    ],
    "questions": [
      {"prompt":"What should an aide verify immediately before a planned resident transfer?","correct":"Current condition, care-plan method, equipment, route, footwear, and required helpers.","distractors":["Only the method used yesterday because transfer plans remain safe until formally revised.","Only whether the resident agrees, because consent replaces equipment and helper checks.","Only whether the unit is busy, because staffing pressure determines assistance level."],"explanation":"A safe transfer requires both current resident observation and exact plan conditions. Yesterday's success, consent alone, or workload cannot replace equipment and assistance checks."},
      {"prompt":"A mechanical-lift sling is damaged before use. What is the correct aide action?","correct":"Stop the transfer, secure trained help, and obtain authorized compatible equipment.","distractors":["Use the sling once if the damaged area does not touch the resident's skin.","Add a sheet under the sling because extra fabric restores the original weight rating.","Change to a manual pivot even though the plan requires the mechanical lift."],"explanation":"Damaged or mismatched equipment invalidates the planned safe setup. The aide must stop and obtain authorized equipment rather than improvise another method."},
      {"prompt":"A resident is found on the floor with new hip pain. What should happen before lifting?","correct":"Protect the resident, summon clinical help, and avoid movement unless immediate danger requires it.","distractors":["Ask the resident to stand with two aides so staff can assess whether walking is possible.","Move the resident into bed first because privacy is more important than preserving position.","Use a gait belt immediately because all falls require prompt return to a seated surface."],"explanation":"New pain after a fall can signal injury. Protection, observation, and authorized clinical direction come before lifting unless an immediate environmental threat requires movement."},
      {"prompt":"Which action could function as an unauthorized restraint despite being described as fall prevention?","correct":"Placing furniture to block a resident from leaving the chair for staff convenience.","distractors":["Keeping the call device within reach according to the resident's current care plan.","Providing the prescribed walker and trained assistance during scheduled ambulation.","Removing a spill from the walking route and reporting the recurring environmental hazard."],"explanation":"Purpose and effect matter: a barrier that limits movement for convenience may be a restraint. Accessible assistance and hazard removal support mobility instead of restricting it."},
      {"prompt":"A resident assigned a pivot transfer cannot bear weight and reports new knee pain. What should the aide do?","correct":"Do not pivot; protect the resident and report the functional and pain changes promptly.","distractors":["Complete the pivot with a second aide because extra staff cures the plan mismatch.","Ask the resident to tolerate one transfer so the nurse can be called after reaching bed.","Select a lift independently because any mechanical device is safer than a delayed transfer."],"explanation":"The planned method no longer matches current ability. The aide must stop, protect, and notify rather than adding staff, pushing through symptoms, or selecting another device independently."},
      {"prompt":"A coworker starts lifting a resident from the floor before clinical direction. What is the best response?","correct":"Stop the unassessed lift, summon required help, and communicate pain and scene facts.","distractors":["Help finish quickly because interrupting a lift creates more risk than completing it.","Take a photograph first so the injury and scene can be reviewed after the resident moves.","Leave to find paperwork because documentation must be completed before clinical notification."],"explanation":"Stopping an unsafe lift and summoning help prevents further injury. Photography and paperwork cannot delay resident protection and clinical notification."},
      {"prompt":"Which post-event entry best supports accident-prevention improvement?","correct":"Document exact position, hazards, symptoms, actions, contacts, and resident response.","distractors":["Document that careless staff caused the event without identifying observable conditions.","Document that no injury occurred and omit the near miss because the resident recovered.","Document only the final transfer method because earlier scene details are not clinical."],"explanation":"Objective circumstances and near-miss information allow the team to identify hazards and revise safeguards. Blame or omission prevents useful learning."},
      {"prompt":"When may this transfer and fall module count toward annual nurse-aide education?","correct":"After facility tailoring, acceptance, attendance documentation, and required equipment competency checks.","distractors":["After the quiz because every lift and sling follows the same manufacturer procedure.","After the aide chooses a preferred transfer method for residents with similar diagnoses.","After vendor review replaces the facility's responsibility for device-specific observation."],"explanation":"The facility must connect content to its equipment, resident plans, policies, and competency validation. Online learning cannot prove hands-on transfer competence."}
    ]
  },
  "PA-NH-AIDE-RESTORATIVE-NURSING": {
    "correct_positions": [3,4,1,2,4,1,3,2],
    "practices": [
      {"title":"Restorative-plan task analysis","content":"Review a de-identified restorative assignment and separate the resident goal, aide action, cueing, assistance, precautions, repetitions, stop conditions, and facts requiring nursing or therapy review. Identify where over-assistance would undermine the goal.","deliverable":"Build a stepwise task analysis showing what the resident does, what the aide does, and when the task stops."},
      {"title":"Participation and trend note","content":"Compare three brief restorative visit examples with changing assistance and tolerance. Calculate the observable trend, identify the reportable change, and draft language that avoids labels such as lazy, unmotivated, or did well.","deliverable":"Write one measurable progress note, one decline note, and a concise nurse handoff for the trend."}
    ],
    "questions": [
      {"prompt":"What is the nurse aide's role in a resident's restorative nursing program?","correct":"Carry out the assigned plan under nursing direction and report response and change.","distractors":["Design new exercises whenever the resident appears ready for faster functional progress.","Replace therapy sessions when staffing shortages prevent the therapist from visiting.","Increase repetitions independently as long as the resident does not complain of pain."],"explanation":"The aide implements an authorized restorative plan and communicates observations. Designing, replacing therapy, or changing dosage requires qualified review."},
      {"prompt":"Which approach best promotes independence during dressing practice?","correct":"Set up supplies, allow time, cue steps, and assist only with parts still needed.","distractors":["Complete all buttons before breakfast so the resident avoids frustration and delay.","Withhold all assistance because true independence requires completing every step alone.","Change the resident's clothing choice to an easier garment without asking permission."],"explanation":"Graded assistance lets the resident perform each safe part while preventing failure or excessive dependence. Total assistance and no assistance can both defeat the plan."},
      {"prompt":"A resident reports new sharp pain during assigned range of motion. What should the aide do?","correct":"Stop the movement, support comfort, and promptly report the exact response.","distractors":["Reduce the speed but complete all repetitions because consistency prevents decline.","Test the joint in several directions to determine which structure may be injured.","Apply a warming product from the bedside and restart after the pain decreases."],"explanation":"New pain is a stop-and-report condition, not a cue to test, treat, or force completion. The nurse can assess and revise the plan."},
      {"prompt":"Which restorative note gives the team the most useful evidence of progress?","correct":"Resident walked 30 feet with one cue and contact assistance, then rested without symptoms.","distractors":["Resident did very well and seemed more motivated than during the previous week.","Restorative walking completed according to the plan with no additional details required.","Resident was lazy at first but cooperated after the aide insisted on finishing."],"explanation":"Distance, assistance, cueing, and tolerance are measurable and support comparison over time. Vague praise, bare completion, and judgmental labels do not."},
      {"prompt":"The unit is busy, but a resident can button a shirt with extra time. What should the aide do?","correct":"Provide setup and planned time, then assist only with the remaining needed steps.","distractors":["Dress the resident completely because workflow needs override a maintenance-of-function goal.","Leave the resident alone indefinitely because offering assistance would create dependence.","Remove buttoned clothing from the care plan without consulting the nurse or therapy team."],"explanation":"The restorative approach preserves participation through setup, cueing, and time. Workload should be escalated rather than solved by removing the resident's opportunity."},
      {"prompt":"What is the correct response when the restorative plan and current assignment disagree?","correct":"Pause the affected activity and obtain nursing clarification before proceeding.","distractors":["Choose the version with more repetitions because it offers greater therapeutic benefit.","Follow the coworker's memory because experienced staff can resolve written-plan conflicts.","Combine both instructions so neither source is ignored during the resident's routine."],"explanation":"Conflicting instructions create an authorization and safety problem. Nursing clarification is required before the aide chooses or combines techniques."},
      {"prompt":"What evidence may be needed beyond online course completion for a restorative skill?","correct":"Employer-observed technique, feedback, and competency validation for the assigned activity.","distractors":["A learner statement that every resident responds similarly to the demonstrated technique.","A vendor certificate that automatically authorizes changes to restorative care plans.","A quiz score that replaces observation of body mechanics, precautions, and equipment."],"explanation":"Restorative activities can require direct observation and resident-specific technique. A certificate or quiz measures knowledge, not hands-on performance."},
      {"prompt":"When can this restorative module count toward nursing-facility annual education?","correct":"When the facility accepts, tailors, documents, and connects it to resident and performance needs.","distractors":["When the aide independently chooses the activity with the greatest number of repetitions.","When the vendor guarantees that the module replaces therapy and nursing supervision.","When every resident receives the same exercise routine regardless of current plans."],"explanation":"The facility must use resident needs, performance review, and local restorative practice to accept the content. Generic completion cannot replace individual plans or supervision."}
    ]
  },
  "PA-NH-AIDE-PERSONAL-CARE-SKIN-NUTRITION": {
    "correct_positions": [4,3,2,1,3,2,4,1],
    "practices": [
      {"title":"Meal and personal-care plan verification","content":"Use a de-identified plan to verify bathing preferences, skin precautions, oral supports, diet texture, liquid consistency, allergy, feeding position, adaptive equipment, and assistance. Identify one conflict that requires clarification before care.","deliverable":"Complete a pre-care verification sheet with eight checks and a closed-loop clarification request."},
      {"title":"Observation-to-documentation lab","content":"Review sample skin, oral, intake, urine, stool, and swallowing observations. Separate what the aide can describe from diagnoses or treatments, choose the appropriate urgency, and use the facility measurement method.","deliverable":"Draft three objective entries and one urgent handoff using location, appearance, amount, baseline, action, and response."}
    ],
    "questions": [
      {"prompt":"Which preparation best supports dignified and safe personal care?","correct":"Review preferences and precautions, gather supplies, explain care, and encourage participation.","distractors":["Begin immediately and ask preferences later so exposed skin is not left uncovered.","Use the aide's preferred products because familiar supplies make the task more efficient.","Complete every step for the resident to avoid fatigue even when participation is planned."],"explanation":"Preparation, explanation, privacy, and participation support dignity and safety. Rushing, substituting products, or over-assisting can violate the plan."},
      {"prompt":"An aide sees persistent heel discoloration during sock removal. What should the aide do?","correct":"Relieve pressure as planned, avoid rubbing or unapproved products, and report promptly.","distractors":["Massage the area firmly until normal color returns and then replace the sock.","Apply a family-provided cream because intact skin does not require nursing direction.","Wait for skin to open before reporting because discoloration alone is not objective."],"explanation":"Persistent discoloration can signal pressure injury risk. Plan-based offloading and prompt reporting are appropriate; massage, treatment, and delay can cause harm."},
      {"prompt":"Which finding during feeding requires the aide to stop and obtain clinical help?","correct":"New coughing, wet voice, breathing change, or inability to manage the prescribed texture.","distractors":["The resident requests a favorite television program while remaining alert and comfortable.","The resident eats more slowly than the aide prefers but shows no swallowing warning sign.","The meal tray contains the correct texture and the resident asks for another napkin."],"explanation":"Coughing, wet voice, and breathing or swallowing changes can indicate aspiration risk. Routine preferences and safe pacing do not require stopping for the same reason."},
      {"prompt":"How should an aide record food and fluid intake?","correct":"Use the facility method to record what was actually consumed, including refusals and assistance.","distractors":["Estimate the expected amount before the meal so documentation is completed on time.","Record the amount offered because measuring what remains can upset the resident.","Copy the usual percentage unless a licensed nurse personally observes a change."],"explanation":"Actual measured or facility-defined intake supports clinical decisions. Pre-charting, offered amounts, and copied estimates can conceal meaningful decline."},
      {"prompt":"A resident coughs and develops a wet voice after a sip. What is the best response?","correct":"Stop intake, maintain the directed position, summon help, and report objective signs.","distractors":["Offer a larger sip to clear the throat before deciding whether the meal can continue.","Change to a different liquid consistency without an order and restart more slowly.","Lay the resident flat so coughing requires less energy while waiting for the nurse."],"explanation":"Stopping intake and escalating protects the airway while maintaining the prescribed safe position. More fluid, independent texture changes, or unsafe positioning can worsen harm."},
      {"prompt":"What should the aide document about a new skin change?","correct":"Exact location, color or appearance, pain report, actions, notification, and response.","distractors":["The medical stage and cause of the wound based on the aide's prior experience.","Only that skin care was completed because detailed findings belong in incident reports.","A photograph on a personal phone so the nurse can evaluate it after the shift."],"explanation":"Objective location and appearance plus communication create useful care evidence. Diagnosis, omission, and unauthorized photography exceed or violate the aide role."},
      {"prompt":"A family asks the aide to thicken a resident's drink differently from the current order. What should happen?","correct":"Do not change it; verify the current direction and contact the nurse for clarification.","distractors":["Follow the family request because household members know the resident's preferences best.","Mix two consistencies together so the final drink represents both sets of instructions.","Let the resident try the changed drink once and report only if coughing occurs."],"explanation":"Texture and consistency are clinical directions. The aide must follow the current plan and obtain authorized clarification before changing them."},
      {"prompt":"What makes this personal-care module eligible for annual nurse-aide credit?","correct":"Facility acceptance, local tailoring, attendance records, and any required competency observation.","distractors":["A passing quiz that authorizes every feeding, device, and skin procedure in the facility.","A vendor certificate that substitutes for current diets, orders, and resident care plans.","An aide-selected product list used consistently even when facility policy differs."],"explanation":"The facility must connect learning to current plans, products, documentation, and skill validation. Online knowledge alone does not authorize resident-specific procedures."}
    ]
  },
  "PA-NH-AIDE-EMERGENCY-FIRE-PREPAREDNESS": {
    "correct_positions": [1,2,3,4,2,4,1,3],
    "practices": [
      {"title":"Unit emergency-role lookup","content":"Retrieve the current emergency and fire plan for the assigned unit. Locate alarms, primary and alternate routes, fire doors, shelter areas, command contacts, resident assistance assignments, backup communication, and accountability tools.","deliverable":"Draw a unit action map with two routes, three role decisions, and the exact accountability handoff."},
      {"title":"Drill gap and corrective-action review","content":"Analyze a drill report containing a blocked route, unclear helper assignment, failed call system, and delayed resident count. Prioritize immediate correction, responsible role, due date, retest, and documentation without changing the approved emergency plan independently.","deliverable":"Complete a four-item corrective-action table and write the evidence needed to verify each fix."}
    ],
    "questions": [
      {"prompt":"What information must an aide know before a facility emergency occurs?","correct":"Assigned role, alarms, routes, communications, and each resident's assistance needs.","distractors":["Only the nearest exit because incident leaders assign every other detail after the alarm.","Only the fire-extinguisher location because aides are expected to control small fires first.","Only the administrator's number because all resident movement waits for executive approval."],"explanation":"Prepared aides need role, route, communication, and resident-support knowledge before an event. One exit, one device, or one contact is not an emergency plan."},
      {"prompt":"Smoke is visible near resident rooms and no alarm is sounding. What should the aide do?","correct":"Initiate the facility fire alarm and notification process and protect immediate life as trained.","distractors":["Search for the fire source alone before alarming residents or contacting other staff.","Open doors and windows throughout the unit so smoke can leave the building faster.","Use an elevator to move residents because it reduces the time spent near smoke."],"explanation":"Early alarm and trained life-safety actions activate the facility response. Delayed investigation, uncontrolled airflow, and elevator use can increase fire risk."},
      {"prompt":"During evacuation, which action maintains resident accountability?","correct":"Track each resident through the ordered movement and confirm handoff at the receiving area.","distractors":["Move the fastest residents first and reconstruct everyone's location after the unit clears.","Let family members choose destinations because they know which location feels safest.","Remove identification materials to protect privacy during transfer between care areas."],"explanation":"Continuous tracking and confirmed handoff prevent missing or duplicated movement. Speed without accountability and unauthorized destinations create serious risk."},
      {"prompt":"How should an aide treat a scheduled emergency drill?","correct":"Perform the assigned role, identify barriers, and contribute facts to corrective action.","distractors":["Sign the attendance record but skip movement because drills cannot create real learning.","Use shortcuts that would be prohibited in an event so routine care remains uninterrupted.","Wait for the final report and avoid describing failures that could affect staff evaluations."],"explanation":"Drills test whether roles, routes, equipment, and communication work. Honest performance and reporting allow the facility to correct real weaknesses."},
      {"prompt":"A prolonged power outage stops a resident's oxygen concentrator. What is the correct response?","correct":"Use the approved backup and emergency plan and immediately report the priority need.","distractors":["Reconnect the concentrator through improvised household wiring to restore power quickly.","Reduce the oxygen setting so the remaining equipment can operate for a longer period.","Wait for power restoration because changing equipment would exceed the aide role."],"explanation":"The facility plan provides authorized backup and escalation for power-dependent support. Improvised wiring, setting changes, and passive delay can endanger the resident."},
      {"prompt":"When may an aide use a fire extinguisher during a facility fire response?","correct":"Only when trained and assigned, conditions are safe, and a clear escape route remains.","distractors":["Whenever smoke is visible because extinguishing the source always comes before evacuation.","Only after every resident reaches the final relocation site, regardless of fire growth.","Whenever another employee requests help, even if training and escape access are absent."],"explanation":"Extinguisher use is conditional on training, assignment, fire conditions, and escape. It must never delay alarm, evacuation, or personal safety."},
      {"prompt":"Which federal section directly addresses nursing-facility life safety from fire and physical environment?","correct":"42 CFR 483.90, together with the facility's applicable life-safety procedures.","distractors":["42 CFR 483.71, which addresses the facility assessment rather than fire systems.","42 CFR 484.80, which establishes home-health-aide conditions and annual in-service.","42 CFR 418.76, which governs hospice-aide services and in-service requirements."],"explanation":"Section 483.90 governs the long-term-care physical environment and life safety from fire. Emergency preparedness and training sections also apply but do not replace it."},
      {"prompt":"What additional evidence is needed before this online emergency course counts as annual facility training?","correct":"Employer acceptance, site-specific instruction, drill participation, role validation, and attendance records.","distractors":["A vendor statement that a generic map applies to every unit and relocation destination.","A learner promise to remember the nearest exit without reviewing resident assignments.","An online quiz used instead of required drills, local routes, and emergency communications."],"explanation":"Emergency readiness depends on the actual building, residents, roles, routes, and exercises. Vendor learning contributes but cannot replace local instruction and drills."}
    ]
  },
  "PA-NH-AIDE-BEHAVIORAL-HEALTH-PERSON-CENTERED": {
    "correct_positions": [2,3,1,4,4,1,3,2],
    "practices": [
      {"title":"Behavior-to-observation rewrite","content":"Rewrite stigmatizing or diagnostic shift notes into exact words, observable behavior, context, baseline change, support attempted, and response. Use the behavioral-health and crisis policies to select routine, urgent, or emergency escalation.","deliverable":"Produce three objective rewrites and identify the policy threshold and contact for each example."},
      {"title":"Trauma-informed de-escalation plan","content":"Apply a de-identified care plan to a distress episode involving noise, touch, and loss of control. Choose a predictable introduction, space, communication, meaningful choice, and early help while rejecting coercive shortcuts.","deliverable":"Write a six-step de-escalation script plus one sentence explaining each prohibited action you rejected."}
    ],
    "questions": [
      {"prompt":"Which documentation best describes a behavioral-health change without stigmatizing the resident?","correct":"Record exact words, pacing, sleep change, context, supports attempted, and response.","distractors":["Record that the resident was manipulative and wanted attention throughout the shift.","Record a new psychiatric diagnosis based on the aide's interpretation of the behavior.","Record only that the resident was difficult because detailed behavior may be upsetting."],"explanation":"Objective words, behavior, context, intervention, and response support clinical review. Labels and aide-made diagnoses stigmatize and obscure what happened."},
      {"prompt":"What is a trauma-informed approach before beginning hands-on personal care?","correct":"Explain the task, ask permission, offer choices, and follow known trigger supports.","distractors":["Begin quickly without warning so anticipation does not give the resident time to refuse.","Require the resident to disclose past trauma before any accommodation is considered.","Use firm commands and close physical presence to demonstrate that staff control the setting."],"explanation":"Predictability, permission, and choice reduce loss of control and avoid unnecessary triggers. Forced disclosure and coercive presence can retraumatize the resident."},
      {"prompt":"A resident states there is no reason to live. What should the aide do?","correct":"Stay present, notify the nurse immediately, and activate the facility safety pathway.","distractors":["Promise secrecy and monitor mood privately until the resident repeats the statement.","Explain that many residents feel this way and redirect to a scheduled group activity.","Ask the resident to complete a detailed suicide assessment before contacting the nurse."],"explanation":"Self-harm language requires immediate safety escalation through the facility pathway. The aide should not promise secrecy, normalize the risk, or conduct an independent clinical assessment."},
      {"prompt":"Which action is appropriate during escalating agitation when no immediate attack is occurring?","correct":"Maintain space, reduce stimulation, speak briefly, offer a safe choice, and summon help early.","distractors":["Crowd the resident with several staff so every exit and movement can be controlled.","Argue through each inaccurate belief until the resident acknowledges the factual situation.","Search the resident's belongings without authorization to remove anything that might be risky."],"explanation":"Low-stimulation communication, space, choice, and early assistance support de-escalation. Crowding, argument, and unauthorized searches can intensify distress and violate rights."},
      {"prompt":"A resident pushes the aide away after an unexpected door opening during bathing. What is the best response?","correct":"Stop nonurgent care, restore privacy, offer space and choice, and report the trigger.","distractors":["Finish the bath with another aide because refusal during exposure is not meaningful.","Tell the resident the reaction is inappropriate and require an apology before stopping.","Document physical aggression without mentioning the privacy breach or care context."],"explanation":"Stopping, restoring privacy, and using plan-based trauma supports address the trigger and preserve safety. Force, punishment, and incomplete documentation can cause further harm."},
      {"prompt":"Which boundary protects both resident support and professional judgment?","correct":"Do not exchange secret contact, money, substances, or favors outside facility policy.","distractors":["Accept private messages if the resident promises not to discuss clinical information.","Borrow small amounts when repayment occurs before the next scheduled work shift.","Keep a resident's safety concern secret when disclosure might damage staff relationships."],"explanation":"Secret dual relationships, money, substances, and hidden concerns can create exploitation and impaired judgment. Facility channels preserve transparent professional support."},
      {"prompt":"What details belong in a record after a de-escalation attempt?","correct":"Precipitating facts, exact behavior, support used, timing, response, injuries, and contacts.","distractors":["The aide's opinion about the resident's personality and motives for seeking attention.","Only whether the resident became quiet, because earlier escalation is no longer relevant.","A copied description from the last episode even when the trigger and response differed."],"explanation":"Event-specific observations and response allow the team to evaluate patterns and supports. Motive assumptions, omissions, and copied narratives are unreliable."},
      {"prompt":"What must occur before this behavioral-health module counts as annual nurse-aide education?","correct":"Facility acceptance and tailoring to resident needs, crisis policy, resources, and staff competence.","distractors":["Vendor confirmation that one de-escalation sequence is clinically appropriate for every resident.","Learner completion used instead of care-plan review and facility crisis-response instruction.","Aide agreement to manage all distress without calling licensed or emergency resources."],"explanation":"The facility assessment, population, care plans, and crisis resources determine how knowledge is applied. Vendor content alone cannot establish resident-specific competence."}
    ]
  },
  "PA-NH-AIDE-QAPI-ETHICS-DOCUMENTATION": {
    "correct_positions": [3,2,4,1,1,4,2,3],
    "practices": [
      {"title":"Record-integrity correction lab","content":"Use the current chart-correction, late-entry, credential, and downtime policies to resolve a wrong-resident entry, delayed documentation, and unavailable login. Preserve author, time, original information, and escalation without fabricating care.","deliverable":"Write the approved correction sequence for all three events and identify what the audit trail must retain."},
      {"title":"Near-miss to QAPI action","content":"Analyze repeated lift-battery failures that have not caused injury. Separate immediate equipment safety, clinical communication, incident or near-miss reporting, QAPI review, contributing system conditions, and follow-up verification.","deliverable":"Create a one-page improvement record with facts, risk, owner, corrective action, measure, and retest date."}
    ],
    "questions": [
      {"prompt":"A coworker asks the aide to chart completed care using the aide's login. What is the correct response?","correct":"Refuse credential sharing and direct the coworker to the approved access and correction process.","distractors":["Enter the care if the coworker verbally confirms every task and time as accurate.","Share the password once and change it later so the record still shows a unique account.","Leave the task undocumented because any late entry is less accurate than no entry."],"explanation":"Each user must authenticate and document their own work through approved processes. Shared credentials destroy attribution, while an authorized late entry preserves the audit trail."},
      {"prompt":"Which charting practice creates the most reliable resident record?","correct":"Document actual care and objective observations promptly in the correct resident record.","distractors":["Pre-chart predictable routines and revise only when something unusual happens during care.","Copy the prior shift's assessment language when the resident appears generally unchanged.","Use broad labels so other staff can interpret details according to their own experience."],"explanation":"Timely, resident-specific, objective documentation supports safe decisions. Pre-charting, copied assumptions, and vague labels can hide changes or misstate care."},
      {"prompt":"How do the clinical record and an incident report relate after a resident event?","correct":"Each serves its own required purpose; neither should be used as a substitute for the other.","distractors":["The confidential incident report replaces all clinical documentation about the resident's response.","The clinical note should include protected QAPI conclusions so every employee can review them.","Only one record is needed, and the aide may choose whichever form takes less time."],"explanation":"The clinical record communicates resident care, while incident and quality systems support separate review. Both must be completed as policy requires without leaking protected conclusions."},
      {"prompt":"What is the aide's most useful contribution to QAPI work?","correct":"Provide honest frontline observations, workflow barriers, near misses, and response to changes.","distractors":["Adjust documentation so monthly measures show improvement before the process is stable.","Avoid reporting workarounds because QAPI should focus only on events causing actual injury.","Select only successful resident examples so the improvement team remains encouraged."],"explanation":"QAPI depends on accurate frontline evidence, including near misses and barriers. Manipulating data or selecting only successes prevents the facility from learning."},
      {"prompt":"A lift battery repeatedly fails during setup but no resident falls. What should the aide do?","correct":"Protect the resident, remove or tag equipment as directed, and report the recurring near miss.","distractors":["Continue swapping batteries because no injury means the equipment remains clinically acceptable.","Wait until the lift fails during an actual transfer so the report includes a measurable outcome.","Purchase a replacement battery personally and avoid involving the facility maintenance process."],"explanation":"Repeated equipment failure is a reportable near miss and system risk. Waiting for injury or creating a private workaround bypasses safety controls."},
      {"prompt":"An aide discovers an entry was placed in the wrong resident's chart. What should happen?","correct":"Report it promptly and use the approved correction process that preserves the original audit trail.","distractors":["Delete the entry completely so no inaccurate information remains visible to other staff.","Add the correct resident's name to the note without notifying anyone about the initial error.","Ask the next shift to correct it because changing one's own entry appears suspicious."],"explanation":"Prompt reporting and audit-preserving correction protect both records and allow care impacts to be assessed. Deletion, silent editing, and delay conceal the error."},
      {"prompt":"Which action best protects resident privacy during ordinary documentation work?","correct":"Use approved systems, limit access to work need, secure screens, and avoid personal messaging.","distractors":["Photograph the screen with a personal phone when the electronic record is temporarily slow.","Discuss the resident quietly in a public elevator because names are not being used.","Leave the record open for the next aide so repeated login does not delay bedside care."],"explanation":"Approved systems, minimum necessary access, and secured displays reduce unauthorized disclosure. Personal devices, public discussion, and open sessions create privacy risk."},
      {"prompt":"When may this QAPI and documentation course count toward annual aide education?","correct":"After facility acceptance and integration with current records, incident policy, ethics, and QAPI priorities.","distractors":["After the vendor certifies that its sample record matches every facility documentation system.","When the quiz replaces employer instruction about corrections, downtime, and protected quality review.","When the aide promises to avoid all errors, making follow-up observation and auditing unnecessary."],"explanation":"The facility must apply its actual systems, policies, and quality priorities and document attendance. Generic examples cannot substitute for local workflows and follow-up."}
    ]
  },
  "PA-NH-AIDE-PERFORMANCE-FACILITY-REMEDIATION": {
    "correct_positions": [4,1,3,2,2,3,1,4],
    "practices": [
      {"title":"Facility-assessment learning crosswalk","content":"Retrieve the current 42 CFR 483.71 facility assessment summary available for staff education and connect resident population, acuity, services, equipment, staffing competency, incidents, and new admissions to one annual aide learning priority.","deliverable":"Write a crosswalk naming the assessed need, affected task, required skill evidence, and responsible educator."},
      {"title":"Performance-gap remediation design","content":"Use a de-identified performance-review weakness to distinguish knowledge, hands-on skill, unclear plan, equipment, workload, and technology contributors. Select training, supervised practice, system correction, and follow-up evidence without treating course completion as mastery.","deliverable":"Produce a remediation plan with target behavior, practice method, evaluator, system action, measure, and follow-up date."}
    ],
    "questions": [
      {"prompt":"What makes performance feedback useful for designing nurse-aide remediation?","correct":"It identifies an observable gap, expected standard, resident risk, and conditions of performance.","distractors":["It describes the aide's attitude broadly so the educator can choose any motivational course.","It assigns blame before examining whether equipment, plans, or staffing contributed to the gap.","It requires repeating all annual courses regardless of which behavior or system failed."],"explanation":"Specific behavior, standard, risk, and context distinguish knowledge, skill, and system needs. Broad labels and blanket retraining do not target the cause."},
      {"prompt":"Which federal section now contains the nursing-facility assessment requirement used to tailor training?","correct":"42 CFR 483.71 contains the current facility assessment requirement.","distractors":["42 CFR 483.70 remains the current location of the separate facility assessment section.","42 CFR 483.90 contains the facility assessment because it governs the physical environment.","42 CFR 484.80 contains the nursing-facility assessment and nurse-aide performance review."],"explanation":"The facility assessment requirement is in 42 CFR 483.71. It informs workforce competency and training needs based on the resident population and services."},
      {"prompt":"What evidence may be required to show remediation of a hands-on transfer weakness?","correct":"Qualified demonstration, supervised practice, return demonstration, feedback, and follow-up observation.","distractors":["A passing online quiz without use of the facility's actual lift, sling, or helper procedure.","A written promise that the aide will copy the most experienced coworker's transfer technique.","Completion of unrelated annual hours until the total exceeds the facility's minimum requirement."],"explanation":"Hands-on gaps require observed performance with relevant equipment and conditions. Hour totals and knowledge quizzes do not establish safe technique."},
      {"prompt":"An aide receives an unfamiliar assignment that exceeds current competency. What should the aide do?","correct":"Pause the task, protect the resident, disclose the gap, and obtain authorized trained support.","distractors":["Attempt the task once so the supervisor can later evaluate whether retraining was necessary.","Exchange tasks privately with a coworker and omit the competency concern from handoff.","Follow an online demonstration even when the device and resident plan differ from the example."],"explanation":"Speaking up before unsafe performance protects the resident and allows appropriate assignment or training. Trial-and-error and hidden workarounds conceal the risk."},
      {"prompt":"Missing intake entries coincide with unreliable meal-time connectivity. What is the best remediation response?","correct":"Practice accurate downtime entry and correct the connectivity barrier through the responsible process.","distractors":["Retrain the aide on nutrition alone because technology problems cannot affect documentation behavior.","Estimate missing intake at the end of each week so records remain complete despite outages.","Remove documentation from the performance target because the system contributed to the problem."],"explanation":"The response must address both the required skill and the system barrier. Estimation and abandoning the standard do not create accurate records."},
      {"prompt":"A facility begins using complex lifts for a new admission pattern. What training decision follows?","correct":"Update assessed competency needs and provide device-specific training and observed validation before assignment.","distractors":["Assign experienced aides immediately because general transfer experience covers every lift model.","Use the vendor video as final competency proof without supervised practice on actual equipment.","Delay all education until an incident shows which part of the new process is most difficult."],"explanation":"New resident and equipment needs belong in the facility assessment and competency plan. Device-specific observed readiness must precede independent assignment."},
      {"prompt":"Which finding suggests a system correction is needed in addition to individual education?","correct":"Multiple aides follow conflicting written plans because the controlled source is not updated.","distractors":["One aide cannot describe a current procedure that is clearly available and consistently taught.","One learner requests additional supervised practice before a newly assigned transfer skill.","One competency evaluator documents a correction that the learner then performs successfully."],"explanation":"Widespread conflict caused by an outdated source is a system defect. Individual retraining alone will not correct the authoritative information that staff receive."},
      {"prompt":"When can this remediation module count toward annual nurse-aide education?","correct":"When the facility selects the actual need, accepts the content, documents attendance, and validates outcomes.","distractors":["When the vendor chooses a generic weakness without reviewing facility assessment or performance data.","When course completion is treated as proof that every related hands-on competency is restored.","When an aide repeats the module annually even though the facility never defines a target behavior."],"explanation":"Regulations require education tied to performance weaknesses and facility-assessment needs. The employer must choose, tailor, document, and verify the actual remediation."}
    ]
  }
}
$nhe$::jsonb;
  v_hha_enrichment jsonb := $hhae$
{
  "PA-HHA-AIDE-RIGHTS-COMMUNICATION-CULTURE": {
    "correct_positions": [1,4,2,3,3,2,4,1],
    "practices": [
      {"title":"Aging and illness observation reflection","content":"Use the agency's assessment and communication policy with a de-identified profile. Separate an individual aging change, an emotional response to illness, a sudden reportable change, and a stereotype. Decide how each affects communication without diagnosing.","deliverable":"Write four observation statements, one supportive phrase for each, and the nurse-report threshold for any baseline change."},
      {"title":"Rights and language-access lookup","content":"Retrieve the patient-rights, interpreter, privacy, refusal, and boundary procedures. Apply them to a patient whose family speaks over the patient and requests a personal social-media connection with the aide.","deliverable":"Create a six-step response showing direct patient communication, authorized interpretation, privacy, refusal handling, boundary language, and escalation."}
    ],
    "questions": [
      {"prompt":"Which statement reflects appropriate understanding of the aging process in home care?","correct":"Aging varies by person, so compare function and communication with the patient's own baseline.","distractors":["Confusion is an inevitable aging change, so new disorientation rarely requires reporting.","Older adults generally lose decision-making ability and should defer choices to family members.","Aging follows a predictable sequence, so one standard communication method fits each age group."],"explanation":"Pennsylvania requires training in the aging process, but aging must not become a stereotype. Patient-specific baseline and meaningful change guide observation and reporting."},
      {"prompt":"A patient becomes tearful and angry after an illness limits independence. What is the best aide response?","correct":"Acknowledge the emotion, support plan-based choice, and report meaningful mood or function change.","distractors":["Explain that anger is medically expected and therefore does not need team communication.","Redirect every emotional statement so the visit remains focused only on physical tasks.","Tell the family to make all care decisions until the patient displays a positive attitude."],"explanation":"Illness can bring grief, fear, anger, and loss of control. Respectful listening and reporting change support the patient without diagnosing or taking away autonomy."},
      {"prompt":"A patient and aide do not share a language for an intimate-care discussion. What should the aide use?","correct":"The plan's communication supports and the agency's authorized language-access process.","distractors":["Any nearby child who speaks both languages because family interpretation is always sufficient.","Gestures alone, even when the aide cannot confirm consent or understand reported symptoms.","A personal translation account that stores patient information outside agency controls."],"explanation":"Authorized language access and plan supports protect accuracy, consent, privacy, and patient participation. Informal or unsecured methods can misrepresent critical information."},
      {"prompt":"A competent patient states a preference while a relative repeatedly answers instead. What should the aide do?","correct":"Address the patient directly, support private communication, and report coercion or unresolved conflict.","distractors":["Follow the relative because household ownership gives family final authority over home-care choices.","End the visit immediately without assessing safety or contacting the supervising nurse.","Ask both people to vote, treating care preference as a decision made by simple majority."],"explanation":"The patient's rights and voice remain central. The aide should facilitate accessible direct communication and involve the care team when coercion or safety concerns persist."},
      {"prompt":"A patient asks an aide to post a visit photograph online. What is the appropriate response?","correct":"Decline personal posting and refer the request to the agency's authorized privacy process.","distractors":["Post it without the patient's name because images alone cannot reveal protected information.","Use a disappearing message because temporary social-media content does not require authorization.","Ask a family member to post it from the aide's phone so the agency is not directly involved."],"explanation":"Patient permission alone may not satisfy agency privacy and boundary controls. Personal devices and social media create disclosure and professional-role risks."},
      {"prompt":"Which action best respects culture and identity without stereotyping?","correct":"Ask about the patient's preferences and follow the authorized plan rather than assuming group customs.","distractors":["Apply the same faith and modesty practices to everyone from a shared cultural background.","Avoid asking about identity because respectful care should remain culturally neutral and identical.","Let the aide's personal beliefs determine which household relationships deserve recognition."],"explanation":"Cultural humility is individualized inquiry and correction of assumptions. Group rules, avoidance, and staff beliefs can erase the patient's stated identity and preferences."},
      {"prompt":"Which Pennsylvania rule expressly includes aging and emotional problems of illness in HHA training?","correct":"28 Pa. Code Section 601.35 expressly lists both subjects for home health aides.","distractors":["28 Pa. Code Section 201.20 is the exclusive home-health rule for these two topics.","42 CFR 483.90 lists aging and illness emotions as nursing-facility fire-safety content.","42 CFR 418.76 assigns those HHA topics to hospice volunteers rather than home health aides."],"explanation":"Section 601.35 specifically lists the aging process and emotional problems of illness among Pennsylvania home-health-aide training topics."},
      {"prompt":"What must occur before this HHA rights course can be accepted as annual in-service credit?","correct":"The agency RN approves the content and attends the in-service to supervise it, with agency records.","distractors":["The vendor supervises the aide remotely, making RN content review and attendance unnecessary.","The RN approves the outline afterward, even if no RN attended the in-service presentation.","The aide submits a certificate directly to Pennsylvania without agency acceptance or documentation."],"explanation":"CMS guidance requires the agency RN to approve the content and attend the in-service to supervise it. The agency must also accept and retain the training record."}
    ]
  },
  "PA-HHA-AIDE-OBSERVATION-VITALS-ESCALATION": {
    "correct_positions": [2,4,3,1,1,3,4,2],
    "practices": [
      {"title":"Measurement-technique verification","content":"Use the agency competency checklist for one assigned vital sign and one weight. Identify patient position, device fit, rest period, repeat rule, equipment check, documentation field, threshold, and when symptoms require escalation without repeating.","deliverable":"Complete a technique card and a teach-back script covering eight verification points and two stop conditions."},
      {"title":"Urgency and call-tree sorting exercise","content":"Sort de-identified breathing, swelling, fever, dizziness, confusion, intake, and pain examples into emergency, urgent nurse call, and routine report using current policy and patient instructions. Apply the alternate route when the first contact fails.","deliverable":"Produce a seven-row decision table with facts, urgency, first contact, alternate contact, immediate action, and documentation."}
    ],
    "questions": [
      {"prompt":"What information makes an aide's change-in-condition report clinically useful?","correct":"Specific baseline comparison, current facts, onset, assigned measurements, function, and safety.","distractors":["A diagnosis selected from the patient's problem list and the aide's likely treatment recommendation.","A statement that the patient seems worse, without describing what changed or when.","Only the newest vital sign because symptoms and functional change are subjective information."],"explanation":"Baseline, onset, objective findings, assigned data, function, and current safety allow the nurse to triage. Diagnosis and vague impressions do not."},
      {"prompt":"Which practice is correct when an assigned blood-pressure reading appears unexpected?","correct":"Check technique and equipment as policy directs, then report without delaying concerning symptoms.","distractors":["Repeat the reading until a value near the patient's usual range appears and chart that value.","Change the cuff location without training because different sites provide a more accurate average.","Wait until the next scheduled visit because a single unexpected reading has no clinical value."],"explanation":"Technique verification can identify error, but repeated testing must not delay symptom escalation. All actual readings and concerns must be communicated honestly."},
      {"prompt":"A patient cannot speak full sentences and has blue discoloration around the lips. What should the aide do?","correct":"Activate emergency services under the plan, support safety, and notify the agency immediately.","distractors":["Wait for a relative who is a nurse because family clinical judgment outranks the agency plan.","Complete a full set of repeated vital signs before deciding whether emergency help is necessary.","Drive the patient to urgent care personally so emergency responders do not disturb the home."],"explanation":"Severe breathing difficulty and color change are immediate threats. The aide must use the emergency plan without delaying for family, extensive measurement, or personal transport."},
      {"prompt":"The first nurse contact does not answer an urgent change report. What is the correct next step?","correct":"Use the agency's alternate escalation route and continue appropriate safety actions.","distractors":["Leave one voicemail and wait until the next visit because the reporting duty is complete.","Ask the patient to decide whether the change can safely wait for regular office hours.","Send clinical details through a personal text to any coworker who appears available."],"explanation":"Urgent communication requires closed-loop escalation. An unanswered call is not a handoff, and personal messaging may violate privacy and policy."},
      {"prompt":"A patient's weight rises and ankle swelling increases from baseline. What should the aide do?","correct":"Verify the assigned measurement and promptly report the trend and swelling to the nurse.","distractors":["Recommend reducing fluids because swelling proves the patient is retaining too much water.","Skip documentation at the patient's request and check whether the weight falls tomorrow.","Increase activity independently because walking is the standard treatment for ankle swelling."],"explanation":"The aide verifies and reports objective change; diagnosis and treatment belong to qualified clinicians. Patient reluctance does not justify concealing meaningful findings."},
      {"prompt":"Which documentation best closes the loop after an urgent observation call?","correct":"Record facts, time, contacts and attempts, directions read back, actions, and patient response.","distractors":["Record only that the nurse was informed because call details are stored on the phone.","Enter the nurse's assessment as though the aide personally performed the clinical evaluation.","Wait to chart until the outcome is known so the record contains only the final result."],"explanation":"Times, attempts, directions, actions, and response show what was communicated and done. Delayed or incomplete records can obscure urgent follow-up."},
      {"prompt":"How does 28 Pa. Code Section 601.35 apply to observation and reporting?","correct":"It requires training in reportable condition changes and work from RN-prepared patient instructions.","distractors":["It authorizes aides to diagnose new conditions when the supervising nurse is unavailable.","It limits reporting to vital-sign readings and excludes functional or emotional change.","It permits families to replace written RN instructions with verbal household preferences."],"explanation":"Section 601.35 requires aides to be trained in changes that should be reported and provides for RN assignment and written patient-care instructions."},
      {"prompt":"What is required for this observation module to count as HHA annual in-service?","correct":"The agency RN approves the content and attends the in-service to supervise it and document credit.","distractors":["A licensed practical nurse signs the vendor certificate later without RN attendance at training.","The aide completes the quiz alone and chooses which abnormal thresholds the agency should use.","The vendor records attendance while the agency omits RN approval and its emergency procedures."],"explanation":"The agency RN must approve the content and attend the in-service to supervise it. Agency thresholds, call routes, acceptance, and records must be applied."}
    ]
  },
  "PA-HHA-AIDE-DOCUMENTATION-CARE-COORDINATION": {
    "correct_positions": [3,1,2,4,4,2,1,3],
    "practices": [
      {"title":"Visit-record audit","content":"Compare a de-identified plan, assignment, aide note, and call log. Identify pre-charting, copied text, omitted refusal, unsupported conclusion, missing nurse contact, and time inconsistency, then use the agency correction procedure.","deliverable":"Create a corrected objective visit note and list the audit-trail elements that must remain visible."},
      {"title":"Deviation and handoff drill","content":"Apply the care-coordination policy to a task that cannot be completed because of symptoms, missing equipment, and a failed electronic connection. Decide immediate safety, first and alternate contact, authorized substitute, downtime record, and unresolved handoff.","deliverable":"Write a closed-loop call script and a downtime entry that clearly distinguishes completed, omitted, and deferred care."}
    ],
    "questions": [
      {"prompt":"Which entry belongs in a home-health-aide visit record?","correct":"Tasks actually provided, assistance, observations, patient response, refusals, and required contacts.","distractors":["Tasks expected on the assignment even when the patient refused or the aide omitted them.","A nurse-level assessment explaining the diagnosis responsible for the patient's response.","Only unusual events because routine care does not need to be connected to the plan."],"explanation":"The visit record must reflect actual care and response, including deviations and communication. Expected tasks and aide-made diagnoses misstate the encounter."},
      {"prompt":"Which phrase is the most objective documentation of a mobility change?","correct":"Patient required two cues and contact assistance after usually walking with one cue.","distractors":["Patient was lazy and did not try as hard as usual during the walking exercise.","Patient looked medically unstable and probably experienced a neurological decline.","Patient did poorly today, and the family appeared unconcerned about the situation."],"explanation":"Specific assistance and baseline comparison describe observable function. Labels, diagnosis, and judgments about effort or family attitude are not objective."},
      {"prompt":"The plan-directed walk is unsafe because the patient is newly dizzy. What should the aide record?","correct":"The dizziness, omitted walk, immediate safety action, nurse contact, directions, and response.","distractors":["Mark the walk complete because symptom management took the same amount of scheduled time.","Omit the entire visit because a planned task was not completed exactly as assigned.","Record only patient refusal even though the aide stopped the task for observed safety reasons."],"explanation":"The record should show why care deviated, how safety was protected, and what direction followed. False completion or inaccurate refusal obscures the change."},
      {"prompt":"How should an aide correct an entry placed in the wrong patient's record?","correct":"Report promptly and use the agency correction method that preserves author, time, and original entry.","distractors":["Delete the entry completely and recreate it so no inaccurate information remains in the audit trail.","Change the patient name inside the original entry without notifying the agency or checking care impact.","Ask another aide to overwrite the entry because a second author makes the correction more reliable."],"explanation":"An audit-preserving correction maintains accountability and permits assessment of any care impact. Silent deletion or overwriting conceals what occurred."},
      {"prompt":"The visit application will not close unless an unsafe task is marked complete. What should the aide do?","correct":"Use the exception or downtime process, notify the nurse, and never mark unperformed care complete.","distractors":["Mark it complete and add a private personal note explaining that the software required the choice.","Perform a shortened version despite the safety concern so the electronic status becomes technically true.","Leave the patient without handoff and ask technical support to decide whether care was safe."],"explanation":"Record integrity and patient safety take priority over software workflow. The agency exception and escalation process documents the real deviation."},
      {"prompt":"Which action best protects patient records while traveling between home visits?","correct":"Use approved secured systems, log out, protect paper, and avoid personal storage or messaging.","distractors":["Keep printed visit lists visible in the vehicle so addresses can be checked quickly.","Send records to a personal email account before entering homes with unreliable internet.","Share one device login among nearby aides so urgent schedule changes remain accessible."],"explanation":"Approved secured access and physical control reduce loss and disclosure. Visible paper, personal accounts, and shared credentials violate record safeguards."},
      {"prompt":"Which Pennsylvania HHA topics directly support this documentation course?","correct":"Agency and health-team work, ethics, confidentiality, reporting changes, and recordkeeping.","distractors":["Facility life-safety construction, sprinkler inspection, and nursing-home room dimensions.","Hospice bereavement counseling, volunteer management, and interdisciplinary prognosis certification.","Restaurant sanitation licensing, commercial food preparation, and public occupancy records."],"explanation":"28 Pa. Code Section 601.35 expressly includes the agency and health team, ethics, confidentiality, reportable changes, and recordkeeping for aides."},
      {"prompt":"What makes this documentation module eligible for HHA annual in-service credit?","correct":"The agency RN approves the content and attends the in-service to supervise it; the agency tailors and records it.","distractors":["A vendor-generated sample note accepted without review of the agency's actual record system.","Aide completion used instead of RN attendance because documentation is not a clinical skill.","RN signature after the fact without prior content approval or attendance during the in-service."],"explanation":"The agency RN must approve the content and attend the in-service to supervise it. The agency must apply its system, call tree, correction policy, and records."}
    ]
  },
  "PA-HHA-AIDE-INFECTION-PREVENTION": {
    "correct_positions": [4,2,1,3,3,4,2,1],
    "practices": [
      {"title":"Clean-zone setup in a difficult home","content":"Use the bag-technique and infection policy to plan a visit in a crowded home with pets and no clear table. Select a barrier, clean zone, supply order, hand-hygiene moments, PPE, used-item containment, and equipment disinfection.","deliverable":"Draw the clean workflow from entry through bag closure and list three contamination points you prevented."},
      {"title":"Exposure-response work product","content":"Apply the occupational-exposure procedure to a hidden-needle puncture and a body-fluid splash. Identify immediate first aid, urgent contact, source handling limits, patient handoff, evaluation, documentation, and confidentiality.","deliverable":"Write two minute-by-minute exposure responses and the exact alternate contact if the first line fails."}
    ],
    "questions": [
      {"prompt":"What should an aide do when a home has no visibly clean surface for the agency bag?","correct":"Create an approved barrier-based clean zone away from pets, food, sinks, and contamination.","distractors":["Place the closed bag on the floor because supplies remain protected while zippers are shut.","Use the patient's bed because bedding is considered clean before personal care begins.","Hold all supplies in gloved hands so no surface barrier or hand hygiene is needed."],"explanation":"An agency-approved clean zone protects supplies and the bag. Floors, beds, and gloved hands can transfer contamination into clean storage."},
      {"prompt":"Which statement about gloves and hand hygiene is correct in home care?","correct":"Gloves are selected for exposure risk, but hand hygiene is still required at policy-defined moments.","distractors":["Gloves replace hand hygiene whenever the aide removes them without touching the outer surface.","Hand hygiene is needed only when the patient has a diagnosed communicable infection.","One pair of gloves may be used across body sites if no visible soil appears on the surface."],"explanation":"Standard precautions apply regardless of diagnosis, and gloves do not replace hand cleaning. Changing tasks or body sites can require new gloves and hygiene."},
      {"prompt":"An aide finds an uncapped needle in bedding. What is the safest response?","correct":"Avoid recapping or unsafe handling, protect the area, and contact the agency for direction.","distractors":["Recap it with two hands so the needle can be carried safely to a household trash bin.","Break the needle before disposal so no family member can accidentally reuse the device.","Place it loose in the agency bag and ask the office to dispose of it after the visit."],"explanation":"Unexpected sharps require area protection and the agency's safe handling process. Recapping, breaking, loose transport, and household disposal can cause injury."},
      {"prompt":"What should happen immediately after a needlestick during linen handling?","correct":"Perform exposure first aid and promptly activate the agency's occupational-exposure pathway.","distractors":["Finish the visit first because leaving patient care early creates a greater legal risk.","Squeeze the site repeatedly and wait for symptoms before reporting possible exposure.","Ask the family to identify the needle source before contacting the agency or obtaining care."],"explanation":"Immediate first aid and prompt evaluation are time-sensitive. Completing the visit, waiting for symptoms, or investigating source details can delay necessary care."},
      {"prompt":"Which practice keeps reusable equipment from contaminating the agency bag?","correct":"Disinfect with the approved product and contact time before returning it to clean storage.","distractors":["Wrap used equipment in a clean towel and disinfect it at the end of the workweek.","Store it in a separate bag pocket because separation alone removes infectious material.","Use a household fragrance spray so the equipment smells clean before the next visit."],"explanation":"Approved disinfection with full contact time is required before clean storage. Wrapping, separating, or masking odor does not decontaminate equipment."},
      {"prompt":"How does a clean, healthful, pleasant home requirement affect infection-control work?","correct":"Perform assigned health-related household services respectfully without imposing personal housekeeping standards.","distractors":["Deep-clean every room regardless of the care plan because pleasant means meeting agency aesthetics.","Discard household possessions that appear cluttered whenever they complicate the clean-bag setup.","Avoid all household services because infection control applies only to direct hands-on care."],"explanation":"Section 601.35 connects health-related household procedures with a clean, healthful, pleasant environment. Patient choice and plan boundaries still control the aide's work."},
      {"prompt":"Which source requires Pennsylvania HHA training in maintaining a clean and healthful environment?","correct":"28 Pa. Code Section 601.35 includes clean, healthful, and pleasant environment procedures.","distractors":["42 CFR 483.90 assigns the home environment duty to nursing-facility construction staff.","28 Pa. Code Section 201.20 is the only Pennsylvania rule governing HHA home cleanliness.","42 CFR 418.76 limits environmental training to hospice bereavement and volunteer services."],"explanation":"Pennsylvania Section 601.35 expressly includes procedures for maintaining a clean, healthful, and pleasant environment in HHA training."},
      {"prompt":"What must happen for this infection module to count as HHA annual in-service?","correct":"The agency RN approves the content and attends the in-service to supervise it, with local tailoring.","distractors":["The aide reviews a product label alone because infection content does not require RN attendance.","The vendor selects PPE and disinfectants without the agency infection-control program's review.","The RN signs attendance later without approving the content or attending the in-service."],"explanation":"The agency RN must approve the content and attend the in-service to supervise it. Agency products, PPE, exposure procedures, and retained records must be incorporated."}
    ]
  },
  "PA-HHA-AIDE-HOME-SAFETY-EMERGENCIES": {
    "correct_positions": [1,3,4,2,2,1,3,4],
    "practices": [
      {"title":"Clean and safe home walkthrough","content":"Using an agency checklist and a de-identified home diagram, identify health-related household services, patient preferences, trip hazards, oxygen and smoking risk, utilities, food, pests, pets, alarms, equipment, and evacuation access. Separate assigned correction from report-only hazards.","deliverable":"Create a prioritized home action list with patient permission, aide task, supervisor referral, and emergency threshold."},
      {"title":"Individual emergency-plan verification","content":"Review a sample plan for evacuation, backup oxygen or power, medications, communication, caregiver roles, emergency contacts, worker safety, and alternate agency calls. Identify two gaps that make the plan unusable during a storm.","deliverable":"Write a gap report and a timed response sequence for power loss, failed calls, and an acute patient change."}
    ],
    "questions": [
      {"prompt":"What does maintaining a clean, healthful, and pleasant home mean for an HHA?","correct":"Complete assigned health-related household tasks while respecting the patient's home and preferences.","distractors":["Apply the aide's personal cleanliness standard throughout the home before direct care begins.","Remove clutter and possessions without permission whenever they affect the room's appearance.","Limit household work to cosmetic cleaning because health and safety belong only to nurses."],"explanation":"Section 601.35 supports household services essential to health care and a clean, healthful, pleasant environment, but the plan and patient permission define the aide's role."},
      {"prompt":"Which home hazard should an aide correct only within assignment and patient permission?","correct":"A movable pathway obstruction that the care plan authorizes the aide to address.","distractors":["An electrical wiring defect that requires repair by a qualified authorized professional.","An unsecured weapon that requires the agency safety and emergency process, not handling.","A leaking oxygen device that requires immediate clinical and equipment escalation."],"explanation":"Simple assigned environmental support may be appropriate with permission. Technical, weapon, and oxygen hazards require specialized agency or emergency response."},
      {"prompt":"A patient's oxygen concentrator stops during a prolonged outage. What should the aide do?","correct":"Use the individualized backup plan, activate indicated emergency help, and notify the agency.","distractors":["Adjust the oxygen flow downward so any remaining supply lasts for the entire outage.","Connect the concentrator through improvised wiring because restoring therapy is the first priority.","Wait for the utility company estimate before contacting hospice or emergency resources."],"explanation":"The current backup and emergency plan directs safe continuity. Independent oxygen adjustment, electrical improvisation, and delayed notification can cause serious harm."},
      {"prompt":"The aide arrives and finds a patient on the floor with severe neck pain. What is the best response?","correct":"Do not lift; activate emergency and agency procedures, protect the patient, and report facts.","distractors":["Help the family lift the patient because remaining on the floor causes emotional distress.","Move the patient into bed before calling so emergency responders can assess comfortably.","Ask the patient to turn the neck in each direction to determine whether movement is safe."],"explanation":"Severe neck pain after a fall requires protection and authorized emergency response without unnecessary movement. Lifting or testing can worsen injury."},
      {"prompt":"Which situation requires the aide to move to safety before continuing agency notification?","correct":"Active violence, fire, hazardous fumes, or another imminent threat in the home.","distractors":["A patient politely refuses a routine bath while remaining safe and able to communicate.","A family asks a question that the aide must refer to the supervising nurse.","The electronic visit system is unavailable but the approved downtime plan is accessible."],"explanation":"Imminent threats require the aide to avoid entry or leave for safety and activate emergency help. Routine refusals and workflow issues use different agency processes."},
      {"prompt":"What belongs in a patient-specific emergency plan before a predictable event?","correct":"Contacts, evacuation support, communication, backup equipment, supplies, and agency call routes.","distractors":["A private promise that the aide will transport the patient in a personal vehicle if needed.","A family assumption that emergency responders will know every medication and mobility need.","A generic weather brochure without the patient's equipment, caregiver, or communication details."],"explanation":"An actionable continuity plan identifies patient-specific needs, resources, contacts, and roles. Informal transport promises and generic information do not."},
      {"prompt":"Which Pennsylvania provision supports assigned household services essential to health care at home?","correct":"28 Pa. Code Section 601.35 includes household services and environment procedures.","distractors":["42 CFR 483.90 assigns all home household services to nursing-facility maintenance staff.","28 Pa. Code Section 201.20 eliminates the need for patient-specific home instructions.","42 CFR 418.76 authorizes any household member to change an HHA emergency plan."],"explanation":"Section 601.35 includes household services essential to home health care and procedures for a clean, healthful, pleasant environment."},
      {"prompt":"When can this safety course be accepted as HHA annual in-service credit?","correct":"When the RN approves the content and attends the in-service to supervise it, with agency emergency plans and records.","distractors":["When the aide completes a generic home checklist without agency emergency or worker-safety review.","When an RN signs the certificate after training but did not approve content or attend it.","When the vendor assumes responsibility for each patient's backup power, oxygen, and evacuation plan."],"explanation":"The agency RN must approve the content and attend the in-service to supervise it. Local emergency, worker-safety, patient continuity, and record requirements remain essential."}
    ]
  },
  "PA-HHA-AIDE-HYGIENE-ORAL-CONTINENCE-SKIN": {
    "correct_positions": [2,1,3,4,4,3,1,2],
    "practices": [
      {"title":"Personal-care plan setup","content":"Retrieve the current written patient instructions and identify bathing method, transfer support, skin precautions, oral and aspiration precautions, continence devices, authorized products, patient preferences, and stop conditions. Compare them with supplies actually present.","deliverable":"Complete a nine-point setup check and draft the nurse call for one missing or conflicting instruction."},
      {"title":"Skin and elimination observation record","content":"Use de-identified findings to distinguish objective skin color, moisture, drainage, pain, urine, stool, device, and oral observations from wound staging, diagnosis, or treatment. Select the appropriate notification timing.","deliverable":"Write four concise entries with location, appearance, baseline, care provided, notification, and patient response."}
    ],
    "questions": [
      {"prompt":"What should the aide verify before beginning a planned shower in the home?","correct":"Method, assistance, mobility, devices, products, preferences, environment, and stop conditions.","distractors":["Only that hot water is available because the plan was already reviewed at admission.","Only whether the family approves, because household permission replaces patient consent.","Only the scheduled task list, since current symptoms do not change a written assignment."],"explanation":"The current plan, patient condition, environment, supplies, and consent determine whether the planned method remains safe and appropriate."},
      {"prompt":"Which oral-care finding should be reported rather than treated with an unapproved product?","correct":"New sores, bleeding, pain, broken teeth, coating, or difficulty managing secretions.","distractors":["A patient preference for a familiar toothbrush that is clean and allowed by the plan.","A family request to schedule mouth care after the patient's preferred television program.","A labeled denture cup stored in the clean location identified by agency instructions."],"explanation":"New oral findings and secretion changes can affect comfort, nutrition, and safety. The aide reports them and uses only authorized products and techniques."},
      {"prompt":"Which catheter-related action stays within the usual aide boundary described in this course?","correct":"Provide assigned hygiene and keep the drainage system positioned as trained and directed.","distractors":["Disconnect the tubing to remove a blockage whenever urine output appears lower than usual.","Irrigate the catheter with household water when the family reports sediment in the tubing.","Replace the catheter independently because delayed drainage creates an immediate infection risk."],"explanation":"Assigned external hygiene and positioning may be within the plan. Insertion, irrigation, disconnection, and replacement require specific authorization and qualified practice."},
      {"prompt":"A new dark sacral area is seen during incontinence care. What should the aide do?","correct":"Use existing pressure and hygiene directions, avoid unapproved treatment, and report promptly.","distractors":["Stage the area and apply the family's herbal cream because the skin remains intact.","Massage the discoloration until circulation improves and then recheck at the next visit.","Cover the area with a new dressing even though dressing care is absent from the plan."],"explanation":"Objective observation, plan-based protection, and prompt nursing notification are appropriate. The aide should not diagnose, stage, massage, or independently treat the area."},
      {"prompt":"A patient becomes pale and dizzy while standing in the shower. What is the best response?","correct":"Stop, prevent a fall with trained support, obtain help, and report symptoms by urgency.","distractors":["Finish rinsing quickly because wet skin creates more risk than remaining upright.","Lower the water temperature and continue if the patient says the dizziness is manageable.","Leave the patient standing while retrieving a chair from another room without assistance."],"explanation":"New dizziness during standing creates immediate fall risk. Stopping, trained support, help, and escalation protect the patient without improvising an unsafe continuation."},
      {"prompt":"How should the aide document a partial bath stopped for symptoms?","correct":"Record care completed, symptoms, patient words, safety actions, contacts, directions, and response.","distractors":["Mark the bath complete because most scheduled hygiene was provided before symptoms began.","Record patient refusal without mentioning the observed symptoms that led the aide to stop.","Omit the bath from the visit record because incomplete care cannot be accurately documented."],"explanation":"The record must distinguish completed and omitted care and explain the observed reason, communication, and outcome. False completion or inaccurate refusal obscures risk."},
      {"prompt":"How does 28 Pa. Code Section 601.35 support this personal-care module?","correct":"It includes personal care, simple procedures, reportable changes, RN instructions, and close supervision.","distractors":["It authorizes aides to diagnose skin conditions and select wound treatments without an order.","It makes family verbal preference the controlling instruction for every continence device task.","It limits HHA work to housekeeping and excludes hygiene, ambulation, and patient records."],"explanation":"Section 601.35 identifies personal care and related assigned duties, with RN-prepared instructions, reporting, training, and close supervision for competence."},
      {"prompt":"What is required before this hygiene course counts as HHA annual in-service?","correct":"The agency RN approves the content and attends the in-service to supervise it; the agency accepts, records, and validates skills.","distractors":["Vendor certification that every product and device is equivalent across home-health agencies.","Quiz completion used instead of RN attendance and observed competency for hands-on procedures.","A family signature that expands the aide's scope beyond current written patient instructions."],"explanation":"The agency RN must approve the content and attend the in-service to supervise it. Local products, instructions, records, and hands-on competency remain agency responsibilities."}
    ]
  },
  "PA-HHA-AIDE-TRANSFERS-AMBULATION-FALLS": {
    "correct_positions": [3,4,2,1,1,2,4,3],
    "practices": [
      {"title":"Home transfer setup decision","content":"Use a sample written assignment and room diagram to verify weight bearing, assistance, helper, lift and sling, footwear, line management, furniture, pathway, symptoms, and emergency access. Identify one household item that must not substitute for clinical equipment.","deliverable":"Create a transfer-readiness checklist and a scripted stop-work call for missing help or unsafe conditions."},
      {"title":"Near-fall trend and record","content":"Compare three walking visits showing increasing cues, knee buckling, fatigue, and recovery. Decide when to stop, how to seat safely within training, what to report, and why the device or assistance level cannot be changed independently.","deliverable":"Draft a near-fall note, nurse handoff, and three data points for follow-up on functional change."}
    ],
    "questions": [
      {"prompt":"What must be checked before every home transfer, even when yesterday's transfer was successful?","correct":"Today's condition, exact plan, equipment, route, footwear, lines, and required helpers.","distractors":["Only the patient's willingness because consent confirms that the physical method remains safe.","Only whether a family member is available, even if that person lacks training or assignment.","Only the aide's body mechanics because equipment and symptoms were addressed at admission."],"explanation":"Patient condition and home circumstances can change between visits. Current observation and exact plan conditions must be verified each time."},
      {"prompt":"The plan requires two people and a lift, but the family helper is absent. What should the aide do?","correct":"Do not transfer; keep the patient safe and contact the agency for an authorized solution.","distractors":["Complete the lift alone because mechanical equipment removes the need for a second helper.","Ask an untrained neighbor to help so the patient can keep the scheduled appointment.","Change to a manual pivot because delays are more harmful than using another transfer method."],"explanation":"Missing required assistance makes the planned transfer unsafe. The aide cannot reduce helper count or substitute an untrained person or different method."},
      {"prompt":"Which action is appropriate when new weakness appears during a planned walk?","correct":"Stop safely, report the functional change, and do not alter the device or plan independently.","distractors":["Increase verbal pressure so the patient completes the distance before weakness worsens.","Change to a different walker in the home based on which device appears more stable.","Continue at a slower pace and report only if the patient actually falls or reports pain."],"explanation":"New weakness is a stop-and-report change. Independent device changes and pushing through decline can cause a fall and exceed the written plan."},
      {"prompt":"A patient falls and reports pain. What should happen before any lift from the floor?","correct":"Protect, observe, summon designated help, and avoid movement unless immediate danger requires it.","distractors":["Use the familiar transfer technique because returning to bed is the first comfort priority.","Ask the patient to crawl toward a chair so the aide does not perform an unauthorized lift.","Move the patient before calling because emergency services need clear access to the floor."],"explanation":"Pain after a fall may reflect injury. The aide protects and reports without unnecessary movement until authorized clinical or emergency direction is available."},
      {"prompt":"The patient's knee buckles but the aide safely returns the patient to a chair. What should happen next?","correct":"Stop further walking and promptly report and document the near fall and new weakness.","distractors":["Resume after a short rest because a near fall without injury does not change the plan.","Omit the event at the patient's request and see whether weakness recurs next visit.","Select a wheelchair for future visits without asking the nurse to revise the plan."],"explanation":"A near fall and new weakness are meaningful changes even without injury. Prompt communication allows clinical review and prevents an unauthorized plan change."},
      {"prompt":"Which equipment use is within the aide's safe transfer boundary?","correct":"Use only the patient-authorized device and sling after agency training and competency validation.","distractors":["Use any lift model after watching a family demonstration because lift principles are universal.","Substitute household furniture when the prescribed transfer surface is not immediately available.","Use a damaged sling once if the patient's weight is far below the stated equipment limit."],"explanation":"Device-specific training, authorization, compatibility, and condition matter. Family demonstration, furniture substitution, and damaged equipment do not establish safety."},
      {"prompt":"Which Pennsylvania HHA concepts support mobility and transfer training?","correct":"Maximum self-reliance, ambulation, exercise, simple procedures, RN assignment, and close supervision.","distractors":["Independent aide prescription of exercise frequency, weight bearing, and mobility equipment.","Family replacement of RN-prepared instructions whenever a home routine is more convenient.","Automatic competency based on time in the job without device-specific observation or feedback."],"explanation":"Section 601.35 emphasizes self-reliance, ambulation and exercise, assigned procedures, written instructions, and close supervision for competence."},
      {"prompt":"What makes this transfer module acceptable for HHA annual in-service credit?","correct":"The RN approves the content and attends the in-service to supervise it; the agency validates devices and skills.","distractors":["The vendor authorizes every lift model after the aide passes a single online assessment.","An RN signs the record later despite not approving content or attending the in-service.","The family certifies the aide's ability using household equipment not listed in the plan."],"explanation":"The agency RN must approve the content and attend the in-service to supervise it. The agency remains responsible for device-specific instruction, competency, acceptance, and records."}
    ]
  },
  "PA-HHA-AIDE-ROM-POSITIONING-SKIN-INTEGRITY": {
    "correct_positions": [4,3,1,2,2,1,3,4],
    "practices": [
      {"title":"Written ROM instruction crosswalk","content":"Review a de-identified RN or therapist instruction for active, assisted, or passive movement. Identify joints, repetitions, supports, positioning, precautions, symptoms, assistance, and documentation. Mark every place an aide choice would improperly change the therapy extension.","deliverable":"Produce an eight-part instruction crosswalk and a clarification request for one missing stop condition."},
      {"title":"Pressure and device observation map","content":"Use a body map and sample brace plan to identify bony areas, device contact, alignment, moisture, friction, shear, offloading, and reportable skin findings. Decide what may be repositioned and what requires nurse direction.","deliverable":"Complete the body map with four objective findings and draft a device-pressure nurse handoff."}
    ],
    "questions": [
      {"prompt":"What controls an aide's assigned range-of-motion activity?","correct":"Current written instructions specify movement type, joints, repetitions, supports, precautions, and stops.","distractors":["The aide's judgment determines repetitions whenever the patient appears comfortable and motivated.","A prior patient's exercise sheet may be reused when the diagnosis and affected joint are similar.","A family member may add movements because household practice is outside agency responsibility."],"explanation":"Range-of-motion work is an assigned extension under current instructions. The aide does not design, copy, or expand a patient-specific program."},
      {"prompt":"Which positioning practice is appropriate for a home health aide?","correct":"Use plan-approved supports, protect lines, align the body, and recheck comfort and pressure.","distractors":["Use improvised rings and tight rolled towels whenever commercial supports are unavailable.","Tie the patient in position loosely so alignment remains stable between scheduled visits.","Place pressure directly under a red area because firm support improves local circulation."],"explanation":"Approved supports and post-position checks protect comfort, alignment, devices, and skin. Improvised restraints and direct pressure can cause harm."},
      {"prompt":"A patient reports sharp new pain during a prescribed shoulder movement. What should the aide do?","correct":"Stop, support the limb comfortably, report exact findings, and document partial completion.","distractors":["Complete fewer repetitions so the joint still receives the prescribed therapeutic benefit.","Test a different direction to determine whether the pain comes from muscle or joint tissue.","Apply an unapproved topical product and restart when the patient reports some relief."],"explanation":"New sharp pain is a stop-and-report condition. Testing, treating, or continuing changes the assigned procedure and can worsen injury."},
      {"prompt":"Which skin finding under a brace requires prompt communication?","correct":"Persistent redness or discoloration, blistering, warmth, pain, swelling, or an equipment mark.","distractors":["A temporary fabric impression that disappears promptly and causes no discomfort or change.","The manufacturer's printed size information on an intact external equipment label.","A patient preference to wear a clean sock approved by the current brace instructions."],"explanation":"Persistent color and pressure changes can signal tissue injury or device mismatch. Objective findings should be reported so qualified staff can evaluate the plan."},
      {"prompt":"What should the aide do before reapplying a brace that left a deep persistent red line?","correct":"Follow the plan's hold or protection direction and contact the nurse for device guidance.","distractors":["Loosen straps by an estimated amount and reapply because any pressure reduction is safe.","Pad the red line with household material and continue the prescribed wear schedule.","Stop the brace permanently and tell the family that the device is no longer medically needed."],"explanation":"The aide follows existing directions and seeks qualified review. Independent adjustment, padding, or discontinuation can change treatment and pressure distribution."},
      {"prompt":"Which record accurately describes an incomplete movement routine?","correct":"Document movements performed, assistance, symptoms, stop point, notification, and response.","distractors":["Mark the entire routine complete because stopping for pain follows the safety portion of the plan.","Record patient refusal even when the aide stopped because of an observed clinical change.","Copy the prior completed routine and add a private reminder to mention pain at the next visit."],"explanation":"Actual partial completion, symptoms, and communication must appear in the official record. False completion and inaccurate refusal obscure change and follow-up."},
      {"prompt":"How does Section 601.35 support range-of-motion and positioning duties?","correct":"It includes exercise and simple therapy-extension procedures under written instructions and supervision.","distractors":["It lets aides independently prescribe exercise after demonstrating general movement knowledge.","It replaces therapist and RN instructions with standardized annual online course directions.","It authorizes family members to validate clinical competency without agency observation."],"explanation":"Pennsylvania permits assigned simple procedures as an extension of therapy and exercise within RN or therapist instructions and close competence supervision."},
      {"prompt":"What is required before this ROM module counts as HHA annual in-service?","correct":"The RN approves the content and attends the in-service to supervise it; the agency accepts, records, and validates skills.","distractors":["A vendor quiz used as authority to change movement, positioning, or device instructions.","An RN signature after the session despite no content approval or attendance at training.","A general exercise certificate that removes the need for patient-specific precautions."],"explanation":"The RN must approve the content and attend the in-service to supervise it. Patient-specific directions, hands-on validation, agency acceptance, and records remain required."}
    ]
  },
  "PA-HHA-AIDE-NUTRITION-HYDRATION-SAFE-FEEDING": {
    "correct_positions": [1,2,4,3,3,4,2,1],
    "practices": [
      {"title":"Diet and meal-preparation verification","content":"Use a de-identified plan and kitchen inventory to verify identity, diet, texture, liquid consistency, allergy, positioning, assistance, adaptive equipment, sanitation, storage, cooking, and food access. Identify conflicts requiring the nurse.","deliverable":"Complete a meal-readiness sheet and a closed-loop call for one unsafe substitution and one supply shortage."},
      {"title":"Swallowing and intake decision record","content":"Analyze coughing, wet voice, pocketing, fatigue, low intake, vomiting, urine change, and weight trend examples. Choose immediate stop, emergency, prompt nurse report, or routine documentation without diagnosing dehydration or aspiration.","deliverable":"Produce a seven-row action table and draft one urgent swallowing note plus one intake-trend handoff."}
    ],
    "questions": [
      {"prompt":"What must the aide verify before preparing or offering a home-health meal?","correct":"Current diet, texture, liquid, allergies, position, equipment, assistance, and available safe food.","distractors":["Only the patient's preferred food because choice overrides written nutrition and swallowing directions.","Only the package date because cooking makes texture, allergy, and contamination concerns irrelevant.","Only the family menu because household members assume responsibility for any diet conflict."],"explanation":"The current plan and safe food handling both matter. Patient preference can be supported only within authorized diet and swallowing directions."},
      {"prompt":"Which action best reflects safe meal preparation under Section 601.35?","correct":"Use plan-directed nutrition and meal methods while maintaining a clean, healthful preparation area.","distractors":["Serve questionable food when thorough reheating removes every possible storage-related hazard.","Discard culturally preferred food without discussion because standard menus are easier to verify.","Prepare a restricted item if the family agrees to accept responsibility for the choice."],"explanation":"Pennsylvania expressly includes nutrition, meal preparation, and a healthful environment. Safe handling and the patient plan must be respected together."},
      {"prompt":"A patient develops coughing, wet voice, and breathlessness while eating. What should the aide do?","correct":"Stop intake, maintain the directed safe position, and activate clinical or emergency help.","distractors":["Offer a thin liquid to clear the throat before deciding whether the meal should end.","Change the texture independently and continue with smaller bites after symptoms improve.","Lay the patient flat and wait for the family to determine whether choking occurred."],"explanation":"Swallowing and breathing warning signs require stopping and escalation. More intake, independent texture change, or unsafe positioning can worsen airway risk."},
      {"prompt":"How should an aide respond to repeated low intake without acute swallowing symptoms?","correct":"Record actual intake, offer authorized choices, and promptly report the trend and related changes.","distractors":["Diagnose dehydration and set a daily fluid target without nursing or plan direction.","Pressure the patient to finish because refusal prevents the aide from completing the assignment.","Record the amount offered as consumed so the family is not blamed for inadequate nutrition."],"explanation":"Actual intake and change reporting allow qualified assessment. Diagnosis, coercion, and false documentation exceed the role and conceal the trend."},
      {"prompt":"Only regular juice is available for a patient whose plan requires thickened liquid. What should happen?","correct":"Do not provide the conflicting liquid; contact the nurse for an authorized safe solution.","distractors":["Add cereal until the juice looks thick because visual consistency is adequate for one visit.","Serve a small trial amount because the family reports the patient drinks regular juice often.","Skip all fluids for the day without notifying anyone because the prescribed product is absent."],"explanation":"Liquid consistency is a clinical direction requiring the correct product and method. Improvising, trialing, or silently withholding fluids is unsafe."},
      {"prompt":"Which intake note gives the team the most useful information?","correct":"Actual percentage and fluids, assistance, symptoms, refusals, alternatives offered, and contacts.","distractors":["Patient ate poorly because the meal was unappealing and the family did not encourage enough.","Nutrition task completed, with no amounts because exact intake varies naturally each day.","Usual meal percentage copied from prior visits unless a nurse observes the patient eating."],"explanation":"Measured intake, assistance, symptoms, choices, and communication support trend evaluation. Blame, vague completion, and copied values do not."},
      {"prompt":"Which Pennsylvania rule expressly includes nutrition and meal preparation in HHA training?","correct":"28 Pa. Code Section 601.35 expressly includes nutrition and meal preparation principles.","distractors":["42 CFR 483.90 places home meal preparation within nursing-facility physical-environment duties.","28 Pa. Code Section 201.20 is the sole Pennsylvania nutrition rule for home health aides.","42 CFR 418.76 limits food preparation training to hospice volunteers and family caregivers."],"explanation":"Section 601.35 specifically requires careful HHA training in nutrition and meal preparation, along with related home-care and reporting skills."},
      {"prompt":"What is necessary before this nutrition course counts as HHA annual in-service?","correct":"The RN approves the content and attends the in-service to supervise it, with agency diets, procedures, and records applied.","distractors":["A vendor meal plan used for every patient without RN review of orders or swallowing precautions.","An RN signature obtained after training despite no prior approval or attendance at the session.","A family statement that the aide's food preparation is competent enough for regulatory credit."],"explanation":"The agency RN must approve the content and attend the in-service to supervise it. Current diets, policies, acceptance, and training records must be incorporated."}
    ]
  },
  "PA-HHA-AIDE-MEDICATION-ASSISTANCE-SCOPE": {
    "correct_positions": [2,3,4,1,1,4,3,2],
    "practices": [
      {"title":"Medication-assistance boundary lookup","content":"Retrieve the agency policy and written patient instructions for reminders, containers, organizers, documentation, refusal, discrepancy, symptoms, storage, and emergency contacts. Mark every action that would become administration or an independent clinical decision.","deliverable":"Create a permitted-prohibited-escalate table with at least twelve medication-related actions and the controlling source."},
      {"title":"Discrepancy call and record","content":"Apply the policy to a changed pill appearance, missing dose, duplicate family request, damaged label, and patient refusal. Protect the medication, observe the patient, select urgency, and avoid identification or dosing decisions.","deliverable":"Write a concise nurse call, objective visit entry, and three actions the aide must not take during the discrepancy."}
    ],
    "questions": [
      {"prompt":"What determines whether an HHA may provide a particular medication-related assistance task?","correct":"Law, agency policy, demonstrated competency, and the current written patient instructions together.","distractors":["The family's request, because medication kept in the home is controlled by household preference.","The aide's years of experience, even when the task is absent from the current plan.","A medication label alone, because pharmacy directions automatically assign tasks to the aide."],"explanation":"Medication assistance is limited by law, agency policy, competency, and patient-specific direction. No single family request, experience claim, or label expands scope."},
      {"prompt":"A pill looks different from the current medication record. What should the aide do?","correct":"Pause assistance, secure the item, and obtain authorized nurse or pharmacy clarification.","distractors":["Search the internet for the imprint and proceed if the image appears to match.","Ask the patient to decide whether the color change is an acceptable generic substitution.","Discard the pill and take another from the container so the schedule is not delayed."],"explanation":"A discrepancy requires protection and authorized clarification, not identification, patient guessing, disposal, or substitution by the aide."},
      {"prompt":"How should an aide respond when a patient refuses an ordinarily self-administered medication?","correct":"Respect the refusal, report it as directed, observe concerns, and document without coercion.","distractors":["Hide the medication in food because the care plan shows that the dose is important.","Warn that services may end unless the patient follows the medication schedule exactly.","Leave the medication unlabeled for later so the patient can take it without another discussion."],"explanation":"Refusal must be respected and communicated through the plan. Concealment, threats, and unsafe medication handling violate rights and medication safety."},
      {"prompt":"A family asks the aide to double today's dose after a missed dose yesterday. What is correct?","correct":"Do not change the dose; contact the supervising nurse for authorized direction.","distractors":["Give both doses if the medication is normally self-administered and the patient agrees.","Split the extra dose across the day because smaller amounts reduce medication risk.","Skip today's dose as well because missed-dose schedules should restart the following day."],"explanation":"Dose changes and missed-dose decisions require qualified authorization. The aide must not double, split, or skip based on family reasoning."},
      {"prompt":"Which medication-storage concern requires agency communication?","correct":"Missing doses, damaged labels, unsafe temperature, unsecured access, or suspected diversion.","distractors":["The container is stored in the exact locked location specified by the current plan.","The patient asks to take a scheduled dose independently as authorized in the instructions.","The pharmacy label and current assistance record match the available medication supply."],"explanation":"Security, label, temperature, count, and diversion concerns can affect safe use and require reporting. Correct storage and matching directions do not signal the same problem."},
      {"prompt":"Which documentation is appropriate after medication assistance?","correct":"Record only authorized assistance, observation, refusal, discrepancy, contacts, and directions actually received.","distractors":["Record medication administration even when the patient independently selected and took the dose.","Pre-chart the reminder because the scheduled time makes completion highly predictable.","Enter a diagnosis explaining a symptom that appeared after the patient took medication."],"explanation":"The record must accurately distinguish assistance from administration and document actual events. Pre-charting and diagnosis misstate the aide's role and observations."},
      {"prompt":"How does Section 601.35 describe medication-related HHA work?","correct":"It includes assistance with medications ordinarily self-administered, within instructions and supervision.","distractors":["It authorizes aides to select as-needed medication whenever the patient describes a familiar symptom.","It permits aides to change a dose when a family member reports that the prescriber agreed.","It eliminates agency policy limits whenever medication is stored in the patient's own home."],"explanation":"Pennsylvania includes assistance with ordinarily self-administered medications, not independent prescribing, selection, or dose changes."},
      {"prompt":"What must occur before this medication course counts as HHA annual in-service?","correct":"The RN approves the content and attends the in-service to supervise it; the agency defines and validates lawful tasks.","distractors":["The vendor defines medication scope without reviewing Pennsylvania law or agency policy.","An RN signs the certificate later but neither approves content nor attends the in-service.","The family validates medication competence because the patient ordinarily self-administers."],"explanation":"The agency RN must approve the content and attend the in-service to supervise it. The agency must define lawful assistance, validate competency, accept, and retain records."}
    ]
  },
  "PA-HHA-AIDE-AGENCY-POLICIES-NEW-PROCEDURES": {
    "correct_positions": [3,2,1,4,4,1,2,3],
    "practices": [
      {"title":"Controlled-policy change crosswalk","content":"Compare a current controlled policy with an outdated screenshot for one changed procedure. Identify effective date, patient-plan impact, required supplies, documentation, escalation, downtime, training, and hands-on competency before assignment.","deliverable":"Produce a side-by-side change record and a staff teach-back checklist that resolves every conflicting step."},
      {"title":"Section 601.35 annual-needs audit","content":"Map agency training records and current risks against self-reliance, nutrition, aging, emotional problems of illness, clean and healthful environment, reportable changes, health-team work, ethics, confidentiality, records, medication assistance, and supervision.","deliverable":"Create a twelve-topic gap matrix with evidence, responsible RN, in-service plan, attendance method, competency method, and due date."}
    ],
    "questions": [
      {"prompt":"A current controlled policy conflicts with an old screenshot. Which source should guide the aide?","correct":"Pause and obtain RN clarification using the controlled policy and current patient instructions.","distractors":["Use the screenshot because coworkers likely saved it after testing the procedure in practice.","Combine the two versions so no potentially important step is completely omitted.","Choose the shorter version because efficient care reduces the patient's exposure to risk."],"explanation":"Conflicting instructions require resolution through the controlled source and authorized supervision. Choosing or combining versions independently can create unsafe work."},
      {"prompt":"What may be required after an online introduction to a new clinical device?","correct":"Device-specific demonstration, supervised practice, return demonstration, and documented competency.","distractors":["Only a passing quiz because device controls are designed to prevent unsafe user choices.","A family demonstration because home ownership makes household users the final trainers.","Independent use on the next patient so performance can be evaluated under real conditions."],"explanation":"Knowledge content may introduce a device, but hands-on skills require the agency's device-specific training and observed validation before independent patient use."},
      {"prompt":"Several aides struggle because supplies are missing and the electronic plan is unavailable. What response is appropriate?","correct":"Address the skill need and correct the supply and technology barriers through responsible processes.","distractors":["Retrain each aide repeatedly and exclude system conditions from the remediation record.","Allow undocumented workarounds until an injury proves that the barriers affect patient safety.","Lower the care standard because the agency cannot expect compliance without perfect systems."],"explanation":"Effective remediation addresses individual knowledge or skill and system barriers. Hidden workarounds and lowered standards do not create safe sustainable practice."},
      {"prompt":"What training record supports defensible HHA annual in-service credit?","correct":"Content, date, duration, evidence the RN approved the content and attended the in-service to supervise it, learner attendance, and outcomes.","distractors":["A vendor certificate alone without agency acceptance, RN attendance, or training details.","An aide statement that the material seemed useful, with no record of time or supervision.","An RN signature added later without evidence of content approval or presence at training."],"explanation":"The record must establish what occurred and that the RN approved the content and attended the in-service to supervise it. A certificate or retrospective signature does not show those facts."},
      {"prompt":"An unfamiliar lift arrives and only the family has used that model. What should the aide do?","correct":"Do not use it independently; obtain agency direction, model-specific training, and competency validation.","distractors":["Accept the family demonstration because direct experience with the device replaces agency training.","Use the familiar parts and avoid unfamiliar controls during the first independent transfer.","Watch an online advertisement and proceed if the device resembles a previously used model."],"explanation":"A new device creates specific risks and requires agency authorization and competency validation. Family experience and visual similarity do not establish safe assignment."},
      {"prompt":"The new visit application fails and the aide cannot access the plan. What is the best response?","correct":"Use the approved downtime and call process and do not guess tasks or record false completion.","distractors":["Follow the prior patient's plan because common aide tasks are generally interchangeable.","Ask the family to reconstruct the clinical instructions and treat them as the current plan.","Mark all tasks complete and ask the office to correct any differences after connectivity returns."],"explanation":"Downtime controls preserve access, communication, and record integrity. Guessing, family reconstruction, and false completion can cause direct patient harm."},
      {"prompt":"Which subjects does Section 601.35 require an HHA program to address?","correct":"Self-reliance, nutrition, aging, illness emotions, environment, changes, teamwork, ethics, confidentiality, and records.","distractors":["Only personal hygiene and vital signs because home and emotional subjects are outside HHA work.","Only emergency response and infection control because other content is optional employer preference.","Only medication assistance and housekeeping because written care instructions replace broader training."],"explanation":"Pennsylvania lists a broad set of required training topics in Section 601.35, together with assigned duties and close supervision for competence."},
      {"prompt":"What is the nonnegotiable RN condition for accepting this policy-update module as annual credit?","correct":"The agency RN approves the content and attends the in-service to supervise it and retains evidence.","distractors":["The RN reviews a completion report later, even though the RN neither approved nor attended training.","A non-RN vendor presenter supervises while the agency RN remains available by telephone.","The aide self-attests that current agency policy was reviewed without RN presence or acceptance."],"explanation":"CMS guidance requires RN content approval and RN attendance at the in-service to supervise it. Agency acceptance, tailoring, and retained evidence are also required."}
    ]
  }
}
$hhae$::jsonb;
  v_hos_enrichment jsonb := $hose$
{
  "PA-HOS-AIDE-HOSPICE-PHILOSOPHY-IDG-PLAN": {
    "correct_positions": [4,1,2,3,3,2,1,4],
    "practices": [
      {"title":"Aide-plan and IDG contribution crosswalk","content":"Use a de-identified hospice aide plan to identify assigned personal care, comfort supports, frequency, equipment, precautions, symptoms, communication needs, and out-of-scope decisions. Map each reportable observation to the nurse and interdisciplinary role that may respond.","deliverable":"Create a two-column aide-role and IDG-role crosswalk plus a closed-loop report for one unmet comfort need."},
      {"title":"Goal-concordant visit decision","content":"Apply a patient goal and current plan to competing requests from the patient and family. Identify what comfort means to the patient, the authorized aide action, what must pause, the nurse contact, and the record needed without predicting prognosis.","deliverable":"Write a six-step visit decision and an objective note that preserves the patient's stated goal and family concern."}
    ],
    "questions": [
      {"prompt":"What should define comfort in an individual hospice aide visit?","correct":"The patient's goals, values, preferences, current plan, and response to assigned care.","distractors":["A standard end-of-life routine applied consistently so families know what to expect.","The family's preferred schedule even when it conflicts with the patient's expressed choice.","The aide's personal experience with what usually comforts people near the end of life."],"explanation":"Hospice comfort is individualized through the patient and interdisciplinary plan. Standard routines, family preference alone, and aide assumptions cannot replace those goals."},
      {"prompt":"Which information is an appropriate hospice aide contribution to the interdisciplinary group?","correct":"Objective changes in function, comfort, intake, skin, breathing, mood, and response to care.","distractors":["An independent prognosis estimate based on how much the patient slept during the visit.","A medication change recommendation made before the aide reports current symptoms to the nurse.","A revised plan of care entered by the aide because the next team meeting is several days away."],"explanation":"Close bedside observations help the interdisciplinary group evaluate the plan. Prognosis, medication decisions, and independent plan revision exceed the aide role."},
      {"prompt":"A family requests an oxygen-flow change absent from the hospice aide plan. What should the aide do?","correct":"Do not adjust it; support as currently directed and promptly contact the hospice nurse.","distractors":["Increase the flow one setting because comfort goals permit reasonable aide adjustments.","Ask the family to change it so the action falls outside the aide's professional responsibility.","Turn the oxygen off briefly to determine whether the breathing change is equipment-related."],"explanation":"Oxygen adjustment is a clinical decision controlled by the plan and qualified direction. The aide supports current measures and escalates the symptom and request."},
      {"prompt":"A patient becomes much sleepier and needs more help before the next IDG meeting. What should happen?","correct":"Report the specific change to the supervising nurse now and follow updated directions.","distractors":["Wait for the scheduled IDG meeting because only the full team can consider functional change.","Document active dying as the cause and independently shorten the personal-care schedule.","Tell the family the decline proves the patient has entered the final days of life."],"explanation":"Meaningful change requires prompt nursing communication, not delay or aide interpretation. The team can then evaluate and revise the plan as appropriate."},
      {"prompt":"Which action stays inside the hospice aide role when the plan no longer fits current tolerance?","correct":"Pause the affected task, protect comfort, report the mismatch, and obtain authorized direction.","distractors":["Rewrite the task frequency because the aide directly observed that less care is needed.","Replace the planned task with another clinical procedure that appears more comfortable.","Complete the task despite intolerance because written plans remain controlling until formally changed."],"explanation":"The aide recognizes and reports a mismatch while preserving safety and comfort. Independent plan changes and forced completion are not authorized."},
      {"prompt":"What documentation supports continuity after a hospice aide reports an unmet need?","correct":"Care delivered, objective change, patient response, calls and attempts, directions, and handoff.","distractors":["Only the final outcome because unsuccessful calls and earlier symptoms are no longer relevant.","The aide's diagnosis explaining why the interdisciplinary plan did not meet the patient's need.","A private message to the next aide without an entry in the hospice-approved record."],"explanation":"The record should show what happened, what was communicated, and who assumed follow-up. Diagnosis and off-system messages do not provide reliable continuity."},
      {"prompt":"Which source establishes RN-supervised hospice aide services and annual in-service requirements?","correct":"42 CFR 418.76, implemented through the hospice's current policies and aide plans.","distractors":["42 CFR 483.71, which governs nursing-facility assessments rather than hospice aide services.","42 CFR 484.80, which governs home-health-aide services rather than the hospice condition.","28 Pa. Code 201.20, which establishes nursing-facility education rather than hospice aide rules."],"explanation":"42 CFR 418.76 governs hospice aide qualifications, duties, supervision, and in-service. The hospice operationalizes it through policies, plans, and records."},
      {"prompt":"When may this hospice philosophy module count toward annual aide in-service?","correct":"When the hospice accepts and documents it under RN supervision and tailors it to its plans.","distractors":["Immediately after vendor completion because hospice philosophy is identical across all agencies.","When the aide independently decides which IDG observations satisfy the remaining annual hours.","When the vendor certificate replaces hospice review of role, policy, and patient-specific direction."],"explanation":"The hospice must provide RN supervision, accept the content, connect it to current practice, and retain evidence. Vendor completion alone does not establish credit."}
    ]
  },
  "PA-HOS-AIDE-COMMUNICATION-PRIVACY-GRIEF": {
    "correct_positions": [1,4,3,2,2,3,4,1],
    "practices": [
      {"title":"Serious-illness listening script","content":"Use the hospice communication and referral policies to respond to prognosis, fear, anger, silence, spiritual distress, and family conflict. Identify validating language, the question beyond role, the correct team referral, and the alternate contact.","deliverable":"Write five brief patient-led responses and pair each with the appropriate nurse, social work, counseling, or spiritual-care referral."},
      {"title":"Privacy and family-role decision","content":"Review authorized contacts and a de-identified plan where relatives disagree about updates and bedside access. Separate patient preference, privacy, immediate safety, neutral aide support, and issues requiring nurse or social-worker resolution.","deliverable":"Create a privacy-safe response script and an objective note recording the conflict, patient preference, action, and referral."}
    ],
    "questions": [
      {"prompt":"A spouse asks the aide exactly how many days the patient has left. What is the best response?","correct":"Acknowledge the concern, avoid predicting, and promptly connect the spouse with the hospice nurse.","distractors":["Estimate a range from the patient's current intake and sleep so the spouse can prepare.","Say that no one can know and end the conversation to avoid creating false reassurance.","Promise that the patient will remain comfortable regardless of symptoms or plan changes."],"explanation":"The aide can offer presence and referral but cannot predict prognosis or promise outcomes. The hospice nurse and team address clinical interpretation and planning."},
      {"prompt":"Which communication approach supports a patient whose verbal response is becoming limited?","correct":"Continue direct respectful communication and use plan-identified nonverbal or assistive supports.","distractors":["Speak only to family because limited response means the patient cannot understand conversation.","Ask multiple questions rapidly so at least one response can be observed before fatigue increases.","Stop explaining personal care because nonverbal patients do not need advance information."],"explanation":"Limited response does not eliminate dignity, possible understanding, or communication preference. Direct explanation and plan supports remain important."},
      {"prompt":"Two relatives demand conflicting clinical updates. What should the aide do?","correct":"Protect authorized privacy, remain neutral, and refer the conflict through the hospice team.","distractors":["Share equal details with both relatives because fairness resolves authorization uncertainty.","Choose the relative who provides the most hands-on care and treat that person as authorized.","Post a written update in the home so every visitor receives the same clinical information."],"explanation":"Authorization and patient preference control disclosure, not family volume or caregiving role alone. Neutral referral protects privacy and avoids escalating the dispute."},
      {"prompt":"Which aide statement best supports grief without counseling beyond role?","correct":"I hear how painful this is, and I can contact the team member who can support you.","distractors":["You should focus on gratitude because positive thinking is the healthiest way to grieve.","I know exactly how you feel, and I can tell you why this illness happened to your family.","Try not to cry in front of the patient because visible grief always increases suffering."],"explanation":"Acknowledgment and referral offer support without prescribing emotion, claiming identical experience, or imposing unsupported rules about grief."},
      {"prompt":"A family asks the aide to choose sides in a bedside disagreement. What is appropriate?","correct":"Stay neutral, support the patient's known preference and safety, and notify the hospice team.","distractors":["Support the family member who appears calmest because that person is most likely correct.","Leave without notifying anyone because family disputes are outside all hospice responsibilities.","Disclose confidential plan details to prove which family member has misunderstood the situation."],"explanation":"The aide maintains neutrality and patient-centered safety while referring conflict. Choosing sides, abandoning communication, or disclosing private information is unsafe."},
      {"prompt":"Which action demonstrates cultural humility during grief and end-of-life support?","correct":"Ask about rituals, faith, family roles, modesty, and desired support without assuming.","distractors":["Apply the customs most commonly associated with the family's stated cultural background.","Avoid all discussion of culture because hospice care should be identical for every household.","Explain the aide's personal beliefs so the family has a clear model for coping with death."],"explanation":"Individual inquiry respects variation within cultures and families. Stereotypes, silence, and staff belief-sharing can displace the patient's preferences."},
      {"prompt":"Which boundary protects privacy and professional support in hospice communication?","correct":"Use approved channels and avoid personal social media, secret contact, and unauthorized disclosure.","distractors":["Use personal messaging when the family promises not to forward screenshots or clinical details.","Accept private contact after hours because grief support is separate from the hospice aide role.","Share de-identified stories publicly even when household details make the patient recognizable."],"explanation":"Approved channels and clear boundaries protect confidentiality and role integrity. Personal contact and recognizable stories can expose patients and create dual relationships."},
      {"prompt":"What is required before this communication course counts toward hospice annual in-service?","correct":"Hospice acceptance, RN supervision, local privacy and referral procedures, attendance, and records.","distractors":["A vendor statement that its grief script replaces the hospice's counselor and social-work pathways.","Aide completion without hospice review because communication skills do not require clinical supervision.","Family approval of the course as a substitute for agency privacy and training documentation."],"explanation":"The hospice must supervise, accept, tailor, and document the training. Vendor content cannot replace its privacy authorizations, referrals, or patient-specific plans."}
    ]
  },
  "PA-HOS-AIDE-OBSERVATION-REPORTING-DOCUMENTATION": {
    "correct_positions": [2,4,1,3,4,2,3,1],
    "practices": [
      {"title":"Comfort-change observation grid","content":"Compare a de-identified baseline with changes in breathing, alertness, movement, vocalization, skin, intake, output, sleep, anxiety, and response to care. Sort objective findings from diagnosis and select routine, urgent, or emergency communication.","deliverable":"Complete a ten-domain observation grid and draft one urgent SBAR-style aide report without clinical interpretation."},
      {"title":"Closed-loop record and correction lab","content":"Use hospice call, record, correction, and downtime policies to document uncontrolled pain, an unanswered call, alternate escalation, directions, partial care, and a copied skin statement that is no longer accurate.","deliverable":"Write a corrected visit note showing all contact attempts, read-back, actions, response, and the preserved audit trail."}
    ],
    "questions": [
      {"prompt":"Which observation report is most useful when a hospice patient's comfort changes?","correct":"Baseline comparison, exact behavior and symptoms, onset, function, actions, response, and safety.","distractors":["The aide's conclusion that the patient has entered active dying and needs a new medication.","A general statement that the patient had a bad visit without identifying specific changes.","Only the family's interpretation because hospice symptoms are too subjective for aide observation."],"explanation":"Specific factual comparison helps the nurse evaluate urgency and the plan. Aide diagnosis and vague or secondhand-only reports do not."},
      {"prompt":"A patient develops severe pain behavior despite assigned comfort measures. What should the aide do?","correct":"Promptly contact the hospice nurse or on-call route and report measures and response.","distractors":["Increase medication or oxygen within a small range because the comfort goal is documented.","Wait until the visit ends so the report includes whether the symptom resolved naturally.","Tell the family the symptom is expected and therefore does not need an urgent hospice call."],"explanation":"Uncontrolled symptoms require prompt hospice clinical response. The aide reports and supports within the plan but does not change treatment or dismiss distress."},
      {"prompt":"The first on-call number does not answer an urgent symptom report. What is the next step?","correct":"Use the alternate hospice escalation path and continue appropriate patient safety and comfort actions.","distractors":["Leave one message and wait because the aide has completed the legal communication duty.","Ask a family member to choose whether the symptom can wait until normal office hours.","Send clinical information to a personal contact who previously worked for the hospice."],"explanation":"Urgent communication requires a completed handoff. The alternate path prevents unsafe delay and keeps information within authorized systems."},
      {"prompt":"Which documentation practice preserves an accurate hospice aide record?","correct":"Chart actual care and facts promptly and correct errors through the audit-preserving process.","distractors":["Pre-chart predictable comfort care and edit only if the patient's response is unusual.","Copy the previous visit's skin statement when the same area remains covered by a dressing.","Delete a wrong entry completely so the record no longer reveals that an error occurred."],"explanation":"Actual timely entries and preserved corrections support continuity and accountability. Pre-charting, copied assumptions, and deletion undermine record integrity."},
      {"prompt":"A copied note says skin is intact, but the aide sees new redness. What should the aide do?","correct":"Document today's finding, report it, and correct any error using the approved process.","distractors":["Leave the copied statement because changing templated language may make the record inconsistent.","Stage the area independently and replace the prior note with the aide's clinical conclusion.","Wait for the next nurse visit because a covered template cannot be changed by an aide."],"explanation":"Today's objective finding must replace assumption and be reported. The aide does not stage, but must not preserve inaccurate copied text."},
      {"prompt":"Why must an aide avoid assuming every serious change is expected in hospice?","correct":"Similar signs can be urgent, uncontrolled, or unexpected and require the patient-specific response plan.","distractors":["Hospice patients must receive emergency transport for every symptom regardless of goals or plan.","Only family members can decide whether a change is expected because they know the patient best.","Expected-decline teaching permanently eliminates the need to call hospice about repeated symptoms."],"explanation":"Hospice goals vary and plans guide response. Serious or worsening changes still require observation and timely clinical communication."},
      {"prompt":"What belongs in a closed-loop hospice aide handoff?","correct":"Identity, exact change, onset, care provided, safety, family concern, directions, and follow-up owner.","distractors":["Only the aide's diagnosis and suggested medication so the nurse can approve the treatment quickly.","Only the final symptom status because call attempts and interim actions have no continuing value.","A personal text summary without patient identity so the official record can remain brief."],"explanation":"A complete handoff communicates facts, actions, directions, and responsibility. Diagnosis, omissions, and off-system messages can break continuity."},
      {"prompt":"When may this observation course count toward hospice annual aide in-service?","correct":"When the hospice accepts and documents it under RN supervision with its call and record systems.","distractors":["When the vendor decides which symptoms are expected for every hospice patient and diagnosis.","When course completion replaces the hospice's patient-specific thresholds and alternate call route.","When the aide independently certifies that documentation competency no longer needs observation."],"explanation":"The hospice must apply its policies, patient plans, RN supervision, acceptance, and records. Generic vendor content cannot set symptom thresholds or prove skill."}
    ]
  },
  "PA-HOS-AIDE-INFECTION-PREVENTION": {
    "correct_positions": [3,1,4,2,2,4,3,1],
    "practices": [
      {"title":"Compassionate precaution plan","content":"Use hospice infection and patient communication policies to plan PPE and hand hygiene for intimate care while preserving hearing, eye contact, explanation, warmth, and family understanding. Identify what cannot be waived for comfort.","deliverable":"Write a care script with PPE sequence, four hand-hygiene moments, two dignity supports, and the escalation for missing supplies."},
      {"title":"Clean-bag and exposure simulation","content":"Map entry, clean-zone setup, supply removal, linen, waste, reusable equipment, bag closure, and exit in a home with pets and limited surfaces. Then apply the exposure procedure to a splash during oral care.","deliverable":"Draw the workflow, mark five contamination risks, and write the immediate exposure first aid, call, handoff, and record."}
    ],
    "questions": [
      {"prompt":"Does a hospice comfort goal remove the need for standard precautions during body-fluid exposure?","correct":"No; use required precautions while adapting communication and care to preserve comfort and dignity.","distractors":["Yes; infection precautions may be skipped whenever the family believes PPE frightens the patient.","Yes; standard precautions apply only when curative treatment remains part of the patient's goals.","No; but the aide should avoid explaining PPE because discussion increases end-of-life anxiety."],"explanation":"Comfort-focused care and infection prevention coexist. Required precautions remain, while respectful explanation and communication reduce distress."},
      {"prompt":"Which hand-hygiene statement is correct for hospice aide care?","correct":"Clean hands at required moments even when gloves were worn and removed correctly.","distractors":["Gloves replace hand hygiene if the patient's diagnosis does not identify an infection.","Hand hygiene may wait until leaving the home when repeated comfort care is planned.","One glove change is sufficient across clean and contaminated body sites without hand cleaning."],"explanation":"Gloves do not replace hand hygiene, and standard precautions do not depend on a known diagnosis. Task transitions can require glove changes and hand cleaning."},
      {"prompt":"What keeps contaminated reusable equipment out of the clean hospice bag?","correct":"Approved disinfection with full contact time before equipment returns to clean storage.","distractors":["Wrapping the used item in a clean towel until the aide has time to clean it later.","Placing the item in a separate bag pocket because physical separation destroys organisms.","Using a household fragrance product so the item smells clean for the next patient."],"explanation":"The approved product and contact time decontaminate compatible equipment. Wrapping, separating, and masking odor do not make an item clean."},
      {"prompt":"A body-fluid splash reaches the aide's eye during oral care. What should happen first?","correct":"Stop, perform immediate exposure first aid, and promptly activate the hospice employee pathway.","distractors":["Finish oral care so the patient is comfortable before the aide begins personal first aid.","Wait for symptoms because a brief splash may not require formal exposure evaluation.","Ask the family to identify the likely infection source before contacting the hospice."],"explanation":"Exposure first aid and prompt evaluation are time-sensitive. Patient handoff can be arranged without delaying the aide's required response."},
      {"prompt":"A family asks the aide to skip posted PPE during incontinence care. What is appropriate?","correct":"Explain and use required PPE, preserve dignity, and contact the nurse if conflict continues.","distractors":["Honor the request because family preference controls infection precautions in the private home.","Complete care without PPE once and ask the hospice to revise the plan afterward.","Refuse all future visits without first using the hospice communication and safety process."],"explanation":"The aide should not waive required precautions. Respectful explanation and nurse involvement can address comfort while maintaining safe care."},
      {"prompt":"Which action is safest when an unexpected loose sharp is found near hospice supplies?","correct":"Protect access, avoid recapping or unsafe handling, and obtain hospice disposal direction.","distractors":["Place it loose in the hospice bag so agency staff can dispose of it after the route.","Break or bend it before household disposal so no one can use the device again.","Recap it with two hands because a covered needle no longer poses an immediate hazard."],"explanation":"Unexpected sharps require area control and the approved disposal process. Recapping, breaking, and loose transport can cause puncture injuries."},
      {"prompt":"Which policies must tailor infection-prevention learning for a hospice aide?","correct":"Current hospice precautions, PPE, bag technique, products, exposure contacts, and setting directions.","distractors":["The aide's preferred cleaning products and techniques used successfully in personal households.","A generic vendor checklist that replaces all patient-specific and setting-specific precautions.","Family preferences alone, even when they conflict with required employee protection procedures."],"explanation":"The hospice's infection program and patient plans operationalize federal expectations. Vendor learning contributes but cannot set local products or exposure response."},
      {"prompt":"When can this infection module count toward hospice annual aide in-service?","correct":"After hospice acceptance, RN supervision, local infection tailoring, attendance, and retained records.","distractors":["After the quiz replaces observed PPE technique and the hospice's current exposure policy.","When the vendor certifies one clean-bag method for every home and inpatient setting.","When family approval substitutes for hospice infection-control review and RN supervision."],"explanation":"The hospice must supervise, accept, tailor, and document the module. Hands-on practice and current infection controls remain agency responsibilities."}
    ]
  },
  "PA-HOS-AIDE-COMFORT-HYGIENE-ORAL-CONTINENCE": {
    "correct_positions": [4,2,3,1,1,4,2,3],
    "practices": [
      {"title":"Comfort-priority care plan","content":"Use a de-identified aide plan to prioritize warmth, privacy, breathing, pain, energy, bathing, grooming, mouth care, continence, devices, and patient choice. Decide what can be shortened within the plan and what change requires nursing direction.","deliverable":"Create a tiered full, partial, and stop-care plan with symptoms, consent, authorized alternatives, contact, and documentation."},
      {"title":"Oral and continence observation lab","content":"Review mouth dryness, sores, secretions, reduced alertness, urine and stool change, catheter leakage, skin moisture, and distress. Separate assigned comfort care from suction, medication, irrigation, or device manipulation beyond role.","deliverable":"Write four objective observation notes and a nurse handoff for one swallowing or device change."}
    ],
    "questions": [
      {"prompt":"A hospice patient is too breathless and fatigued for the planned shower. What should the aide do?","correct":"Stop, support assigned comfort, offer only desired plan-consistent limited care, and notify the nurse.","distractors":["Complete the shower quickly because hygiene prevents greater discomfort later in the day.","Cancel all hygiene indefinitely because any reduced tolerance proves active dying has begun.","Ask the family to hold the patient upright so the aide can finish the scheduled task."],"explanation":"Current tolerance and patient choice guide comfort-focused care. The nurse should evaluate the change; force, diagnosis, and unsafe assistance are inappropriate."},
      {"prompt":"Which bathing approach best supports comfort-focused hospice aide care?","correct":"Use warm, slow, private, preference-sensitive care and pause for symptoms or distress.","distractors":["Use vigorous rubbing to complete cleansing before the patient becomes more fatigued.","Choose strongly scented products because pleasant odor is more important than preference.","Expose the entire body at once so the task takes less time and reduces total handling."],"explanation":"Slow pacing, warmth, privacy, and preference reduce distress and preserve dignity. Vigorous, scented, or unnecessarily exposing care can worsen symptoms."},
      {"prompt":"A less-responsive patient has a dry mouth. What should the aide avoid?","correct":"Do not pour fluid into the mouth; use only plan-authorized oral comfort and report change.","distractors":["Moisten the mouth with the approved product and positioning identified in the plan.","Observe secretion handling and notify the nurse of reduced alertness and swallowing concern.","Explain to the family which approved mouth-care steps they may reinforce under the plan."],"explanation":"Pouring fluid into a poorly responsive mouth can create aspiration risk. Authorized moisture care, observation, and reporting support comfort safely."},
      {"prompt":"Which continence-care action remains within the assigned hospice aide role?","correct":"Provide prompt hygiene and skin protection and handle devices only as trained and directed.","distractors":["Irrigate a catheter independently when urine output falls and the family reports discomfort.","Disconnect drainage tubing for cleaning because hospice goals prioritize comfort over sterility.","Change an ostomy appliance procedure without direction when the current method takes too long."],"explanation":"Assigned external care and device support may be appropriate. Irrigation, disconnection, and procedure changes require specific authorization and competence."},
      {"prompt":"The patient refuses grooming after becoming exhausted. How should the aide document the visit?","correct":"Record the patient's words, symptoms, care completed or omitted, comfort action, contacts, and response.","distractors":["Mark all grooming complete because the aide offered the service and respected the refusal.","Record noncompliance without describing fatigue, choice, or the comfort alternative provided.","Omit the visit record because partial comfort care does not meet the scheduled task definition."],"explanation":"Actual care, refusal, symptoms, support, and communication belong in the record. False completion and labels hide the patient's current needs."},
      {"prompt":"Which finding during oral care requires prompt hospice communication?","correct":"New inability to manage secretions, bleeding, sores, pain, or a major alertness change.","distractors":["A preference for a different approved lip moisturizer already available in the home.","The patient's request to pause care while a family member reads a familiar passage.","A clean denture container located in the storage place identified by the current plan."],"explanation":"New oral, swallowing, secretion, and alertness changes can affect comfort and safety. Routine preference and planned pauses do not carry the same urgency."},
      {"prompt":"What is the safest response when family preference conflicts with the current aide plan?","correct":"Pause the affected action, explain the role limit, and obtain direction from the hospice nurse.","distractors":["Follow the family because household members control how hospice care is delivered at home.","Choose whichever approach seems more comfortable based on the aide's previous patients.","Complete both approaches so the family request and written plan are equally represented."],"explanation":"The current plan and authorized clinical direction control aide work. Family concerns matter but do not independently revise procedures."},
      {"prompt":"What makes this comfort-care module eligible for hospice annual in-service credit?","correct":"Hospice acceptance, RN supervision, patient-plan tailoring, attendance, records, and skill validation.","distractors":["A vendor certificate that authorizes oral, device, and continence procedures for every patient.","Quiz completion used instead of current plan review and hands-on competency observation.","Family confirmation that the aide's technique feels comfortable, replacing hospice supervision."],"explanation":"The hospice must supervise, accept, tailor, document, and validate relevant skills. Vendor completion alone cannot authorize hands-on patient care."}
    ]
  },
  "PA-HOS-AIDE-SKIN-POSITIONING-PRESSURE-COMFORT": {
    "correct_positions": [1,3,2,4,3,1,4,2],
    "practices": [
      {"title":"Position-comfort tradeoff worksheet","content":"Use a patient plan to compare pressure reduction, breathing, pain, sleep, contractures, devices, skin risk, and preference across three positions. Identify the authorized supports, stop signs, and the clinical decision the aide cannot make.","deliverable":"Complete a position-response table and a nurse report recommending plan review without prescribing the new position."},
      {"title":"Skin and device body map","content":"Map bony areas, dressings, tubing, brace contact, moisture, friction, shear, discoloration, drainage, odor, pain, and offloading on a de-identified profile. Separate observation and assigned prevention from staging or treatment.","deliverable":"Create a marked body map, objective skin entry, and immediate handoff for one new device-pressure finding."}
    ],
    "questions": [
      {"prompt":"Who determines tradeoffs among turning, breathing, pain, sleep, and patient preference in hospice?","correct":"The patient-centered interdisciplinary plan directs them, informed by reported aide observations.","distractors":["The aide independently selects the position that appears to protect skin most effectively.","The family decides because positioning in the home falls outside the hospice plan of care.","A fixed turning schedule always controls, even when the patient develops severe intolerance."],"explanation":"These goals can conflict and require individualized clinical planning. The aide implements and reports response rather than choosing the tradeoff independently."},
      {"prompt":"Which action reduces friction and shear during an assigned position change?","correct":"Use trained helpers and approved lift or draw equipment while protecting devices and skin.","distractors":["Pull the patient by the arms so the movement is completed before fatigue increases.","Drag the patient across the sheet slowly because lower speed prevents skin injury.","Use an improvised household strap to keep the patient aligned after the turn."],"explanation":"Approved equipment, helpers, and technique reduce dragging and protect fragile skin and devices. Pulling and improvised restraints create harm."},
      {"prompt":"New drainage is leaking through a wound dressing during bathing. What should the aide do?","correct":"Do not remove it unless assigned; protect the area and promptly report objective findings.","distractors":["Remove the dressing to photograph and stage the wound before contacting the nurse.","Apply a second treatment product over the dressing so drainage and odor remain contained.","Finish bathing and wait for the next scheduled nurse visit because the wound is already covered."],"explanation":"New drainage and odor require prompt communication. The aide protects and observes within assignment but does not independently remove, stage, or treat the wound."},
      {"prompt":"A planned side-lying position causes worse breathlessness and anxiety. What is the best response?","correct":"Return to the safest tolerated position as trained, provide assigned support, and call the nurse.","distractors":["Maintain the position for the full interval because pressure relief requires consistent timing.","Raise oxygen independently until the patient can tolerate the prescribed side-lying position.","Discontinue all future turning and tell the family the care plan no longer applies."],"explanation":"Immediate comfort and safety require stopping an intolerable position and reporting the response. The aide does not change oxygen or permanently revise the plan."},
      {"prompt":"Which skin documentation is appropriate for a hospice aide?","correct":"Exact location, color or appearance, drainage, pain, care provided, contacts, and response.","distractors":["The wound stage, tissue type, and treatment selected from the aide's prior experience.","Only that skin care was completed because detailed findings belong exclusively in nursing notes.","A personal-phone photograph stored until the nurse asks for visual documentation."],"explanation":"Objective description and communication are within the aide role. Staging, treatment decisions, omission, and unauthorized photography are not."},
      {"prompt":"A patient refuses repositioning because it increases pain. What should the aide do?","correct":"Pause, support comfort, report the refusal and pain, and obtain authorized plan direction.","distractors":["Use additional staff to complete the turn because pressure prevention overrides refusal.","Record noncompliance without describing pain or what comfort alternatives were offered.","Cancel the turning plan independently for the remainder of hospice services."],"explanation":"Refusal and pain require respectful pause and clinical review. Force, labeling, and independent cancellation do not support patient-centered care."},
      {"prompt":"Which action is outside the hospice aide's wound-care boundary unless specifically assigned?","correct":"Removing a dressing to stage, pack, debride, or select a treatment for the wound.","distractors":["Observing exposed skin during authorized personal care and reporting new discoloration.","Using the plan's offloading support and checking comfort after an assigned position change.","Keeping surrounding skin clean and dry using the exact task and product in the aide plan."],"explanation":"Assessment and treatment procedures require qualified authorization. Observation and specifically assigned prevention or hygiene remain within the plan."},
      {"prompt":"When may this skin and positioning module count toward hospice annual in-service?","correct":"After hospice acceptance, RN supervision, plan tailoring, attendance records, and competency validation.","distractors":["After the vendor quiz authorizes aides to stage wounds and redesign turning schedules.","When family approval replaces RN supervision for positioning and device decisions at home.","When every patient receives the same pressure schedule regardless of comfort or goals."],"explanation":"The hospice must connect learning to actual plans and skills under RN supervision. Vendor content cannot authorize assessment, treatment, or standardized tradeoffs."}
    ]
  },
  "PA-HOS-AIDE-TRANSFERS-AMBULATION-FALLS": {
    "correct_positions": [2,1,4,3,3,2,4,1],
    "practices": [
      {"title":"Changing-mobility plan check","content":"Review a de-identified hospice mobility plan and compare it with current weakness, pain, breathlessness, fatigue, lines, equipment, helper availability, patient goals, and home pathway. Identify the first mismatch requiring a stop.","deliverable":"Complete a transfer-readiness decision tree and a nurse call for new inability to bear weight."},
      {"title":"Fall and near-fall record drill","content":"Analyze a fall with hip pain and a near fall with knee buckling. Use hospice and emergency procedures to decide movement limits, observation, contacts, family communication, handoff, and documentation without declaring injury or expected decline.","deliverable":"Write two time-ordered records and identify the exact decision owner for lifting and plan revision."}
    ],
    "questions": [
      {"prompt":"Why must a hospice aide reassess current tolerance before each planned transfer?","correct":"Strength, pain, breathing, fatigue, goals, and equipment needs can change rapidly.","distractors":["Only the family's availability changes; the patient's written assistance level remains permanently safe.","A prior successful transfer proves the same technique remains appropriate until the next IDG meeting.","Hospice comfort goals remove the need to check weight bearing and transfer equipment."],"explanation":"Hospice patient function and goals can change quickly. Current observation must be compared with the plan before movement begins."},
      {"prompt":"The required lift helper is unavailable. What should the hospice aide do?","correct":"Do not transfer; protect comfort and contact hospice for an authorized alternative.","distractors":["Use the lift alone because mechanical devices eliminate most manual handling risk.","Ask an untrained visitor to help so the patient can keep the planned daily routine.","Switch to a manual pivot because avoiding delay is the most important comfort goal."],"explanation":"Missing required help makes the transfer unsafe. The aide must not reduce assistance or substitute an unauthorized method or helper."},
      {"prompt":"Which response is appropriate when walking causes new breathlessness and fatigue?","correct":"Stop safely, support comfort, report the change, and do not alter the mobility plan independently.","distractors":["Complete the planned distance slowly because stopping early accelerates functional decline.","Increase oxygen without direction so the patient can continue the activity comfortably.","Select a wheelchair from the home and make it the new mobility method for future visits."],"explanation":"New symptoms require a safe stop and nursing communication. The aide does not push through, change oxygen, or revise equipment independently."},
      {"prompt":"A patient falls beside the commode and reports new hip pain. What is the best response?","correct":"Prevent an unassessed lift, protect and observe, and activate hospice and emergency procedures.","distractors":["Help the caregiver lift immediately because remaining on the floor conflicts with comfort goals.","Move the patient to bed before calling so the nurse can assess in a familiar position.","Ask the patient to bear weight briefly to determine whether emergency transport is necessary."],"explanation":"Pain after a fall can signal injury. Protection and authorized clinical or emergency response come before lifting or weight-bearing tests."},
      {"prompt":"The patient cannot bear weight today during a planned pivot. What should the aide do?","correct":"Stop, support the safest tolerated position, and contact the hospice nurse for reassessment.","distractors":["Add a second unassigned helper and complete the pivot because staffing solves the weakness.","Choose a mechanical lift independently because any lift is safer than remaining in bed.","Tell the family that loss of weight bearing confirms the final stage of dying."],"explanation":"The plan no longer matches current ability. The aide protects and reports without improvising equipment or interpreting prognosis."},
      {"prompt":"Which near-fall information should be communicated even when no injury occurs?","correct":"Knee buckling, increased assistance, symptoms, distance, safe response, and current function.","distractors":["Only whether the family witnessed the event because unwitnessed near falls are unreliable.","Only the final seated position because the patient recovered without a reportable outcome.","The aide's opinion that motivation caused the patient to stop walking before the goal."],"explanation":"Near falls and functional change can predict injury and require plan review. Objective facts matter even when the patient recovers without obvious harm."},
      {"prompt":"Which transfer documentation supports hospice continuity?","correct":"Plan method, helpers, patient ability, symptoms, task completed or stopped, contacts, and response.","distractors":["Transfer completed, with no detail because the hospice aide plan already contains the method.","Patient noncompliant, without describing pain, weakness, preference, or alternatives offered.","A copied mobility note from the prior visit when the same equipment was present."],"explanation":"Actual ability, symptoms, assistance, actions, and communication show whether the current plan still works. Vague or copied entries hide change."},
      {"prompt":"What makes this mobility module acceptable for hospice annual in-service credit?","correct":"Hospice acceptance, RN supervision, local equipment and plan tailoring, records, and skill validation.","distractors":["A vendor quiz that authorizes every lift and sling used across hospice care settings.","Family confirmation that the aide transferred the patient comfortably during one home visit.","Course completion used instead of observed competency and current patient-specific direction."],"explanation":"The hospice must supervise, tailor, document, and validate actual mobility skills. Online learning cannot establish device or patient-specific competence."}
    ]
  },
  "PA-HOS-AIDE-NUTRITION-HYDRATION-SWALLOWING": {
    "correct_positions": [3,4,1,2,2,4,1,3],
    "practices": [
      {"title":"Comfort-goal intake decision","content":"Use a de-identified hospice plan to compare patient preference, alertness, diet texture, liquids, positioning, swallowing signs, oral care, family concern, and goals. Identify what the aide can offer and what requires nurse review.","deliverable":"Create a choice-and-safety table and a family response script that avoids pressure, prognosis, and unauthorized diet change."},
      {"title":"Swallowing-stop and report exercise","content":"Analyze coughing, wet voice, pocketing, drooling, fatigue, reduced alertness, breathing change, low intake, and dry mouth. Select immediate stop, urgent hospice call, emergency action, or routine record using current policy.","deliverable":"Complete an eight-finding action grid and draft one urgent note with signs, intake stopped, position, calls, and response."}
    ],
    "questions": [
      {"prompt":"How should a hospice aide respond when a patient has little appetite but no acute swallowing distress?","correct":"Follow the comfort plan, offer desired authorized choices, avoid pressure, and report meaningful change.","distractors":["Insist on a minimum portion because reduced intake directly determines how quickly decline occurs.","Tell the family that low appetite always proves the patient has entered the final days.","Add a nutritional supplement independently because hospice goals allow comfort-based substitutions."],"explanation":"Appetite can change, but the aide supports choice within the plan and reports change. Coercion, prognosis, and independent supplementation exceed the role."},
      {"prompt":"What must be checked before offering food or fluid to a hospice patient?","correct":"Current goal, alertness, diet, texture, liquid, position, equipment, and assistance directions.","distractors":["Only the patient's favorite food because comfort preference replaces swallowing precautions.","Only whether the family agrees because household choice controls home feeding decisions.","Only the prior visit's intake because diet and positioning do not change between visits."],"explanation":"Goal-concordant care still requires current swallowing and assistance directions. Preference is supported within, not instead of, the patient plan."},
      {"prompt":"A sleepy patient turns away and coughs after one spoonful. What should the aide do?","correct":"Stop feeding, position safely as directed, notify hospice promptly, and provide approved oral comfort.","distractors":["Offer several sips of thin liquid so the patient can clear the throat and resume eating.","Ask the family to continue slowly because familiar voices reduce swallowing difficulty.","Change to a smoother texture without direction and continue if coughing does not recur."],"explanation":"Reduced alertness and coughing require stopping and clinical communication. More intake, family continuation, and independent texture changes can increase aspiration risk."},
      {"prompt":"An alert patient requests a favorite food that conflicts with documented texture. What should happen?","correct":"Acknowledge the choice and contact the hospice nurse for a goal-concordant plan decision.","distractors":["Serve it secretly because a capable patient's preference automatically changes the written plan.","Refuse permanently because swallowing directions can never be reconsidered in hospice care.","Blend the food by eye and serve it without checking whether the resulting texture is authorized."],"explanation":"The patient's preference deserves team review, but the aide cannot secretly override or permanently freeze the plan or improvise texture."},
      {"prompt":"Which oral-comfort action is safest for a poorly responsive patient?","correct":"Use only plan-authorized moisture and hygiene methods and never pour fluid into the mouth.","distractors":["Give frequent spoonfuls because dehydration discomfort outweighs possible swallowing risk.","Insert a suction device independently whenever secretions become audible to the family.","Place the patient flat so mouth moisture remains in contact with tissues for longer."],"explanation":"Approved oral moisture can support comfort without requiring swallowing. Pouring fluid, independent suction, and unsafe positioning can cause harm."},
      {"prompt":"How should an aide respond to family fear about reduced intake?","correct":"Acknowledge concern, explain only approved guidance, and connect clinical questions to the nurse.","distractors":["Promise that additional feeding will improve strength and extend the patient's remaining time.","Tell the family that intake no longer matters because the patient is enrolled in hospice.","Avoid discussing the concern because nutrition decisions belong entirely outside hospice care."],"explanation":"Supportive acknowledgment and qualified referral respect the family without promises or dismissal. The interdisciplinary team addresses clinical meaning and goals."},
      {"prompt":"Which intake documentation is appropriate for hospice aide care?","correct":"Actual food and fluid accepted, assistance, symptoms, refusal, oral care, contacts, and response.","distractors":["The amount offered recorded as consumed so the family does not feel responsible for decline.","A copied prior intake percentage when the patient remains on the same diet texture.","The aide's diagnosis of dehydration based on dry mouth and reduced urine alone."],"explanation":"Actual intake, symptoms, support, and communication provide useful evidence. False amounts, copied values, and diagnosis do not."},
      {"prompt":"When can this nutrition module count toward hospice annual aide in-service?","correct":"After hospice acceptance, RN supervision, patient-plan tailoring, attendance, records, and skill review.","distractors":["After vendor completion authorizes the aide to change texture according to comfort preference.","When family approval replaces the hospice's swallowing plan and competency requirements.","When the quiz is used instead of current diet review and urgent-response instruction."],"explanation":"The hospice must supervise, accept, tailor, document, and validate relevant skills. Vendor material cannot set patient-specific diet or swallowing decisions."}
    ]
  },
  "PA-HOS-AIDE-ACTIVE-DYING-SYMPTOM-ESCALATION": {
    "correct_positions": [4,3,2,1,1,3,2,4],
    "practices": [
      {"title":"Possible-change versus urgent-symptom sort","content":"Use the hospice plan to classify changes in sleep, intake, breathing, color, urine, swallowing, restlessness, pain, bleeding, seizure, vomiting, secretions, injury, and equipment. Identify what is reportable, urgent, or emergency without declaring active dying.","deliverable":"Complete a fourteen-item action sort with exact first call, alternate call, immediate comfort action, and prohibited aide interpretation."},
      {"title":"Death-event procedure lookup","content":"Retrieve the hospice's patient-specific procedure for unresponsiveness, absent visible breathing, expected death, emergency choices, on-call contact, family support, equipment, body care, and documentation. Identify every action the aide must await.","deliverable":"Write a time-ordered response card showing contact, observation, family language, actions withheld, authorized handoff, and record."}
    ],
    "questions": [
      {"prompt":"Which statement about possible active-dying signs is accurate for a hospice aide?","correct":"Observe and report specific changes; qualified hospice clinicians interpret prognosis and active dying.","distractors":["Reduced intake and mottling allow the aide to tell the family death will occur within days.","Any change discussed in prior teaching can be treated as expected without another hospice call.","An aide may pronounce death when breathing is not visible and the family agrees."],"explanation":"Signs vary and may have urgent or treatable causes. The aide reports observations and follows the plan without predicting, declaring active dying, or pronouncing death."},
      {"prompt":"Which comfort action is appropriate for an aide during changing end-of-life symptoms?","correct":"Use only assigned positioning, mouth care, environment, skin care, and quiet-presence measures.","distractors":["Adjust oxygen or medication within a small range whenever the patient appears uncomfortable.","Add suction, heat, or cold based on family preference even when absent from the plan.","Offer food and fluid repeatedly because reduced intake is the primary cause of discomfort."],"explanation":"The aide implements assigned nonpharmacologic comfort measures and observes response. Treatment changes require qualified direction."},
      {"prompt":"Which symptom requires immediate hospice escalation rather than waiting for the next visit?","correct":"New severe breathlessness, heavy bleeding, seizure, injury, or uncontrolled pain or agitation.","distractors":["A request for a preferred blanket while the patient remains comfortable and safely positioned.","A family member asking to repeat previously approved mouth-care teaching during the visit.","A planned decrease in room noise that improves the patient's rest without a new symptom."],"explanation":"Severe, uncontrolled, or unexpected symptoms and injury require urgent response. Routine preferences and effective assigned comfort measures do not have the same threshold."},
      {"prompt":"The patient appears unresponsive and no breathing is visible. What should the aide do?","correct":"Follow the exact patient-specific death-event or emergency procedure and contact hospice immediately.","distractors":["Pronounce the death for the family and call the funeral home listed in the home records.","Remove equipment and reposition the body before contacting hospice so the room appears peaceful.","Wait for the next scheduled nurse visit because absence of breathing is expected in hospice."],"explanation":"Only authorized professionals and procedures govern death events. The aide contacts hospice and avoids pronouncement, body movement, equipment changes, and delay."},
      {"prompt":"Sudden heavy bleeding occurs and family says hospice means no emergency calls. What is correct?","correct":"Activate the hospice urgent and emergency plan and provide only trained protective comfort measures.","distractors":["Wait quietly because emergency activation always conflicts with the goals of hospice enrollment.","Apply an improvised invasive treatment because immediate comfort permits broader aide action.","Leave to find supplies before contacting anyone so the report includes a completed response."],"explanation":"Hospice enrollment does not create one universal emergency choice. The patient-specific plan and immediate circumstances require prompt activation and trained action."},
      {"prompt":"Which family statement should the aide avoid when discussing end-of-life change?","correct":"This sign proves exactly how long remains and means no other urgent cause is possible.","distractors":["I can tell you what I observe and contact the hospice nurse for clinical interpretation.","Let us use the comfort steps in the plan while the on-call nurse is being contacted.","People can show different changes, so we should follow this patient's current hospice instructions."],"explanation":"The aide must not predict timing or rule out urgent causes. Observation, plan-based comfort, and qualified referral provide truthful support."},
      {"prompt":"What should an aide record after urgent symptom escalation?","correct":"Exact signs, onset, assigned measures, response, contacts and attempts, directions, and handoff.","distractors":["Only the final outcome because earlier symptoms and failed contacts no longer affect care.","The aide's conclusion that the event was expected and required no team plan review.","A personal message to the next aide instead of the hospice-approved event and care records."],"explanation":"A complete timeline supports continuity and review. Omitting attempts, diagnosing expected decline, or using off-system messages creates gaps."},
      {"prompt":"What is required before this active-dying module counts as hospice annual in-service?","correct":"Hospice acceptance, RN supervision, local symptom and death procedures, attendance, and records.","distractors":["Vendor certification that all patients share the same emergency and after-death procedures.","Aide completion used instead of hospice-specific on-call, medication, and family guidance.","Family approval that permits the aide to pronounce death or change comfort treatments."],"explanation":"The hospice must supervise, tailor, accept, and document the content. Patient-specific symptom, emergency, and death-event procedures remain controlling."}
    ]
  },
  "PA-HOS-AIDE-FAMILY-SUPPORT-BOUNDARIES": {
    "correct_positions": [1,2,3,4,4,1,3,2],
    "practices": [
      {"title":"Caregiver-strain observation and referral","content":"Use hospice caregiver, abuse, emergency, respite, and referral policies to analyze exhaustion, confusion, anger, unsafe lifting, missed care, substance concern, and inability to continue. Distinguish supportive listening from clinical teaching or counseling.","deliverable":"Complete a strain-risk-referral table and write the immediate nurse call for one near-drop during transfer."},
      {"title":"Boundary decision audit","content":"Apply the gift, money, errands, keys, transport, personal contact, social media, private work, document witnessing, and post-death contact policies to realistic requests. Identify the unmet need behind each request and the correct team referral.","deliverable":"Produce a ten-request boundary table with decline language, safety action, referral, and documentation requirement."}
    ],
    "questions": [
      {"prompt":"Which response provides appropriate aide support to an overwhelmed hospice caregiver?","correct":"Listen without judgment, offer assigned practical help, and connect broader needs to the team.","distractors":["Provide psychotherapy during the visit because immediate emotional support prevents caregiver burnout.","Promise private after-hours availability so the caregiver has a dependable personal contact.","Tell the caregiver which feelings are healthy and which show an inappropriate grief response."],"explanation":"The aide offers presence and assigned help while referring clinical, counseling, spiritual, and social needs. Private availability and therapy exceed role boundaries."},
      {"prompt":"When may an aide reinforce caregiver teaching?","correct":"When the hospice has approved and documented the instruction and assigned reinforcement to the aide.","distractors":["Whenever the aide has performed the task before, even if the patient's current plan differs.","Whenever family asks, because home caregivers may choose their own clinical training source.","Only after the aide independently certifies the caregiver as competent in the procedure."],"explanation":"Reinforcement must come from current team-approved teaching and assignment. The aide does not create clinical instruction or independently validate caregiver competency."},
      {"prompt":"A spouse reports nearly dropping the patient after two sleepless nights. What should the aide do?","correct":"Protect the patient, avoid unsafe transfer, and promptly report the near miss and caregiver strain.","distractors":["Coach the spouse through another transfer so the aide can observe whether fatigue truly affects safety.","Keep the disclosure private because admitting caregiver difficulty could lead to unwanted services.","Tell the spouse to sleep after the aide leaves and omit the event because no injury occurred."],"explanation":"Caregiver exhaustion and a near drop are meaningful safety concerns requiring immediate team response. Repeating the risk or concealing it can cause harm."},
      {"prompt":"A family offers cash for the hospice aide to provide private off-duty care. What is appropriate?","correct":"Decline the arrangement and payment and refer the unmet care need through hospice channels.","distractors":["Accept once because continuity with a familiar aide directly supports the patient's comfort goals.","Accept only if the family signs a statement separating the work from hospice responsibility.","Provide the care without payment because unpaid private contact does not create a dual role."],"explanation":"Private work with a current hospice family creates boundary, liability, and care-coordination risks. The unmet need belongs with hospice supervision or social resources."},
      {"prompt":"Which caregiver concern requires immediate protection or emergency procedures rather than routine referral?","correct":"A credible threat, active violence, self-harm statement, abuse concern, or immediate unsafe care.","distractors":["A request for a different visit time because the current schedule conflicts with family work.","A question about a chaplain referral while the patient and household remain safe.","A disagreement about which approved music is most comforting during personal care."],"explanation":"Immediate threats, abuse, and severe safety concerns require urgent pathways. Routine scheduling, resource questions, and preferences use ordinary team coordination."},
      {"prompt":"Which action crosses a professional boundary even when intended to help?","correct":"Exchanging personal contact, money, secret favors, document signatures, or beneficiary status.","distractors":["Using hospice-approved communication to report an unmet supply need to the team.","Listening to a caregiver describe distress and referring counseling needs to social work.","Reinforcing an assigned nonclinical task using the exact documented team instruction."],"explanation":"Money, secrecy, personal contact, legal documents, and beneficiary relationships can exploit or impair judgment. Approved support and referral remain within role."},
      {"prompt":"What should documentation include after identifying significant caregiver strain?","correct":"Exact statements, observed safety issue, patient effect, actions, contacts, directions, and response.","distractors":["The aide's diagnosis of caregiver burnout and prediction that placement will be required.","Only that the family seemed upset because detailed concerns may damage the relationship.","A private note kept outside the hospice record so the caregiver does not feel judged."],"explanation":"Objective words, safety effects, actions, and communication support coordinated response. Diagnosis, omission, and hidden records undermine care."},
      {"prompt":"When may this family-support module count toward hospice annual aide in-service?","correct":"After hospice acceptance, RN supervision, policy tailoring, attendance, records, and referral integration.","distractors":["After the vendor authorizes aides to counsel grief and validate caregiver clinical competence.","When family satisfaction replaces hospice review of privacy, safety, and professional boundaries.","When quiz completion substitutes for the hospice's abuse, emergency, and social-resource pathways."],"explanation":"The hospice must supervise, accept, tailor, and document the content. Vendor learning cannot expand counseling, teaching, or boundary authority."}
    ]
  },
  "PA-HOS-AIDE-EMERGENCY-VS-EXPECTED-DECLINE": {
    "correct_positions": [2,3,1,4,3,2,4,1],
    "practices": [
      {"title":"Patient-specific emergency-choice lookup","content":"Retrieve a de-identified plan containing emergency choices, code-status information available to the aide role, hospice and emergency contacts, injury response, symptom thresholds, death-event procedure, and alternate call routes. Identify ambiguity requiring clarification.","deliverable":"Create a one-page response card and a gap report for one missing or conflicting emergency instruction."},
      {"title":"Expected-change decision drill","content":"Sort fall with head strike, new severe distress, familiar breathing change without distress, uncontrolled bleeding, seizure, fire, equipment failure, and unresponsiveness using the current plan. Avoid treating hospice enrollment as the decision.","deliverable":"Complete an eight-event decision table with immediate protection, first call, emergency activation, alternate route, and documentation."}
    ],
    "questions": [
      {"prompt":"What determines whether a hospice aide activates emergency services for a serious change?","correct":"The patient-specific hospice plan, immediate circumstances, and authorized emergency procedures.","distractors":["Hospice enrollment alone, because emergency services are never compatible with comfort goals.","The family member who speaks first, regardless of the patient's plan or immediate danger.","The aide's prior experience with patients who showed a similar symptom near end of life."],"explanation":"Goals and emergency choices vary. The current plan and event circumstances guide response; hospice status alone does not answer the question."},
      {"prompt":"A weak patient falls and strikes the head. Family says falls are expected. What should the aide do?","correct":"Protect without an unassessed lift and immediately activate the hospice and emergency injury plan.","distractors":["Accept the family's interpretation and wait for the next routine hospice visit.","Lift the patient to bed first because comfort goals make floor time unacceptable.","Ask the patient to stand briefly so the aide can decide whether injury is likely."],"explanation":"A head strike is an injury event requiring the patient-specific response. Family characterization does not replace protection, hospice notification, or emergency direction."},
      {"prompt":"Which observation should the aide make without delaying emergency activation?","correct":"Responsiveness, breathing, bleeding, pain behavior, position, and immediate environmental danger.","distractors":["A full clinical assessment that determines diagnosis and treatment before any call is made.","A detailed family interview about every prior symptom and medication response this week.","A search of online symptom guides to decide whether the event is typical for the diagnosis."],"explanation":"Brief objective safety observations support the call, but extensive assessment, history collection, and internet research can dangerously delay response."},
      {"prompt":"A previously discussed breathing pattern now includes severe new distress. What is the correct action?","correct":"Provide assigned comfort and promptly call hospice, using emergency services if plan or severity directs.","distractors":["Treat the pattern as expected because it appeared in prior family teaching and handouts.","Change oxygen independently because new distress makes small comfort adjustments reasonable.","Wait for the pattern to persist for a full hour so the nurse receives a complete trend."],"explanation":"A familiar sign with new severe distress requires prompt clinical response. Prior teaching does not authorize dismissal or independent treatment change."},
      {"prompt":"Which action is outside the aide role during an apparent death event?","correct":"Pronouncing death, removing equipment, calling the funeral home, or moving the body without direction.","distractors":["Following the hospice's exact contact procedure and remaining supportively present with family.","Reporting objective observations to the designated hospice clinician without predicting cause.","Protecting privacy and waiting for authorized direction about equipment and after-death care."],"explanation":"Pronouncement and after-death actions follow specific legal and hospice procedures. The aide observes, contacts, supports, and awaits direction."},
      {"prompt":"What should happen when the first hospice call is unanswered during a serious event?","correct":"Use the alternate on-call or emergency route and continue trained safety and comfort actions.","distractors":["Wait for a return call because one voicemail completes the aide's communication responsibility.","Ask an unauthorized neighbor with medical experience to decide what care is needed.","Send patient details through personal social media to locate an off-duty hospice employee."],"explanation":"An unanswered call is not a completed handoff. Alternate and emergency routes prevent delay while keeping care within authorized systems."},
      {"prompt":"Which record best supports review after an emergency-versus-expected decision?","correct":"Exact findings, onset, plan used, actions, calls and attempts, directions, response, and handoff.","distractors":["Only whether emergency services arrived because earlier observations no longer affect the outcome.","The aide's conclusion that the event was expected and therefore could not have been prevented.","A family-approved summary outside the hospice record to avoid upsetting the official care plan."],"explanation":"A factual timeline shows how the plan operated and whether follow-up is needed. Conclusions and hidden summaries do not support continuity or improvement."},
      {"prompt":"What makes this emergency-decision module acceptable for hospice annual in-service credit?","correct":"Hospice acceptance, RN supervision, patient-specific procedure integration, attendance, and records.","distractors":["Vendor completion that assigns one emergency rule to all hospice patients and settings.","Family approval that replaces hospice review of emergency choices and death-event procedures.","A passing quiz used instead of local on-call routes, plans, and supervised decision practice."],"explanation":"The hospice must supervise, tailor, accept, and document this course. Actual patient instructions and local emergency processes remain controlling."}
    ]
  },
  "PA-HOS-AIDE-AGENCY-SPECIFIC-NEW-SKILL": {
    "correct_positions": [3,2,4,1,4,3,1,2],
    "practices": [
      {"title":"New-skill authorization crosswalk","content":"Compare the controlled policy, current aide plan, RN direction, manufacturer instruction, training record, and competency checklist for a new device. Identify conflicts, missing supplies, alarms, cleaning, troubleshooting limits, and actions not yet authorized.","deliverable":"Create an authorization matrix and a stop-work call naming the exact source or competency still missing."},
      {"title":"Remediation and evidence plan","content":"Use a de-identified performance gap to separate knowledge, hands-on technique, plan conflict, device mismatch, supply issue, and workflow barrier. Choose RN-supervised training, demonstration, return demonstration, system correction, and follow-up observation.","deliverable":"Write a remediation record with target behavior, trainer, practice, evaluator, outcome, system owner, retest date, and retained evidence."}
    ],
    "questions": [
      {"prompt":"A controlled hospice policy conflicts with an old screenshot. What should the aide do?","correct":"Pause the task and obtain supervising-RN clarification using current controlled sources.","distractors":["Use the screenshot because coworkers likely saved it after confirming the procedure worked.","Combine both versions so no instruction is completely lost during the patient visit.","Choose the shorter procedure because reducing handling best supports hospice comfort."],"explanation":"Conflicting sources create an authorization and safety problem. The supervising RN resolves them; the aide does not choose or combine instructions."},
      {"prompt":"What may be required after completing online education about a new specialty bed?","correct":"Model-specific demonstration, supervised practice, return demonstration, and documented competency.","distractors":["Only the online quiz because bed controls include alarms that prevent incorrect use.","A delivery-driver explanation because manufacturer representatives replace hospice training.","Independent use on the patient so competency can be judged under actual conditions."],"explanation":"Online knowledge does not establish hands-on ability. Hospice-specific supervised validation must precede independent use of unfamiliar clinical features."},
      {"prompt":"Supplies are missing and the required helper is absent. What is the appropriate aide response?","correct":"Pause affected care, protect the patient, report the barriers, and obtain an authorized plan.","distractors":["Improvise with household supplies because delaying comfort care creates greater harm.","Perform the task alone once and report only if an adverse outcome actually occurs.","Mark the task refused so the record closes without exposing a hospice system problem."],"explanation":"Missing prerequisites require stop-work communication and safe alternative direction. Improvisation, trial-and-error, and false refusal conceal risk."},
      {"prompt":"Which record demonstrates durable remediation of a hands-on skill gap?","correct":"Target, RN-supervised practice, evaluator, observed result, feedback, system action, and follow-up.","distractors":["A vendor certificate alone showing the aide opened every online lesson and passed the quiz.","A promise to ask an experienced coworker if the same problem happens during future care.","A record of annual hours with no identification of the skill, evaluator, or patient-safety outcome."],"explanation":"Durable remediation links the specific gap to supervised practice, observed performance, contributing systems, and follow-up. Hours alone do not."},
      {"prompt":"A specialty bed arrives and only the delivery driver demonstrates it. What should the aide do?","correct":"Limit action to authorized safety steps and obtain hospice model-specific training before independent use.","distractors":["Use every feature demonstrated because the delivery driver's product expertise establishes competency.","Ask the family to operate unfamiliar controls so the aide remains technically outside the procedure.","Test the controls while the patient is in bed because actual load is needed to learn the device."],"explanation":"Hospice authorization and competency are required before independent clinical use. Driver instruction, family operation, and testing on a patient do not substitute."},
      {"prompt":"Which action is appropriate when training reveals a policy that no longer fits actual equipment?","correct":"Report the mismatch, protect patients, and request controlled policy and competency review.","distractors":["Create a local workaround and share it privately with experienced aides on the same team.","Continue the written procedure because policy compliance is more important than equipment mismatch.","Edit the aide plan directly so the new equipment method becomes immediately authorized."],"explanation":"The mismatch requires formal review and correction. Hidden workarounds, knowingly unsafe compliance, and unauthorized plan edits are not solutions."},
      {"prompt":"What should a hospice training record retain for a new clinical skill?","correct":"Content, date, duration, RN supervision, trainer, competency method, evaluator, result, and retraining.","distractors":["Only the vendor certificate because competency details are part of the employee's private notes.","Only total annual hours because the exact skill and result are not relevant after completion.","Only the aide signature because supervisor identity and observation method are optional."],"explanation":"A detailed record establishes what was taught, supervised, observed, and corrected. A certificate, hour total, or signature alone does not prove competence."},
      {"prompt":"When may this policy and new-skill module count toward hospice annual in-service?","correct":"After hospice acceptance, RN supervision, current-policy tailoring, attendance, records, and needed validation.","distractors":["After vendor completion automatically authorizes every new device and procedure in the hospice.","When family satisfaction replaces hospice review of policy, scope, and hands-on competence.","When the aide self-attests that written knowledge makes supervised practice unnecessary."],"explanation":"The hospice must supervise, accept, tailor, document, and validate applicable skills. Vendor learning cannot create authority or prove hands-on performance."}
    ]
  }
}
$hose$::jsonb;
  v_enrichment jsonb;
  v_catalog jsonb;
  v_item jsonb;
  v_lesson jsonb;
  v_practice jsonb;
  v_scenario jsonb;
  v_question jsonb;
  v_objective text;
  v_course_id uuid;
  v_version_id uuid;
  v_block_id uuid;
  v_quiz_id uuid;
  v_question_id uuid;
  v_training_type_id uuid;
  v_track text;
  v_description text;
  v_credit_rule text;
  v_duration integer;
  v_objective_minutes integer;
  v_lesson_minutes integer;
  v_practice_minutes integer;
  v_scenario_minutes integer;
  v_source_minutes integer;
  v_quiz_minutes integer;
  v_sort_order integer;
  v_question_order integer;
  v_correct_position integer;
  v_answer_position integer;
  v_distractor_index integer;
  v_question_text text;
  v_correct_answer text;
  v_explanation text;
  v_objectives_text text;
  v_body_text text;
  v_existing_code text;
  v_duplicate_code text;
  v_duplicate_sequence text;
  v_total_minutes integer;
begin
  v_enrichment := v_nh_enrichment || v_hha_enrichment || v_hos_enrichment;

  select jsonb_agg(
    base.value || coalesce(v_enrichment -> (base.value ->> 'catalog_code'), '{}'::jsonb)
    order by base.ordinality
  )
  into v_catalog
  from jsonb_array_elements(v_nh_catalog || v_hha_catalog || v_hos_catalog)
    with ordinality as base(value, ordinality);

  if jsonb_array_length(v_nh_catalog) <> 11
     or jsonb_array_length(v_hha_catalog) <> 11
     or jsonb_array_length(v_hos_catalog) <> 12 then
    raise exception 'Clinical catalog must contain 11 NH, 11 HHA, and 12 hospice courses';
  end if;

  if (select count(*) from jsonb_object_keys(v_nh_enrichment)) <> 11
     or (select count(*) from jsonb_object_keys(v_hha_enrichment)) <> 11
     or (select count(*) from jsonb_object_keys(v_hos_enrichment)) <> 12 then
    raise exception 'Clinical enrichment must contain exactly one entry for every course';
  end if;

  select value ->> 'catalog_code'
  into v_duplicate_code
  from jsonb_array_elements(v_catalog)
  group by value ->> 'catalog_code'
  having count(*) > 1
  limit 1;

  if v_duplicate_code is not null then
    raise exception 'Duplicate clinical catalog code in migration data: %', v_duplicate_code;
  end if;

  select (value -> 'correct_positions')::text
  into v_duplicate_sequence
  from jsonb_array_elements(v_catalog)
  group by (value -> 'correct_positions')::text
  having count(*) > 1
  limit 1;

  if v_duplicate_sequence is not null then
    raise exception 'Every course must use a distinct authored correct-answer position sequence; duplicate %',
      v_duplicate_sequence;
  end if;

  select c.catalog_code
  into v_existing_code
  from public.courses c
  join jsonb_array_elements(v_catalog) item
    on item ->> 'catalog_code' = c.catalog_code
  where c.organization_id is null
  limit 1;

  if v_existing_code is not null then
    raise exception 'Clinical catalog code already exists; migration is intentionally non-reentrant: %', v_existing_code;
  end if;

  for v_item in select value from jsonb_array_elements(v_catalog)
  loop
    v_track := v_item ->> 'track';
    v_duration := (v_item ->> 'duration_minutes')::integer;

    if not (v_item ? 'practices')
       or not (v_item ? 'questions')
       or not (v_item ? 'correct_positions')
       or jsonb_array_length(v_item -> 'objectives') < 3
       or jsonb_array_length(v_item -> 'lessons') <> 4
       or jsonb_array_length(v_item -> 'practices') <> 2
       or jsonb_array_length(v_item -> 'scenarios') <> 2
       or jsonb_array_length(v_item -> 'questions') <> 8
       or jsonb_array_length(v_item -> 'correct_positions') <> 8 then
      raise exception 'Course % must have objectives, 4 instruction blocks, 2 practices, 2 scenarios, and 8 authored questions',
        v_item ->> 'catalog_code';
    end if;

    if exists (
      select 1
      from jsonb_array_elements_text(v_item -> 'correct_positions') position(value)
      where position.value not in ('1', '2', '3', '4')
    ) then
      raise exception 'Course % has an invalid correct-answer position', v_item ->> 'catalog_code';
    end if;

    if (
      select count(distinct position.value)
      from jsonb_array_elements_text(v_item -> 'correct_positions') position(value)
    ) < 3 then
      raise exception 'Course % must vary correct answers across at least 3 positions', v_item ->> 'catalog_code';
    end if;

    for v_question in select value from jsonb_array_elements(v_item -> 'questions')
    loop
      if jsonb_array_length(v_question -> 'distractors') <> 3
         or length(btrim(v_question ->> 'prompt')) < 35
         or length(btrim(v_question ->> 'correct')) < 20
         or length(btrim(v_question ->> 'explanation')) < 80
         or exists (
           select 1
           from jsonb_array_elements_text(v_question -> 'distractors') distractor(value)
           where length(btrim(distractor.value)) < 15
         ) then
        raise exception 'Course % has an incomplete authored assessment item', v_item ->> 'catalog_code';
      end if;
    end loop;

    case v_duration
      when 30 then
        v_objective_minutes := 1; v_lesson_minutes := 3; v_practice_minutes := 2;
        v_scenario_minutes := 2; v_source_minutes := 1; v_quiz_minutes := 8;
      when 45 then
        v_objective_minutes := 2; v_lesson_minutes := 5; v_practice_minutes := 3;
        v_scenario_minutes := 3; v_source_minutes := 2; v_quiz_minutes := 9;
      when 60 then
        v_objective_minutes := 3; v_lesson_minutes := 7; v_practice_minutes := 5;
        v_scenario_minutes := 4; v_source_minutes := 2; v_quiz_minutes := 9;
      when 75 then
        v_objective_minutes := 4; v_lesson_minutes := 9; v_practice_minutes := 6;
        v_scenario_minutes := 5; v_source_minutes := 3; v_quiz_minutes := 10;
      when 90 then
        v_objective_minutes := 4; v_lesson_minutes := 12; v_practice_minutes := 7;
        v_scenario_minutes := 5; v_source_minutes := 3; v_quiz_minutes := 11;
      else
        raise exception 'Unsupported designed duration % for course %', v_duration, v_item ->> 'catalog_code';
    end case;

    v_total_minutes := v_objective_minutes + (4 * v_lesson_minutes)
      + (2 * v_practice_minutes) + (2 * v_scenario_minutes)
      + v_source_minutes + v_quiz_minutes;
    if v_total_minutes <> v_duration then
      raise exception 'Designed block minutes % do not equal course duration % for %',
        v_total_minutes, v_duration, v_item ->> 'catalog_code';
    end if;

    if v_track = 'NH' then
      v_credit_rule := 'The employing nursing facility must accept this vendor module, document attendance, and connect the learning to its facility assessment, the aide''s performance review, resident needs, and facility policies. Completion is contribution evidence, not regulator approval or automatic proof that every individualized requirement is met.';
      v_description := (v_item ->> 'summary') || ' This vendor module contributes to annual nurse-aide in-service education; the employing facility owns tailoring, policy integration, acceptance, and compliance documentation.';
    elsif v_track = 'HHA' then
      v_credit_rule := 'Before these hours count, an employing home health agency registered nurse must approve the content and attend the in-service to supervise it, confirm consistency with agency policy and 28 Pa. Code Section 601.35, and ensure the agency retains the training record.';
      v_description := (v_item ->> 'summary') || ' Vendor content contributes only when the employing HHA''s RN approves the content and attends the in-service to supervise it, and the agency accepts and documents the hours.';
    elsif v_track = 'HOS' then
      v_credit_rule := 'Before these hours count, an employing hospice registered nurse must supervise the in-service, the hospice must accept the content for the aide''s role and policies, and the hospice must retain documentation of the completed hours.';
      v_description := (v_item ->> 'summary') || ' Vendor content contributes only under employing-hospice RN supervision and hospice acceptance and documentation.';
    else
      raise exception 'Unknown clinical track % for %', v_track, v_item ->> 'catalog_code';
    end if;

    select tt.id
    into v_training_type_id
    from public.training_types tt
    where tt.organization_id is null
      and tt.code = case v_track
        when 'NH' then 'NH-AIDE-ANNUAL'
        when 'HHA' then 'HHA-AIDE-ANNUAL'
        when 'HOS' then 'HOS-AIDE-ANNUAL'
      end
      and tt.is_active
    order by tt.is_system_default desc, tt.created_at, tt.id
    limit 1;

    if v_training_type_id is null then
      raise exception 'Missing active system training type for clinical track %', v_track;
    end if;

    insert into public.courses (
      organization_id, catalog_code, title, description, category, status,
      estimated_duration_minutes, recurrence_interval_days, training_type_id
    ) values (
      null, v_item ->> 'catalog_code', v_item ->> 'title', v_description,
      v_item ->> 'category', 'draft', v_duration, 365, null
    ) returning id into v_course_id;

    insert into public.course_versions (
      course_id, organization_id, version_number, title, description, status,
      published_at, content_standard
    ) values (
      v_course_id, null, 1, v_item ->> 'title', v_description, 'draft', null,
      'comprehensive'
    ) returning id into v_version_id;

    select string_agg('- ' || objective.value, E'\n' order by objective.ordinality)
    into v_objectives_text
    from jsonb_array_elements_text(v_item -> 'objectives') with ordinality as objective(value, ordinality);

    insert into public.course_blocks (
      course_version_id, organization_id, block_type, sort_order, title, body
    ) values (
      v_version_id, null, 'text', 1, 'Purpose and learning objectives',
      jsonb_build_object(
        'content', (v_item ->> 'summary') || E'\n\nBy the end of this course, the learner will be able to:\n' || v_objectives_text || E'\n\nCredit safeguard: ' || v_credit_rule,
        'estimated_minutes', v_objective_minutes,
        'activity_type', 'objectives'
      )
    );

    v_sort_order := 1;
    for v_lesson in select value from jsonb_array_elements(v_item -> 'lessons')
    loop
      v_sort_order := v_sort_order + 1;
      v_body_text := (v_lesson ->> 'content')
        || E'\n\nGuided policy reflection (recommended; no submission is collected here): As you study, identify the current employer policy, care-plan section, or written assignment that governs this lesson. If it is readily available, compare its title and effective date, one decision the aide may make, one decision reserved for a nurse or other authorized role, an objective observation example, and the exact escalation route. If the source is unavailable or conflicts with the lesson, identify what is missing or inconsistent and whom you would contact before acting. You may make optional notes in employer-approved scratch space, but this instruction block does not require or save a work product and you may continue without submitting one. The later practice and scenario steps clearly label the written responses that the course saves for trainer review.';

      insert into public.course_blocks (
        course_version_id, organization_id, block_type, sort_order, title, body
      ) values (
        v_version_id, null, 'text', v_sort_order, v_lesson ->> 'title',
        jsonb_build_object(
          'content', v_body_text,
          'key_takeaway', v_lesson ->> 'takeaway',
          'estimated_minutes', v_lesson_minutes,
          'activity_type', 'instruction'
        )
      );
    end loop;

    for v_practice in select value from jsonb_array_elements(v_item -> 'practices')
    loop
      v_sort_order := v_sort_order + 1;
      v_body_text := (v_practice ->> 'content')
        || E'\n\nRequired work product: ' || (v_practice ->> 'deliverable')
        || E' Keep the response for the employer-led discussion or competency review. Compare the completed work with the cited source and correct any unsupported assumption before continuing. Do not include resident or patient identifiers in personal notes, and do not substitute this exercise for a required hands-on observation.';

      insert into public.course_blocks (
        course_version_id, organization_id, block_type, sort_order, title, body
      ) values (
        v_version_id, null, 'text', v_sort_order, v_practice ->> 'title',
        jsonb_build_object(
          'content', v_body_text,
          'work_product', v_practice ->> 'deliverable',
          'estimated_minutes', v_practice_minutes,
          'activity_type', 'practice'
        )
      );
    end loop;

    for v_scenario in select value from jsonb_array_elements(v_item -> 'scenarios')
    loop
      v_sort_order := v_sort_order + 1;
      v_body_text := (v_scenario ->> 'content')
        || E'\n\nRequired scenario work: Before opening the assessment, write (1) the immediate safety, comfort, or dignity concern, (2) the authorized aide action now, (3) the escalation route and timing, (4) an objective documentation entry, and (5) one tempting but unsafe shortcut and why you rejected it. Cite the exact employer policy, written assignment, or care-plan section you used and identify the new fact that would change your decision. The model response is intentionally withheld until the assessment review.';

      insert into public.course_blocks (
        course_version_id, organization_id, block_type, sort_order, title, body
      ) values (
        v_version_id, null, 'text', v_sort_order, v_scenario ->> 'title',
        jsonb_build_object(
          'content', v_body_text,
          'estimated_minutes', v_scenario_minutes,
          'activity_type', 'scenario'
        )
      );
    end loop;

    v_sort_order := v_sort_order + 1;
    insert into public.course_blocks (
      course_version_id, organization_id, block_type, sort_order, title, body
    ) values (
      v_version_id, null, 'text', v_sort_order, 'Primary authority and scope note',
      jsonb_build_object(
        'content', 'Primary source: ' || (v_item ->> 'citation_label') || E'\n' || (v_item ->> 'citation_url') || E'\n\n' || (v_item ->> 'citation_note') || E'\n\nThis course teaches an aide-level annual in-service topic. It does not create a professional license, expand scope of practice, replace competency evaluation, or override an employer policy, resident plan, practitioner order, or emergency direction.',
        'estimated_minutes', v_source_minutes,
        'activity_type', 'sources'
      )
    );

    v_sort_order := v_sort_order + 1;
    insert into public.course_blocks (
      course_version_id, organization_id, block_type, sort_order, title, body
    ) values (
      v_version_id, null, 'quiz', v_sort_order, 'Final assessment',
      jsonb_build_object(
        'estimated_minutes', v_quiz_minutes,
        'activity_type', 'assessment'
      )
    ) returning id into v_block_id;

    insert into public.quizzes (
      course_block_id, organization_id, title, passing_score_percent, max_attempts
    ) values (
      v_block_id, null, (v_item ->> 'title') || ' Final Assessment', 80, 3
    ) returning id into v_quiz_id;

    v_question_order := 0;
    for v_question in select value from jsonb_array_elements(v_item -> 'questions')
    loop
      v_question_order := v_question_order + 1;
      v_question_text := v_question ->> 'prompt';
      v_correct_answer := v_question ->> 'correct';
      v_explanation := v_question ->> 'explanation';

      insert into public.quiz_questions (
        quiz_id, organization_id, question_text, question_type, sort_order, points
      ) values (v_quiz_id, null, v_question_text, 'single_choice', v_question_order, 1)
      returning id into v_question_id;

      v_correct_position := (v_item -> 'correct_positions' ->> (v_question_order - 1))::integer;
      v_distractor_index := 0;
      for v_answer_position in 1..4 loop
        if v_answer_position = v_correct_position then
          insert into public.quiz_answers (question_id, organization_id, answer_text, is_correct, sort_order)
          values (v_question_id, null, v_correct_answer, true, v_answer_position);
        else
          v_distractor_index := v_distractor_index + 1;
          insert into public.quiz_answers (question_id, organization_id, answer_text, is_correct, sort_order)
          values (
            v_question_id, null,
            v_question -> 'distractors' ->> (v_distractor_index - 1),
            false, v_answer_position
          );
        end if;
      end loop;

      insert into public.quiz_question_explanations (question_id, organization_id, explanation)
      values (v_question_id, null, v_explanation);
    end loop;

    if v_question_order <> 8 then
      raise exception 'Expected 8 final questions for %, created %', v_item ->> 'catalog_code', v_question_order;
    end if;

    insert into public.course_compliance_credits (
      course_id, course_version_id, training_type_id, topic_code,
      credit_hours, credit_mode, citation_note
    ) values (
      v_course_id, v_version_id, v_training_type_id, v_item ->> 'topic_code',
      (v_duration::numeric / 60), 'verified_only', v_item ->> 'citation_note'
    );

    -- Draft-first publication: all content, questions, answers, explanations,
    -- and crosswalk evidence exist before trusted migration code publishes.
    perform set_config('app.privileged_write', 'on', true);
    update public.course_versions
    set status = 'published', published_at = now()
    where id = v_version_id;
    update public.courses
    set current_version_id = v_version_id, status = 'published'
    where id = v_course_id;
    perform set_config('app.privileged_write', 'off', true);
  end loop;

  if (select sum((value ->> 'duration_minutes')::integer) from jsonb_array_elements(v_nh_catalog)) <> 720
     or (select sum((value ->> 'duration_minutes')::integer) from jsonb_array_elements(v_hha_catalog)) <> 720
     or (select sum((value ->> 'duration_minutes')::integer) from jsonb_array_elements(v_hos_catalog)) <> 720 then
    raise exception 'Each clinical annual pathway must total exactly 720 designed minutes';
  end if;
end
$seed$;
